// =========================================================================
// NASCAR Points Analysis — app.js
// Loads data/points_<year>.json + data/colors.json, renders 6 views,
// handles routing, series/season/entity switching, filters, sorts.
// =========================================================================

const STATE = {
  series: "NCS",
  season: 2026,
  // Per-page series memory. The site is no longer in a single global "series
  // mode" — each series-scoped view (standings, schedule, projection, the
  // analytics tabs, race/track, etc.) remembers its own NCS/NOS/NTS choice.
  // Keyed by STATE.view. ensurePageSeries() restores the active series from
  // here on navigation/boot; the #page-series-bar toggle writes to it.
  // Home stays multi-series (the trios) and is never keyed here.
  pageSeries: {},
  // Tracks which series the user last picked in Present mode. Used by
  // the side panels (standings/form/metric bar) to snap back to the
  // user's preferred series when STATE temporarily wandered into a
  // historical context for a profile route.
  lastPresentSeries: "NCS",
  view: "home",
  // Site mode: "present" (default) locks the global season to the latest
  // available year; users can still switch series freely. "historical"
  // unlocks the season picker for full year-to-year browsing. Persisted
  // across reloads via localStorage.
  mode: "present",
  // Race lightbox state — set when the user clicks a historical race entry
  // point (heatmap cell, track row, search result) while in present mode.
  // Renders an overlay over whatever the user was looking at without
  // changing STATE.season/series. Closing returns them where they were.
  lightbox: { open: false, year: null, series: null, round: null },
  // Identity model: the app is car-centric. Every primary row is a car
  // (#car_number). If multiple drivers drove that car in a season, the UI
  // surfaces them via an "i" tooltip next to the car's primary driver name.
  // `entity` is kept as a constant for backward compatibility with code paths
  // that still read it; do not mutate.
  entity: "owner",
  // Time cursor: when set, all data views behave as if the season ended at this
  // round number. null = "latest", the default. Reset to null on season change.
  throughRound: null,
  data: null,
  colors: null,
  driverBios: null,
  seasonsAvailable: [],
  form: { window: "5", search: "", ftOnly: true, sortKey: null, sortDir: "desc" },
  arc: { selected: new Set(), ftOnly: true, metric: "points" },
  breakdown: { mode: "drivers" },
  trajectory: { mode: "season", show: "all", labels: "top12", tracks: "all",
                selected: new Set(), seasons: new Set(), ftOnly: true },
  teammates: { metric: "fin", ftOnly: true },
  profile: {
    kind: null, slug: null, splitsRange: "season", splitsSeries: "all", heatmapSeries: "all",
    trackPicker: { code: null, series: "all", gens: new Set() },
  },
  // Analytics → Track Stats: pick a track, see all-time driver stats there.
  // sortKey/sortDir control the table; gens/series are filters; minStarts
  // hides drivers with low samples (3+ default).
  trackStats: { code: null, series: "all", gens: new Set(["g5", "g6", "g7"]), sortKey: "wins", sortDir: "desc", minStarts: 1, search: "", expandedSlug: null, yearStart: null, yearEnd: null },
  // Race takeover state: which round is being shown. null = "latest race
  // in the loaded data" (the default — what the Race tab used to do).
  // Set from the #/race/<round> URL when a user clicks into a specific race.
  race: { round: null },
  personnel: { query: "", role: "all" },
  // Standings view + sort. view = "driver" | "owner" | "manufacturer".
  // Driver is default (most-fan-friendly); Owner mirrors NASCAR's owner
  // standings (per-car, subs accrue to the car); Manufacturer uses
  // NASCAR's modern (2011+) mfr point scale applied to all years.
  standings: { sortKey: "total", sortDir: "desc", view: "driver" },
  // Playoff Picture: driver-vs-owner toggle. Defaults to "driver" since
  // the playoff field is fundamentally a driver-eligibility question
  // (drivers, not cars, qualify for the Chase). Owner view is offered
  // for parity with the standings page and to surface car-points-based
  // playoff projections (relevant for teams running ineligible drivers
  // mid-season — those starts count for the OWNER but not the DRIVER).
  playoffs: { view: "driver" },
  // Points Format Calc page — "what-if" recompute of any season under any
  // playoff/points format. Three primary selectors (season, series,
  // formatKey) plus per-format option overrides. formatKey identifies
  // a rule by its lineage start year so we can map back to the
  // PLAYOFF_RULES table without storing the full rule object.
  pointscalc: {
    season: null,
    series: null,
    formatKey: null,
    formatOverrides: {},
    // Driver vs owner view — same toggle pattern as Standings and
    // Playoffs. Defaults to driver since championship contention is
    // fundamentally a driver question (drivers, not cars, qualify
    // for the playoff field). Owner view recomputes by car number,
    // surfacing the car-points version which differs when ineligible
    // drivers run a car (those starts accrue to the OWNER but not the
    // DRIVER).
    view: "driver",
    // Year range filter for the champion-seed stat card. Limits which
    // historical seasons feed the histogram + min/max/avg. Defaulted
    // on first render to the chosen format's era; user-editable
    // thereafter, and persists across format/series swaps.
    statsRange: { startYear: null, endYear: null },
  },
  // Driver Compare page — slugs currently in the comparison set. Cap of
  // 4 to keep the side-by-side layout readable on mobile. Persisted in
  // STATE only; not in localStorage (each visit should be a fresh slate
  // unless the user lands via a ?with=... URL).
  // Driver Compare page state.
  //   slugs   — drivers currently in the comparison set (cap 4).
  //   chart   — career-trajectory chart settings: series + metric + display.
  //             display "per-season" plots the metric per calendar year;
  //             "cumulative" plots a running total against career year
  //             (each driver's first FT season = Year 1). Cumulative
  //             makes era-spanning comparisons direct.
  compare: {
    slugs: [],
    // Default chart view: cumulative wins, in whichever series ends up
    // most-populated for the current driver set. The series gets
    // re-resolved on each render if the current pick has no data; see
    // renderCompareCareerChart.
    chart: { series: "NCS", metric: "wins", display: "cumulative" },
  },
  // Table-split chart: the car whose arc is shown next to Trending/Standings.
  // Null = first row by default. Set when user clicks any row in the table.
  selectedCar: null,
};

const SERIES_TO_KEY = { NCS: "W", NOS: "B", NTS: "C" };
// Default human-readable series names — used when no season context is
// available (e.g. cross-year aggregations). For season-specific labels
// (e.g. "Xfinity" vs "O'Reilly" rename in 2026), call seriesLabel(code, year).
const SERIES_LABELS = { NCS: "Cup Series", NOS: "Xfinity Series", NTS: "Truck Series" };

// Era-aware series name. NASCAR's second-tier series sponsor changed
// from Xfinity (2015-2025) to O'Reilly (2026+). The first tier is
// canonically "Cup Series" across the modern era; trucks are "Truck
// Series" with rotating title sponsors we don't surface in the UI.
//
// Pass a season to get the contemporaneous name; omit for the modern
// default. Falls back to the raw series code for unknown values.
function seriesLabel(seriesCode, season) {
  if (seriesCode === "NCS") return "Cup Series";
  if (seriesCode === "NTS") return "Truck Series";
  if (seriesCode === "NOS") {
    const yr = parseInt(season, 10);
    if (Number.isFinite(yr) && yr >= 2026) return "O'Reilly Series";
    return "Xfinity Series";
  }
  return seriesCode || "—";
}
const FALLBACK_COLOR = "#9ca3af";
const VIEWS = ["home", "race", "track", "schedule", "form", "arc", "breakdown", "trajectory", "teammates", "heatmap", "trackstats", "compare", "standings", "playoffs", "profile", "team", "cc", "drivers", "teams", "crewchiefs", "personnel", "pointscalc", "projection"];

// ============================================================
// GLOBAL SEARCH  (topbar search bar)
// ------------------------------------------------------------
// Searches across drivers, teams, crew chiefs, and races. Indexed lazily
// from SEASON_CACHE (whatever years are loaded) and STATE.driverBios. On
// the first search-bar focus, kicks off a background load of every year
// in STATE.seasonsAvailable so the index is complete after a beat.
//
// Query parsing for races extracts a 4-digit year token (if present) and
// uses the rest as track-name keywords. So "2003 daytona" finds the 2003
// Daytona races, "talladega" finds every Talladega race in cached data.
// ============================================================

const SEARCH = {
  index: null,           // built on demand, invalidated when SEASON_CACHE grows
  indexCacheKey: "",     // cache invalidation: number of cached years stringified
  fullDataLoaded: false, // true after first-focus background fetch completes
  fullDataLoading: false,
  selectedIdx: -1,       // keyboard cursor in dropdown
  results: [],           // last rendered result set (for keyboard nav)
};

// Build a flat search index from currently-cached data. Returns an array
// of { type, key, label, sub, href, score_base } objects. Cached on
// SEARCH.index until SEASON_CACHE changes (years load).
function buildSearchIndex() {
  const cacheKey = Object.keys(SEASON_CACHE).sort().join(",");
  if (SEARCH.index && SEARCH.indexCacheKey === cacheKey) return SEARCH.index;

  // Maps to dedupe across years — drivers/teams/CCs span seasons.
  const driverMap = new Map();   // slug → { name, starts, years (Set) }
  const teamMap = new Map();     // code → { code, fullName, starts, years (Set) }
  const ccMap = new Map();       // slug → { name, starts, years (Set) }
  const races = [];

  Object.keys(SEASON_CACHE).forEach(yearStr => {
    const year = parseInt(yearStr, 10);
    const blocks = SEASON_CACHE[yearStr];
    if (!blocks) return;
    ["NCS", "NOS", "NTS"].forEach(sCode => {
      const block = blocks[sCode];
      if (!block || !block.races) return;
      block.races.forEach(race => {
        // Race entry — only include if it has results (was actually run)
        const hasResults = (race.results || []).some(d => d.finish_pos != null);
        if (hasResults && race.track) {
          races.push({
            year,
            series: sCode,
            round: race.round,
            track: race.track,
            track_code: race.track_code,
            name: race.name || "",
            date: race.date || "",
          });
        }
        // Walk every result row for drivers, teams, CCs
        (race.results || []).forEach(d => {
          if (d.ineligible) return;
          // Driver
          if (d.driver) {
            const slug = slugify(d.driver);
            let drv = driverMap.get(slug);
            if (!drv) {
              drv = { name: d.driver, slug, starts: 0, years: new Set(),
                      seriesSet: new Set() };
              driverMap.set(slug, drv);
            }
            drv.starts++;
            drv.years.add(year);
            drv.seriesSet.add(sCode);
          }
          // Team
          const teamCode = d.team_code || teamCodeFromName(
            d.team, SERIES_TO_KEY[sCode], d.car_number
          );
          if (teamCode) {
            let tm = teamMap.get(teamCode);
            if (!tm) {
              tm = { code: teamCode,
                     fullName: TEAM_FULL_NAMES[teamCode] || teamCode,
                     starts: 0, years: new Set(), seriesSet: new Set() };
              teamMap.set(teamCode, tm);
            }
            tm.starts++;
            tm.years.add(year);
            tm.seriesSet.add(sCode);
          }
          // Crew chief
          if (d.crew_chief) {
            const slug = slugify(d.crew_chief);
            let cc = ccMap.get(slug);
            if (!cc) {
              cc = { name: d.crew_chief, slug, starts: 0, years: new Set(),
                     seriesSet: new Set() };
              ccMap.set(slug, cc);
            }
            cc.starts++;
            cc.years.add(year);
            cc.seriesSet.add(sCode);
          }
        });
      });
    });
  });

  // Also pull driver names from STATE.driverBios — lets us find drivers
  // who had bios scraped but whose seasons aren't loaded into cache yet.
  if (STATE.driverBios) {
    Object.values(STATE.driverBios).forEach(bio => {
      if (!bio || !bio.name) return;
      const slug = bio.slug || slugify(bio.name);
      if (!driverMap.has(slug)) {
        driverMap.set(slug, {
          name: bio.name, slug, starts: 0, years: new Set(),
          seriesSet: new Set(), fromBio: true,
        });
      }
    });
  }

  // Also seed teams from TEAM_FULL_NAMES so well-known codes are findable
  // even before any race data with that team has loaded.
  Object.entries(TEAM_FULL_NAMES).forEach(([code, fullName]) => {
    if (!teamMap.has(code)) {
      teamMap.set(code, {
        code, fullName, starts: 0, years: new Set(), seriesSet: new Set(),
        fromTable: true,
      });
    }
  });

  const idx = [];

  // Drivers
  driverMap.forEach(d => {
    const yrs = Array.from(d.years).sort();
    const yrSpan = yrs.length === 0 ? "" :
      (yrs.length === 1 ? `${yrs[0]}` : `${yrs[0]}-${yrs[yrs.length - 1]}`);
    idx.push({
      type: "driver",
      key: d.slug,
      label: d.name,
      sub: yrSpan + (d.starts > 0 ? ` · ${d.starts} start${d.starts === 1 ? "" : "s"}` : ""),
      href: `#/driver/${d.slug}`,
      // Score base: starts (popularity). Bios-only entries score low so
      // active drivers rank above one-off historical figures.
      score_base: Math.log(1 + (d.starts || 0)) * 10,
    });
  });

  // Teams
  teamMap.forEach(t => {
    const yrs = Array.from(t.years).sort();
    const yrSpan = yrs.length === 0 ? "" :
      (yrs.length === 1 ? `${yrs[0]}` : `${yrs[0]}-${yrs[yrs.length - 1]}`);
    idx.push({
      type: "team",
      key: t.code,
      label: t.fullName,
      sub: `${t.code}${yrSpan ? " · " + yrSpan : ""}`,
      href: `#/team/${t.code}`,
      score_base: Math.log(1 + (t.starts || 0)) * 8,
    });
  });

  // Crew chiefs
  ccMap.forEach(c => {
    const yrs = Array.from(c.years).sort();
    const yrSpan = yrs.length === 0 ? "" :
      (yrs.length === 1 ? `${yrs[0]}` : `${yrs[0]}-${yrs[yrs.length - 1]}`);
    idx.push({
      type: "cc",
      key: c.slug,
      label: c.name,
      sub: yrSpan + ` · ${c.starts} race${c.starts === 1 ? "" : "s"} called`,
      href: `#/cc/${c.slug}`,
      score_base: Math.log(1 + (c.starts || 0)) * 6,
    });
  });

  // Races — keyed by year+round+series so we can deep-link
  races.forEach(r => {
    const trackName = prettyTrack(r.track_code, r.track);
    idx.push({
      type: "race",
      key: `${r.year}-${r.series}-${r.round}`,
      label: `${r.year} ${trackName}`,
      sub: `${r.series} R${r.round}${r.name ? " · " + r.name : ""}${r.date ? " · " + r.date : ""}`,
      // Race route lives within a series+season context, so we navigate
      // to that season's race-detail view via hash. The race view reads
      // STATE.season + STATE.series + round; we'll switch context first
      // via a special handler below.
      href: `#/race/${r.round}?_y=${r.year}&_s=${r.series}`,
      score_base: 1, // races score low by default; year+track match boosts
      _race: r,
    });
  });

  SEARCH.index = idx;
  SEARCH.indexCacheKey = cacheKey;
  return idx;
}

// Score a query against a single index entry. Returns 0 if no match.
function scoreSearchEntry(entry, query, queryParts) {
  const labelLow = entry.label.toLowerCase();
  const subLow = (entry.sub || "").toLowerCase();
  const keyLow = (entry.key || "").toLowerCase();

  // For races, parse year token from query if present
  if (entry.type === "race" && entry._race) {
    const yearMatch = queryParts.find(p => /^\d{4}$/.test(p));
    const trackQ = queryParts.filter(p => !/^\d{4}$/.test(p)).join(" ");
    if (yearMatch) {
      if (entry._race.year !== parseInt(yearMatch, 10)) return 0;
    }
    if (trackQ) {
      const trackName = (prettyTrack(entry._race.track_code, entry._race.track) || "").toLowerCase();
      const rawTrack = (entry._race.track || "").toLowerCase();
      const code = (entry._race.track_code || "").toLowerCase();
      const name = (entry._race.name || "").toLowerCase();
      const hits = [trackName, rawTrack, code, name];
      if (!hits.some(h => h.includes(trackQ))) return 0;
    }
    // Year-only match returns all races in that year, score = base + recency
    let s = 100 + entry.score_base;
    if (yearMatch) s += 50;
    if (trackQ) s += 100;
    return s;
  }

  // Generic match: label hit > sub hit > key hit
  let score = 0;
  // Exact label match
  if (labelLow === query) score += 1000;
  // Word-boundary prefix in label (each query part must hit some word)
  const labelWords = labelLow.split(/\s+/);
  let prefixHits = 0;
  let substringHits = 0;
  for (const part of queryParts) {
    let hitWord = false;
    for (const word of labelWords) {
      if (word.startsWith(part)) { hitWord = true; prefixHits++; break; }
    }
    if (!hitWord && labelLow.includes(part)) {
      substringHits++;
    } else if (!hitWord) {
      // Try sub or key
      if (subLow.includes(part) || keyLow.includes(part)) {
        substringHits++;
      } else {
        return 0;   // any unmatched part disqualifies
      }
    }
  }
  score += prefixHits * 50;
  score += substringHits * 15;
  // Boost: query is exact prefix of label
  if (labelLow.startsWith(query)) score += 200;
  // Type weighting — drivers > teams > CCs > races (when no year/track ctx)
  const typeWeight = { driver: 30, team: 20, cc: 10, race: 5 };
  score += typeWeight[entry.type] || 0;
  // Add popularity base
  score += entry.score_base;
  return score;
}

function searchAll(query) {
  query = (query || "").trim().toLowerCase();
  if (query.length < 1) return [];
  const idx = buildSearchIndex();
  const queryParts = query.split(/\s+/).filter(Boolean);

  const scored = [];
  for (const entry of idx) {
    const s = scoreSearchEntry(entry, query, queryParts);
    if (s > 0) scored.push({ entry, score: s });
  }
  scored.sort((a, b) => b.score - a.score);
  // Cap at 50 results so the dropdown stays manageable
  return scored.slice(0, 50).map(x => x.entry);
}

function renderSearchResults(results) {
  const drop = document.getElementById("search-dropdown");
  if (!drop) return;
  if (results.length === 0) {
    drop.innerHTML = `<div class="search-empty">No matches</div>`;
    drop.hidden = false;
    SEARCH.results = [];
    SEARCH.selectedIdx = -1;
    return;
  }
  // Group by type for visual organization
  const groups = { driver: [], team: [], cc: [], race: [] };
  results.forEach(r => groups[r.type] && groups[r.type].push(r));
  const TYPE_LABEL = { driver: "Drivers", team: "Teams", cc: "Crew Chiefs", race: "Races" };
  const TYPE_BADGE = { driver: "DRV", team: "TM", cc: "CC", race: "R" };

  let flatIdx = 0;
  const html = ["driver", "team", "cc", "race"].map(t => {
    const list = groups[t];
    if (!list.length) return "";
    return `<div class="search-group">
      <div class="search-group-head">${TYPE_LABEL[t]}</div>
      ${list.map(r => {
        const i = flatIdx++;
        return `<a class="search-result" data-idx="${i}" href="${r.href}">
          <span class="search-result-icon r-${t}">${TYPE_BADGE[t]}</span>
          <div class="search-result-body">
            <div class="search-result-label">${escapeHTML(r.label)}</div>
            <div class="search-result-sub">${escapeHTML(r.sub || "")}</div>
          </div>
        </a>`;
      }).join("")}
    </div>`;
  }).join("");

  drop.innerHTML = html + `
    <div class="search-shortcut-hint">
      <kbd>↑</kbd><kbd>↓</kbd> navigate · <kbd>↵</kbd> open · <kbd>Esc</kbd> close
    </div>`;
  drop.hidden = false;

  // Flatten results in display order for keyboard nav
  const flat = [];
  ["driver", "team", "cc", "race"].forEach(t => groups[t].forEach(r => flat.push(r)));
  SEARCH.results = flat;
  SEARCH.selectedIdx = -1;
}

function setSearchKbdSelection(newIdx) {
  const drop = document.getElementById("search-dropdown");
  if (!drop) return;
  const items = drop.querySelectorAll(".search-result");
  if (items.length === 0) return;
  // Wrap
  if (newIdx < 0) newIdx = items.length - 1;
  if (newIdx >= items.length) newIdx = 0;
  items.forEach((el, i) => el.classList.toggle("kbd-active", i === newIdx));
  SEARCH.selectedIdx = newIdx;
  // Scroll into view
  const sel = items[newIdx];
  if (sel) sel.scrollIntoView({ block: "nearest" });
}

// Race href has special form: #/race/<round>?_y=<year>&_s=<series>
// We need to switch STATE.series + STATE.season then navigate. Detect this
// shape on click and handle imperatively.
async function handleSearchRaceClick(rawHref) {
  const m = rawHref.match(/^#\/race\/(\d+)\?_y=(\d+)&_s=(NCS|NOS|NTS)$/);
  if (!m) return false;
  const round = parseInt(m[1], 10);
  const year = parseInt(m[2], 10);
  const series = m[3];
  const drop = document.getElementById("search-dropdown");
  if (drop) drop.hidden = true;
  // Present mode: open the lightbox instead of changing global state.
  // The user explicitly chose "always live" so a 2018 race click should
  // not pull the rest of the site into 2018. In Historical mode we fall
  // through to the original state-changing behavior.
  if (STATE.mode === "present") {
    // If the click is for the CURRENT (year, series) — i.e. a race in
    // the season the user is already viewing — let it route normally
    // so the URL hash reflects the race route. Lightbox only kicks in
    // for cross-year/cross-series jumps.
    const isCurrentContext = (year === STATE.season && series === STATE.series);
    if (!isCurrentContext) {
      await openRaceLightbox(year, series, round);
      return true;
    }
  }
  // Switch context if needed (Historical mode, or current-context click)
  if (STATE.series !== series || STATE.season !== year) {
    STATE.series = series;
    STATE.season = year;
    STATE.throughRound = null;
    await loadCurrentData();
    resetRenderCache();
    populateRacePicker();
    renderTimeCursorBanner();
  }
  location.hash = `#/race/${round}`;
  return true;
}

function clearSearch() {
  const input = document.getElementById("search-input");
  const drop = document.getElementById("search-dropdown");
  if (input) input.value = "";
  if (drop) { drop.hidden = true; drop.innerHTML = ""; }
  SEARCH.results = [];
  SEARCH.selectedIdx = -1;
}

// Trigger background load of all unloaded seasons so the index covers
// every year. Cheap to call repeatedly — guarded by SEARCH.fullDataLoading.
function ensureFullSearchData() {
  if (SEARCH.fullDataLoaded || SEARCH.fullDataLoading) return;
  const allYears = Object.keys(SEASON_CACHE).map(Number);
  const missing = (STATE.seasonsAvailable || []).filter(y => !allYears.includes(y));
  if (missing.length === 0) {
    SEARCH.fullDataLoaded = true;
    return;
  }
  SEARCH.fullDataLoading = true;
  Promise.all(missing.map(y => loadSeasonIntoCache(y)))
    .then(() => {
      SEARCH.fullDataLoaded = true;
      SEARCH.fullDataLoading = false;
      SEARCH.index = null;   // invalidate so next query rebuilds
      // If user is still in the search box, refresh results
      const input = document.getElementById("search-input");
      if (input && document.activeElement === input && input.value.trim()) {
        renderSearchResults(searchAll(input.value));
      }
    })
    .catch(() => { SEARCH.fullDataLoading = false; });
}

// Tab dropdown groups — when the user clicks a tab/subitem within a
// .dash-tab-group, the page navigates but :hover stays latched on the
// just-clicked element until the cursor moves, leaving the submenu
// stuck open over the destination view. We mark the group .just-clicked
// to suppress the hover-open state, then clear the flag on mouseleave
// so re-hovering re-opens normally. Subitems also force-blur themselves
// so :focus-within doesn't latch the menu open either.
function wireTabDropdowns() {
  document.querySelectorAll(".dash-tab-group").forEach(grp => {
    // Click on parent tab OR any subitem → mark group, force-blur active
    // element, allow nav to proceed
    grp.querySelectorAll(".dash-tab-parent, .dash-subitem").forEach(a => {
      a.addEventListener("click", () => {
        grp.classList.add("just-clicked");
        // Defer blur so the click navigation actually fires first
        setTimeout(() => {
          if (document.activeElement && grp.contains(document.activeElement)) {
            document.activeElement.blur();
          }
        }, 0);
      });
    });
    // Cursor leaves the group → reset, so next hover behaves normally
    grp.addEventListener("mouseleave", () => {
      grp.classList.remove("just-clicked");
    });
  });
}

function wireSearch() {
  const input = document.getElementById("search-input");
  const drop = document.getElementById("search-dropdown");
  const wrap = document.getElementById("topbar-search");
  if (!input || !drop) return;

  // Mobile: tap on the search container expands it from icon-only to
  // full input. On blur (and the user hasn't typed anything), collapse
  // back to icon-only. Desktop CSS doesn't apply .expanded so this
  // class flip is a no-op there.
  const expandSearch = () => {
    if (!wrap) return;
    wrap.classList.add("expanded");
    // Focus the input AFTER the class flip so the cursor lands properly
    setTimeout(() => input.focus(), 0);
  };
  const collapseSearch = () => {
    if (!wrap) return;
    wrap.classList.remove("expanded");
    drop.hidden = true;
  };
  if (wrap) {
    wrap.addEventListener("click", (e) => {
      // Don't re-expand if already expanded; the input handles its own
      // focus inside that state. Also: clicking the close button
      // (rendered when expanded) explicitly collapses regardless of
      // input content.
      if (e.target.closest(".topbar-search-close")) {
        e.preventDefault();
        e.stopPropagation();
        input.value = "";
        drop.hidden = true;
        drop.innerHTML = "";
        collapseSearch();
        input.blur();
        return;
      }
      if (!wrap.classList.contains("expanded")) {
        e.stopPropagation();
        expandSearch();
      }
    });
  }
  // Click outside ALWAYS closes the expanded search on mobile. Previously
  // we only collapsed when the input was empty, which meant a user who
  // typed a query had no way to dismiss the bar on mobile (no Escape key
  // on touch keyboards). Now we clear and close on any outside tap.
  document.addEventListener("click", (e) => {
    if (!wrap || !wrap.classList.contains("expanded")) return;
    if (wrap.contains(e.target)) return;
    input.value = "";
    drop.hidden = true;
    drop.innerHTML = "";
    collapseSearch();
  });
  // Escape collapses it too.
  input.addEventListener("keydown", (e) => {
    if (e.key === "Escape") {
      input.value = "";
      drop.hidden = true;
      drop.innerHTML = "";
      collapseSearch();
      input.blur();
    }
  });
  // Debounced query handler — keystrokes are cheap but rebuilding the index
  // when years just landed isn't, so debounce ~120ms.
  let debounceTimer = null;
  input.addEventListener("input", () => {
    clearTimeout(debounceTimer);
    debounceTimer = setTimeout(() => {
      const q = input.value.trim();
      if (q.length === 0) {
        drop.hidden = true;
        drop.innerHTML = "";
        return;
      }
      renderSearchResults(searchAll(q));
    }, 120);
  });

  // First focus → kick off background full load
  input.addEventListener("focus", () => {
    ensureFullSearchData();
    // If there's already a query, re-render with current index
    const q = input.value.trim();
    if (q) renderSearchResults(searchAll(q));
  });

  // Keyboard navigation in the dropdown
  input.addEventListener("keydown", async (e) => {
    if (e.key === "ArrowDown") {
      e.preventDefault();
      setSearchKbdSelection(SEARCH.selectedIdx + 1);
    } else if (e.key === "ArrowUp") {
      e.preventDefault();
      setSearchKbdSelection(SEARCH.selectedIdx - 1);
    } else if (e.key === "Enter") {
      e.preventDefault();
      let target = SEARCH.results[SEARCH.selectedIdx];
      // If user hits Enter without selecting, take first result
      if (!target && SEARCH.results.length > 0) target = SEARCH.results[0];
      if (target) {
        if (target.type === "race") {
          await handleSearchRaceClick(target.href);
        } else {
          location.hash = target.href;
        }
        clearSearch();
        input.blur();
      }
    } else if (e.key === "Escape") {
      e.preventDefault();
      clearSearch();
      input.blur();
    }
  });

  // Click on a result — special-case races for context switching
  drop.addEventListener("click", async (e) => {
    const a = e.target.closest(".search-result");
    if (!a) return;
    const href = a.getAttribute("href");
    if (href && href.startsWith("#/race/") && href.includes("?_y=")) {
      e.preventDefault();
      await handleSearchRaceClick(href);
      clearSearch();
      return;
    }
    // Standard hash routes — let the browser handle it but close dropdown
    setTimeout(() => clearSearch(), 0);
  });

  // Click anywhere outside → close dropdown
  document.addEventListener("click", (e) => {
    if (drop.hidden) return;
    if (e.target.closest("#topbar-search")) return;
    drop.hidden = true;
  });

  // Global hotkey: "/" or Cmd/Ctrl-K focuses the search bar
  document.addEventListener("keydown", (e) => {
    // Skip if user is typing in another input/textarea
    const t = e.target;
    const inField = t && (t.tagName === "INPUT" || t.tagName === "TEXTAREA"
      || t.isContentEditable);
    if (e.key === "/" && !inField) {
      e.preventDefault();
      input.focus();
      input.select();
    } else if ((e.key === "k" || e.key === "K") && (e.metaKey || e.ctrlKey)) {
      e.preventDefault();
      input.focus();
      input.select();
    }
  });
}


// ============================================================
// Spider chart label tooltips
// ============================================================
// Custom hover/tap tooltip for the radar chart axis labels — replaces the
// native SVG <title> which has a slow ~1.5s show delay and disappears
// the moment the mouse moves. This handler attaches at the document
// level (once), uses event delegation, and works for both the compare
// spider AND the profile spider since they share the same selectors.
function _wireSpiderTooltips() {
  if (document.body._spiderTooltipWired) return;
  document.body._spiderTooltipWired = true;

  // Find (or build) the floating tooltip element inside a given host.
  // The renderers emit an empty <div class="cmp-spider-tooltip" hidden>
  // alongside the SVG; we populate + position it on hover.
  const tooltipForHost = (host) => host.querySelector(".cmp-spider-tooltip");

  const showTooltipForGroup = (group) => {
    const host = group.closest(".cmp-spider-host");
    if (!host) return;
    const tip = tooltipForHost(host);
    if (!tip) return;
    const label = group.dataset.axisLabel || "";
    const sub = group.dataset.axisSub || "";
    const explain = group.dataset.axisExplain || "";
    tip.innerHTML = `
      <div class="cmp-spider-tip-title">${label}<span class="cmp-spider-tip-scope">${sub}</span></div>
      <div class="cmp-spider-tip-body">${explain}</div>
    `;
    // Position over the host using the group's bounding rect. Bounds
    // are in document coordinates; subtract the host's offset to get
    // local coords.
    const hostRect = host.getBoundingClientRect();
    const groupRect = group.getBoundingClientRect();
    // Default: center the tooltip horizontally on the group, place it
    // 8px below. If that overflows the host's right edge, shift left;
    // if it'd overflow below the host, place above instead.
    tip.hidden = false;
    const tipRect = tip.getBoundingClientRect();
    let left = (groupRect.left - hostRect.left) + (groupRect.width / 2) - (tipRect.width / 2);
    let top = (groupRect.top - hostRect.top) + groupRect.height + 8;
    // Clamp horizontally inside the host
    left = Math.max(6, Math.min(hostRect.width - tipRect.width - 6, left));
    // If tooltip would extend below the host, flip above the label
    if (top + tipRect.height > hostRect.height - 4) {
      top = (groupRect.top - hostRect.top) - tipRect.height - 8;
    }
    tip.style.left = `${left}px`;
    tip.style.top = `${top}px`;
  };

  const hideAllTooltips = () => {
    document.querySelectorAll(".cmp-spider-tooltip").forEach(tip => {
      tip.hidden = true;
    });
  };

  // Desktop hover. We use mouseover/mouseout (which bubble) rather than
  // mouseenter/mouseleave (which don't bubble — wouldn't work with
  // event delegation). The relatedTarget check on mouseout prevents
  // hiding the tooltip when the cursor moves between the label and
  // sublabel text inside the same group.
  document.body.addEventListener("mouseover", (e) => {
    if (!e.target || !e.target.closest) return;
    const group = e.target.closest(".cmp-spider-label-group");
    if (!group) return;
    showTooltipForGroup(group);
  });

  document.body.addEventListener("mouseout", (e) => {
    if (!e.target || !e.target.closest) return;
    const group = e.target.closest(".cmp-spider-label-group");
    if (!group) return;
    // Only hide if cursor genuinely left the group (not moved between
    // internal children — text label / sublabel — which both fire
    // mouseout/mouseover events as the cursor crosses their boundaries).
    const related = e.relatedTarget;
    if (related && group.contains(related)) return;
    hideAllTooltips();
  });

  // Mobile tap-to-toggle: tap a label to show; tap anywhere else to hide.
  // This is in capture phase so we beat any link-navigation on the page.
  document.body.addEventListener("click", (e) => {
    const group = e.target.closest && e.target.closest(".cmp-spider-label-group");
    if (group) {
      // Tap on a label — toggle its tooltip
      const host = group.closest(".cmp-spider-host");
      const tip = host && tooltipForHost(host);
      if (tip && !tip.hidden) {
        hideAllTooltips();
      } else {
        showTooltipForGroup(group);
      }
      e.stopPropagation();
      return;
    }
    // Tap anywhere else — close any open spider tooltip
    if (e.target.closest && !e.target.closest(".cmp-spider-tooltip")) {
      hideAllTooltips();
    }
  });
}
// Wire on script-load (module-level) — body should exist by the time
// this script runs since we're at end-of-body inclusion.
_wireSpiderTooltips();



// ============================================================
// BOOT
// ============================================================

// Dev/debug helper exposed on `window.dcDebug` so the user can inspect
// data presence from the browser console. Run any of:
//   dcDebug.cc()                       — summary of CC data in current season
//   dcDebug.cc(2024)                   — same but for a specific year (must be loaded)
//   dcDebug.field("crew_chief")        — counts how many rows have this field
//   dcDebug.findCC("mcaulay")          — search loaded years for CC name substring
//   await dcDebug.ccAll("sam-mcaulay") — load ALL years, dump every (year, series) row
//                                         for that CC slug; flags name variants + gaps
//   dcDebug.car("48")                  — per-race breakdown of a car number this season
//   dcDebug.driver("alex-bowman")      — per-race breakdown of a driver slug this season
window.dcDebug = {
  cc(year) {
    const block = year != null
      ? (SEASON_CACHE[year] && SEASON_CACHE[year][STATE.series])
      : STATE.data;
    if (!block) {
      console.log(`No data loaded for ${year || "current"} ${STATE.series}.`);
      return;
    }
    const races = block.races || [];
    let total = 0, withCC = 0;
    const sample = [];
    races.forEach(r => {
      (r.results || []).forEach(d => {
        total++;
        if (d.crew_chief) {
          withCC++;
          if (sample.length < 5) sample.push(`R${r.round} #${d.car_number} ${d.driver} → ${d.crew_chief}`);
        }
      });
    });
    console.log(`Season: ${year || STATE.season} ${STATE.series}`);
    console.log(`Result rows: ${total} total, ${withCC} with crew_chief (${total ? Math.round(100*withCC/total) : 0}%)`);
    if (sample.length) console.log("Sample:", sample);
    if (withCC === 0 && total > 0) {
      console.log("⚠️  Zero crew_chief values — either data file lacks the field or the field name differs.");
      const firstRow = (races[0]?.results || [])[0];
      if (firstRow) console.log("First-row keys:", Object.keys(firstRow));
    }
  },
  field(fieldName) {
    if (!STATE.data) { console.log("No data loaded."); return; }
    let total = 0, present = 0;
    (STATE.data.races || []).forEach(r => {
      (r.results || []).forEach(d => {
        total++;
        if (d[fieldName] != null && d[fieldName] !== "") present++;
      });
    });
    console.log(`Field "${fieldName}": ${present}/${total} rows populated`);
  },
  // Search every loaded year for crew chief names containing the substring.
  // Useful for finding missing CCs ("does Sam McAulay show up in 2025?").
  // Pass case-insensitive substring; prints (year, series, round, driver, cc).
  findCC(substring) {
    if (!substring) { console.log("Usage: dcDebug.findCC('mcaulay')"); return; }
    const needle = substring.toLowerCase();
    const hits = [];
    Object.keys(SEASON_CACHE).map(Number).sort().forEach(year => {
      const blocks = SEASON_CACHE[year];
      if (!blocks) return;
      ["NCS", "NOS", "NTS"].forEach(s => {
        const b = blocks[s];
        if (!b || !b.races) return;
        b.races.forEach(r => {
          (r.results || []).forEach(d => {
            if (d.crew_chief && d.crew_chief.toLowerCase().includes(needle)) {
              hits.push({ year, series: s, round: r.round, driver: d.driver, cc: d.crew_chief });
            }
          });
        });
      });
    });
    if (!hits.length) {
      console.log(`No matches for "${substring}" in loaded data.`);
      return;
    }
    // Aggregate by (year, series) to summarize coverage
    const byYS = new Map();
    hits.forEach(h => {
      const k = `${h.year}-${h.series}`;
      if (!byYS.has(k)) byYS.set(k, { year: h.year, series: h.series, count: 0, drivers: new Set() });
      const v = byYS.get(k);
      v.count++;
      v.drivers.add(h.driver);
    });
    console.log(`Found ${hits.length} rows matching "${substring}":`);
    Array.from(byYS.values()).sort((a, b) => b.year - a.year || a.series.localeCompare(b.series)).forEach(v => {
      console.log(`  ${v.year} ${v.series}: ${v.count} races · drivers: ${Array.from(v.drivers).join(", ")}`);
    });
  },
  // Heavy-duty diagnostic: load EVERY available season, then dump every
  // (year, series) row where the given slug appears. Also surfaces the
  // exact spelling(s) found, so name-variant bugs (e.g., "Samuel McAulay"
  // vs "Sam McAulay") become obvious. Returns a Promise.
  //
  // Usage:
  //   await dcDebug.ccAll("sam-mcaulay")       // canonical CC slug
  //   await dcDebug.ccAll("mcaulay", true)     // substring mode (slug includes)
  async ccAll(slugOrSub, substringMode = false) {
    if (!slugOrSub) { console.log("Usage: dcDebug.ccAll('sam-mcaulay')"); return; }
    const needle = slugOrSub.toLowerCase();
    const allYears = (STATE.seasonsAvailable || []).slice().sort((a, b) => a - b);
    const missing = allYears.filter(y => !SEASON_CACHE[y]);
    if (missing.length) {
      console.log(`Loading ${missing.length} missing season(s)…`);
      // Load in batches of 4 to avoid hammering Pages
      for (let i = 0; i < missing.length; i += 4) {
        await Promise.all(missing.slice(i, i + 4).map(y => loadSeasonIntoCache(y)));
      }
    }
    // Walk every cached year, every series
    const rows = [];      // {year, series, slug, name, count, drivers:Set, totalInSeason}
    const spellings = new Map();   // slug → Set(exact spellings)
    Object.keys(SEASON_CACHE).map(Number).sort((a, b) => a - b).forEach(year => {
      const blocks = SEASON_CACHE[year];
      if (!blocks) return;
      ["NCS", "NOS", "NTS"].forEach(s => {
        const b = blocks[s];
        if (!b || !b.races) return;
        const totalInSeason = (b.races || []).filter(r => (r.results || []).length > 0).length;
        const ysAgg = new Map();   // ccSlug → {name, count, drivers:Set}
        b.races.forEach(r => {
          (r.results || []).forEach(d => {
            if (!d.crew_chief) return;
            const ccSlug = slugify(d.crew_chief);
            const matches = substringMode
              ? ccSlug.includes(needle)
              : ccSlug === needle;
            if (!matches) return;
            if (!ysAgg.has(ccSlug)) ysAgg.set(ccSlug, { name: d.crew_chief, count: 0, drivers: new Set() });
            const v = ysAgg.get(ccSlug);
            v.count++;
            if (d.driver) v.drivers.add(d.driver);
            if (!spellings.has(ccSlug)) spellings.set(ccSlug, new Set());
            spellings.get(ccSlug).add(d.crew_chief);
          });
        });
        ysAgg.forEach((v, ccSlug) => {
          rows.push({ year, series: s, slug: ccSlug, name: v.name,
                      count: v.count, totalInSeason,
                      ratio: totalInSeason ? v.count / totalInSeason : 0,
                      drivers: Array.from(v.drivers) });
        });
      });
    });
    if (!rows.length) {
      console.log(`No matches for "${slugOrSub}" across ${Object.keys(SEASON_CACHE).length} loaded year(s).`);
      console.log("Try substring mode: dcDebug.ccAll('mcaulay', true)");
      return;
    }
    console.log(`%cccAll("${slugOrSub}") — ${rows.length} (year, series) row(s)`,
                "font-weight:bold;color:#d4a017");
    console.log("Spellings encountered:");
    spellings.forEach((set, ccSlug) => {
      console.log(`  slug "${ccSlug}":`, Array.from(set).join(" | "));
    });
    console.table(rows.map(r => ({
      year: r.year,
      series: r.series,
      slug: r.slug,
      starts: r.count,
      total: r.totalInSeason,
      ratio: r.ratio.toFixed(2),
      ft: r.ratio >= 0.80 ? "✓" : "",
      drivers: r.drivers.join(", "),
    })));
    // Highlight any year that's covered for multiple slugs (likely name variant)
    const yearsBySlug = new Map();
    rows.forEach(r => {
      if (!yearsBySlug.has(r.slug)) yearsBySlug.set(r.slug, new Set());
      yearsBySlug.get(r.slug).add(r.year);
    });
    if (yearsBySlug.size > 1) {
      console.log(`%c⚠️  Multiple slugs matched — possible name variant.`,
                  "color:#ff7070;font-weight:bold");
      yearsBySlug.forEach((yrs, sl) => {
        console.log(`  "${sl}" appears in: ${Array.from(yrs).sort().join(", ")}`);
      });
    }
    // Show gaps in years for the canonical slug (if exact mode)
    if (!substringMode) {
      const yrs = Array.from(yearsBySlug.get(needle) || []).sort();
      if (yrs.length >= 2) {
        const gaps = [];
        for (let i = 1; i < yrs.length; i++) {
          for (let y = yrs[i - 1] + 1; y < yrs[i]; y++) gaps.push(y);
        }
        if (gaps.length) {
          console.log(`%cYears with no rows for "${needle}": ${gaps.join(", ")}`,
                      "color:#ff9966");
          console.log(`(Confirms the gap is in the data, not the UI filter.)`);
        }
      }
    }
  },
  // Per-race breakdown for a given car number in the CURRENT season + series.
  // Surfaces every race result row, the team_code/team that resolved, and
  // whether the row was flagged ineligible. Use this when a car looks like
  // it should be full-time but isn't appearing in the Teammate FT view.
  //
  //   dcDebug.car("48")
  car(carNum) {
    if (!STATE.data) { console.log("No data loaded."); return; }
    const target = String(carNum);
    const races = STATE.data.races || [];
    const completed = races.filter(r => (r.results || []).length > 0);
    console.log(`%cdcDebug.car("${target}") — ${STATE.season} ${STATE.series}`,
                "font-weight:bold;color:#d4a017");
    console.log(`Completed races in season: ${completed.length}`);
    const rows = [];
    completed.forEach(r => {
      const matches = (r.results || []).filter(d => String(d.car_number || "") === target);
      if (matches.length === 0) {
        rows.push({ round: r.round, track: r.track || "?", driver: "—",
                    team: "—", team_code: "—", finish: "—",
                    ineligible: "—", note: "no #" + target });
      } else {
        matches.forEach(d => {
          rows.push({
            round: r.round,
            track: r.track || "?",
            driver: d.driver || "?",
            team: d.team || "?",
            team_code: d.team_code || "(none)",
            finish: d.finish_pos != null ? d.finish_pos : "—",
            ineligible: d.ineligible ? "✓ INELIGIBLE" : "",
            note: matches.length > 1 ? "multi-row race" : "",
          });
        });
      }
    });
    console.table(rows);
    // Quick FT check
    const present = rows.filter(r => r.driver !== "—" && !r.ineligible).length;
    console.log(`Eligible appearances: ${present}/${completed.length}` +
                (present === completed.length ? "  → would qualify as full-time" : "  → NOT full-time"));
  },
  // Per-race breakdown for a driver slug. Useful when a driver has run for
  // multiple cars (e.g., a substitute) — shows EVERY car# they appeared in.
  //
  //   dcDebug.driver("alex-bowman")
  driver(slug) {
    if (!STATE.data) { console.log("No data loaded."); return; }
    const needle = (slug || "").toLowerCase();
    const races = STATE.data.races || [];
    const completed = races.filter(r => (r.results || []).length > 0);
    console.log(`%cdcDebug.driver("${needle}") — ${STATE.season} ${STATE.series}`,
                "font-weight:bold;color:#d4a017");
    console.log(`Completed races in season: ${completed.length}`);
    const rows = [];
    completed.forEach(r => {
      const matches = (r.results || []).filter(d => slugify(d.driver || "") === needle);
      matches.forEach(d => {
        rows.push({
          round: r.round,
          track: r.track || "?",
          car: d.car_number || "?",
          team: d.team || "?",
          team_code: d.team_code || "(none)",
          finish: d.finish_pos != null ? d.finish_pos : "—",
          ineligible: d.ineligible ? "✓ INELIGIBLE" : "",
        });
      });
    });
    if (rows.length === 0) {
      console.log(`No appearances for slug "${needle}" in current season ${STATE.series}.`);
      return;
    }
    console.table(rows);
    const carCounts = {};
    rows.forEach(r => { if (!r.ineligible) carCounts[r.car] = (carCounts[r.car] || 0) + 1; });
    console.log(`Car counts (eligible only):`, carCounts);
  },
};

async function boot() {
  // Restore theme preference before any UI paints, so we never flash
  // the wrong palette. Defaults to light (the design system's home base).
  try {
    const saved = localStorage.getItem("dcr-theme");
    if (saved === "light" || saved === "dark") {
      document.documentElement.setAttribute("data-theme", saved);
    }
  } catch (e) { /* localStorage may be unavailable */ }
  // Sync the topbar's theme-toggle icon to whatever's active (the click
  // handler in wireUIControls flips it on every click but doesn't run at
  // boot).
  {
    const active = document.documentElement.getAttribute("data-theme") || "light";
    const icon = document.querySelector("#theme-toggle .theme-toggle-icon");
    if (icon) icon.textContent = active === "light" ? "☾" : "☀";
  }
  // Restore the user's mode (Present/Historical) preference BEFORE wiring
  // any UI — so the toggle button starts in the right state and the
  // season-picker visibility doesn't flicker on first paint.
  restoreModeFromStorage();
  wireUIControls();
  wireMobileNav();
  wirePickerDrawers();
  applyMobileLanding();
  wireSearch();
  wireRaceLightbox();
  wireTabDropdowns();
  observeMobileDropdowns();   // self-heals mobile <select> mirrors on any render
  wireCollapsibleRows();      // tap-to-expand for .m-collapse table rows
  await loadColors();
  loadDriverBios();  // async, not awaited — profile will use it whenever it arrives
  await discoverSeasons();
  parseHash();
  if (!STATE.seasonsAvailable.includes(STATE.season)) {
    STATE.season = STATE.seasonsAvailable[0] || 2026;
  }
  // In Present mode, force STATE.season to the latest available year
  // regardless of what was in the URL or saved state. The user opted
  // into "always live"; we honor that on every load.
  if (STATE.mode === "present") {
    const latest = STATE.seasonsAvailable[0];
    if (latest && STATE.season !== latest) {
      STATE.season = latest;
      STATE.throughRound = null;
    }
  }
  populateSeasonPicker();
  applyModeToDom();   // hide/show season picker based on restored mode
  // If the landing view is series-scoped, adopt that page's remembered
  // series (defaults to NCS) BEFORE the initial data load so we fetch the
  // right block. Home / entity / all-time views are left untouched.
  ensurePageSeries();
  // Sync series toggle UI to initial STATE.series — sets data-series
  // on the mobile <select> so it gets the correct color at boot.
  syncSeriesUIGlobal(STATE.series);
  await loadCurrentData();
  populateRacePicker();
  renderTimeCursorBanner();
  // If the user landed directly on a driver route, resolve home before render
  if (STATE.view === "profile" && STATE.profile && STATE.profile.kind === "driver") {
    await resolveDriverRoute();
  }
  // Legacy car-route redirect: if user came in via #/car/N, resolve to the
  // current primary driver's slug and rewrite the URL. Falls through cleanly
  // if the car isn't in current data (renderProfile shows "not found").
  redirectLegacyCarRoute();
  // If the user landed cold on a race deep-link (#/race/N?_y=YYYY&_s=NCS),
  // route through the same handler the hashchange listener uses. In
  // Present mode this opens the lightbox; in Historical mode it switches
  // context to the linked year/series.
  const bootDeepLink = await handleRaceDeepLink();
  document.getElementById("time-cursor-reset")?.addEventListener("click", () => {
    STATE.throughRound = null;
    populateRacePicker();   // refresh selected state
    renderTimeCursorBanner();
    render();
  });
  // If the boot deep-link opened a lightbox, the underlying view should
  // be neutral (standings is a safe default) so closing the lightbox
  // doesn't leave the user on a half-loaded race takeover.
  if (bootDeepLink === "lightbox") {
    STATE.view = "standings";
    STATE.race = { round: null };
    history.replaceState(null, "", "#/standings");
  }
  render();
  // Warm SEASON_CACHE during browser idle time so the all-time pages
  // and search bar feel instant when users click into them. We use
  // requestIdleCallback if available; otherwise a setTimeout fallback.
  // Loads in small batches so we don't compete with main-thread paint.
  const warmCache = async () => {
    const missing = (STATE.seasonsAvailable || []).filter(y => !SEASON_CACHE[y]);
    if (missing.length === 0) return;
    for (let i = 0; i < missing.length; i += 3) {
      const batch = missing.slice(i, i + 3);
      const loaded = await Promise.all(batch.map(y => loadSeasonIntoCache(y).catch(() => null)));
      const anyLoaded = loaded.some(Boolean);
      // After a batch lands, if the user is on a view that depends on
      // cross-season driver analytics, re-render so the freshly-loaded
      // years can populate any "no history" empty states. The analytics
      // cache itself is already invalidated inside loadSeasonIntoCache;
      // we just need to trigger the view to re-fold.
      // Track view has its own batch-complete re-render hook already
      // (see renderTrackPage), so we only need to handle home here.
      if (anyLoaded && STATE.view === "home") {
        try { renderHome(); } catch (_) { /* swallow — best effort */ }
      }
      await new Promise(r => setTimeout(r, 60));
    }
  };
  if (typeof requestIdleCallback === "function") {
    requestIdleCallback(() => { warmCache(); }, { timeout: 3000 });
  } else {
    setTimeout(warmCache, 1500);
  }
  window.addEventListener("hashchange", async () => {
    // Any URL change dismisses the race lightbox. Covers all navigation
    // pathways — clicking an inner driver/team link, browser back/forward,
    // search bar suggestion, etc. — without each call site needing to
    // remember to close it.
    if (STATE.lightbox && STATE.lightbox.open) {
      closeRaceLightbox();
    }
    const preSeason = STATE.season;
    const preSeries = STATE.series;
    parseHash();
    // If parseHash kicked off a series swap (e.g. from #/standings?series=NOS),
    // wait for the new series' data to land before rendering. Otherwise the
    // render would paint the new STATE.series against the previous block.
    if (STATE.pendingSeriesSwap) {
      const swap = STATE.pendingSeriesSwap;
      delete STATE.pendingSeriesSwap;
      await swap;
      // applySeriesChangeGlobal already called render() on completion, so
      // we're done. Just sync nav UI and return.
      markMobileNavActive();
      closeMobileNav();
      return;
    }
    // Race route with deep-link query params (#/race/N?_y=YYYY&_s=NCS).
    const handled = await handleRaceDeepLink();
    if (handled === "lightbox") {
      // Lightbox flow took over — skip the rest of the render pipeline
      // so the page underneath stays as it was.
      markMobileNavActive();
      closeMobileNav();
      return;
    }
    // Driver-centric route: resolve home (series, season) before rendering
    if (STATE.view === "profile" && STATE.profile && STATE.profile.kind === "driver") {
      await resolveDriverRoute();
    }
    // Per-page series: if we navigated to a series-scoped view, adopt that
    // page's remembered series (independent of every other page). Runs after
    // the profile resolver (which owns its own series) and before the load
    // guard below, so any change is picked up by the same loadCurrentData.
    ensurePageSeries();
    if (STATE.season !== preSeason || STATE.series !== preSeries) {
      await loadCurrentData();
      resetRenderCache();
      populateRacePicker();
      renderTimeCursorBanner();
      // Series buttons in the topbar are tied to STATE.series. Any time
      // navigation changes the series (resolveDriverRoute pulling us
      // into a different series for a profile, or parseHash restoring
      // the pre-takeover series), the toggle UI needs to follow.
      syncSeriesUIGlobal(STATE.series);
    }
    // Clear the restore flag — it's only there to signal parseHash's
    // intent; the actual reload was handled by the guard above.
    if (STATE.pendingSeriesRestore) delete STATE.pendingSeriesRestore;
    redirectLegacyCarRoute();
    render();
    markMobileNavActive();
    closeMobileNav();
  });
}

// Process a race route deep-link (the `?_y=YYYY&_s=NCS` suffix on
// #/race/N URLs). In Present mode → open lightbox without changing
// STATE. In Historical mode → switch context to the linked year/series
// so the race takeover renders against that data. Returns:
//   "lightbox" — handled via lightbox; caller should skip downstream render
//   "switched" — STATE was changed; caller continues normal render
//   null       — no deep-link present, nothing happened
async function handleRaceDeepLink() {
  if (STATE.view !== "race" || !STATE.race || !STATE.race.deepLinkYear) {
    return null;
  }
  const y = STATE.race.deepLinkYear;
  const s = STATE.race.deepLinkSeries;
  const round = STATE.race.round;
  // Clear markers so subsequent renders don't keep reacting
  delete STATE.race.deepLinkYear;
  delete STATE.race.deepLinkSeries;

  if (STATE.mode === "present" && (y !== STATE.season || s !== STATE.series)) {
    // Rewrite URL back to plain race route so reloading doesn't re-trigger
    // and the back button has a stable history entry.
    history.replaceState(null, "", `#/race/${round}`);
    await openRaceLightbox(y, s, round);
    return "lightbox";
  }
  if (STATE.mode === "historical" && (y !== STATE.season || s !== STATE.series)) {
    STATE.season = y;
    STATE.series = s;
    STATE.throughRound = null;
    await loadCurrentData();
    resetRenderCache();
    populateRacePicker();
    renderTimeCursorBanner();
    document.querySelectorAll("#series-sw button").forEach(b =>
      b.classList.toggle("on", b.dataset.series === s)
    );
    const seriesSel = document.getElementById("series-sw-select");
    if (seriesSel && seriesSel.value !== s) seriesSel.value = s;
    const sel = document.getElementById("season-picker");
    if (sel) sel.value = String(y);
    history.replaceState(null, "", `#/race/${round}`);
    return "switched";
  }
  return null;
}

// If the current route is #/car/<N>, look up the primary driver of that
// car in current data and rewrite the URL to #/driver/<slug>. This makes
// every profile driver-centric — clicks anywhere become driver routes,
// chip jumps work without accidentally swapping driver, and old bookmarks
// of car URLs survive. If we can't resolve (no data, car not present),
// leave it as car-kind so renderProfile shows "Profile not found" cleanly.
function redirectLegacyCarRoute() {
  if (!STATE.profile || STATE.profile.kind !== "car") return;
  if (!STATE.data) return;
  const carNum = STATE.profile.slug;
  if (!carNum) return;
  const ents = allEntities();
  const ent = ents.find(e => e.car_number === carNum);
  if (!ent) return;
  const drv = ent.primaryDriver || ent.driver;
  if (!drv) return;
  const drvSlug = slugify(drv);
  // Update STATE in place + rewrite URL hash without firing hashchange
  STATE.profile.kind = "driver";
  STATE.profile.slug = drvSlug;
  STATE.profile.resolvedCarNumber = ent.car_number;
  STATE.profile.resolvedDriver = drv;
  const canonical = `#/driver/${drvSlug}`;
  if (location.hash !== canonical) {
    try { history.replaceState(null, "", canonical); } catch (_) {}
    STATE.lastHash = canonical;
  }
}

// Resolves a #/driver/<slug> route to a concrete (series, season) and loads
// data for it. Always picks the driver's home (most-recent full-time year);
// users can switch year/series from inside the profile body.
async function resolveDriverRoute() {
  const slug = STATE.profile && STATE.profile.slug;
  if (!slug) return;

  // Make sure the newest available season is in cache BEFORE resolving the
  // driver's home. findDriverHomeContext only sees cached years, so without
  // this a driver active in the current year (whose current-year series block
  // happens not to be loaded yet) would resolve to an older cached season —
  // the whole profile would then render a stale year (e.g. a full-time 2026
  // driver shown framed in 2025, comparing against 2024). One fetch; cached.
  const newestSeason = (STATE.seasonsAvailable && STATE.seasonsAvailable[0]) || STATE.season;
  if (newestSeason && !SEASON_CACHE[newestSeason]) {
    try { await loadSeasonIntoCache(newestSeason); } catch (_) { /* non-fatal */ }
  }

  // First-pass home detection from already-cached seasons
  let home = findDriverHomeContext(slug);

  // If not found, opportunistically try recent years that may not be cached.
  // Walks back to STATE.season - 8 to catch drivers who retired recently
  // (Clint Bowyer 2020, Kurt Busch 2022, etc). Hard cap of 8 years keeps
  // network usage bounded — drivers from before that window will fall
  // through to the bio-based fallback in renderProfile.
  if (!home.found) {
    const yearsToTry = [];
    for (let dy = 0; dy <= 8; dy++) {
      yearsToTry.push(STATE.season - dy);
    }
    for (const y of yearsToTry) {
      if (SEASON_CACHE[y]) continue;
      try {
        await loadSeasonIntoCache(y);
        home = findDriverHomeContext(slug);
        if (home.found) break;
      } catch (_) { /* skip year */ }
    }
  }

  if (!home.found) return;

  const needSwitchSeries = home.series !== STATE.series;
  const needSwitchSeason = home.season !== STATE.season;
  if (needSwitchSeries || needSwitchSeason) {
    STATE.series = home.series;
    STATE.season = home.season;
    await loadCurrentData();
    resetRenderCache();
    // Sync the topbar series buttons + mobile select to match the
    // resolved series. Without this, after navigating to a Truck driver
    // the topbar still shows NCS as active and the series toggle UI
    // disagrees with STATE.series.
    if (needSwitchSeries) syncSeriesUIGlobal(STATE.series);
  }
  STATE.profile.resolvedCarNumber = home.car_number;
  STATE.profile.resolvedDriver = home.driver;
}

// ============================================================
// MOBILE NAV
// ============================================================
// A simple viewport check. Matches the CSS breakpoint (<768px). We don't
// respond to resize dynamically — if someone rotates / resizes into the other
// mode, a refresh reapplies. Keeps the code simpler and avoids fighting CSS.
function isMobile() {
  return window.matchMedia("(max-width: 767.98px)").matches;
}

// On mobile, if the URL hash is empty or points to the desktop landing tab,
// redirect to the mobile landing tab (Trending). Does nothing on desktop.
// Called once during boot, before render(). Uses replaceState so the browser
// back button doesn't stack an extra history entry.
function applyMobileLanding() {
  if (!isMobile()) return;
  const h = (location.hash || "").replace(/^#\//, "").split("/")[0];
  // If no hash, route to home (same default as desktop). Empty hash on
  // a fresh visit used to redirect to Trending — but Home is the new
  // canonical landing for everyone, mobile and desktop alike.
  if (!h) {
    history.replaceState(null, "", "#/home");
  }
}

function openMobileNav() {
  const nav = document.getElementById("mobile-nav");
  const overlay = document.getElementById("mobile-nav-overlay");
  const btn = document.getElementById("mobile-menu-btn");
  if (!nav || !overlay || !btn) return;
  syncMobileNavSettings();
  nav.hidden = false;
  overlay.hidden = false;
  btn.setAttribute("aria-expanded", "true");
  markMobileNavActive();
  // Prevent body scroll while sheet is open
  document.body.style.overflow = "hidden";
}

// Mirror the desktop-topbar season + race selects into the mobile nav sheet.
// The desktop selects are still the source of truth; we copy their <option>s
// across and wire a 'change' on the mobile select that re-fires on the desktop
// one (which already has all the right handlers wired).
function syncMobileNavSettings() {
  // Mirrors the desktop topbar season/race pickers into the mobile-only
  // secondary topbar row (#topbar-historical), so phone users in
  // Historical mode have year + race-cursor controls without opening
  // the side-sheet. Idempotent — listener marker prevents stacking.
  const desktopSeason = document.getElementById("season-picker");
  const desktopRace = document.getElementById("race-picker");
  const mobSeason = document.getElementById("topbar-historical-season");
  const mobRace = document.getElementById("topbar-historical-race");
  if (!desktopSeason || !mobSeason || !desktopRace || !mobRace) return;

  // Copy options across (rebuild each time — option lists change with data load).
  const copyOptions = (src, dst) => {
    dst.innerHTML = src.innerHTML;
    dst.value = src.value;
  };
  copyOptions(desktopSeason, mobSeason);
  copyOptions(desktopRace, mobRace);

  // Wire change handlers (idempotent — replace prior listener via marker).
  if (!mobSeason._wired) {
    mobSeason.addEventListener("change", () => {
      desktopSeason.value = mobSeason.value;
      desktopSeason.dispatchEvent(new Event("change", { bubbles: true }));
    });
    mobSeason._wired = true;
  }
  if (!mobRace._wired) {
    mobRace.addEventListener("change", () => {
      desktopRace.value = mobRace.value;
      desktopRace.dispatchEvent(new Event("change", { bubbles: true }));
    });
    mobRace._wired = true;
  }
}

function closeMobileNav() {
  const nav = document.getElementById("mobile-nav");
  const overlay = document.getElementById("mobile-nav-overlay");
  const btn = document.getElementById("mobile-menu-btn");
  if (!nav || !overlay || !btn) return;
  nav.hidden = true;
  overlay.hidden = true;
  btn.setAttribute("aria-expanded", "false");
  document.body.style.overflow = "";
}

function markMobileNavActive() {
  const activeView = STATE.view === "profile" ? STATE.prevView : STATE.view;
  document.querySelectorAll(".mobile-nav-link").forEach(a => {
    a.classList.toggle("active", a.dataset.view === activeView);
  });
}

function wireMobileNav() {
  document.getElementById("mobile-menu-btn")?.addEventListener("click", () => {
    const btn = document.getElementById("mobile-menu-btn");
    if (btn.getAttribute("aria-expanded") === "true") closeMobileNav();
    else openMobileNav();
  });
  document.getElementById("mobile-nav-close")?.addEventListener("click", closeMobileNav);
  document.getElementById("mobile-nav-overlay")?.addEventListener("click", closeMobileNav);

  // Mobile nav links: handle navigation explicitly rather than relying on
  // the browser's anchor tap → hashchange chain. iOS Safari occasionally
  // swallows the tap when the side-sheet is mid-animation, and re-tapping a
  // link that already matches the current hash never fires hashchange.
  // We intercept, close the sheet, then push the new URL (or force-render).
  document.querySelectorAll(".mobile-nav-link").forEach(a => {
    a.addEventListener("click", (e) => {
      e.preventDefault();
      const href = a.getAttribute("href") || "";
      closeMobileNav();
      // Defer the navigation a tick so the close animation kicks in first.
      // (Without this, on slow phones the page can switch before the user
      // sees the menu close, which feels janky.)
      setTimeout(() => {
        if (location.hash === href) {
          // Same page — hashchange won't fire. Re-render manually so any
          // stuck UI state resets.
          parseHash();
          render();
        } else {
          location.hash = href;
        }
      }, 50);
    });
  });

  // Close on Escape key
  document.addEventListener("keydown", (e) => {
    if (e.key === "Escape") closeMobileNav();
  });
}

// ============================================================
// MOBILE PICKER DRAWERS (Arc / Breakdown / Stage Analysis)
// ============================================================
// On mobile, the long row of car-picker pills swallows the chart. We hide it
// behind a "Pick cars ▾" button and let the user expand on demand. The button
// itself is hidden on desktop via CSS (the .mob-only-btn class).
function wirePickerDrawers() {
  document.querySelectorAll(".picker-drawer-toggle").forEach(btn => {
    btn.addEventListener("click", () => {
      const drawer = btn.closest(".picker-drawer");
      if (!drawer) return;
      drawer.classList.toggle("is-open");
      const chev = btn.querySelector(".pdt-chev");
      if (chev) chev.textContent = drawer.classList.contains("is-open") ? "▴" : "▾";
    });
  });

  // Touch dismissal: on mobile, tapping anywhere not on a chart hit point
  // dismisses any visible tooltip. Without this, the tooltip stays up forever
  // because touchend doesn't fire mouseleave reliably.
  document.addEventListener("touchstart", (e) => {
    if (!isMobile()) return;
    const onHit = e.target.closest(
      ".profile-chart-hit, .chart-tooltip, [data-tip], .tm-spk, " +
      "[id$=-tooltip], #metric-tooltip"
    );
    if (onHit) return;
    document.querySelectorAll("#metric-tooltip, .chart-tooltip").forEach(t => {
      t.hidden = true;
    });
  }, { passive: true });
}

// ============================================================
// MOBILE TABLE COLLAPSE (tap-to-expand)
// ============================================================
// Post-processes a data-table to:
//   1. Hide columns not listed in `keepIndices` (by column position, 0-based)
//   2. Append a chevron cell to each row in thead + tbody
//   3. Wire tap handlers that insert a detail row below the tapped row,
//      populated with labels + values cloned from the hidden cells.
//
// Only runs on mobile viewports. Safe to call on every render — it tears
// down any previous wiring via a marker class before re-applying.
//
// `table` — the <table> element
// `keepIndices` — array of column indices to keep visible (counting from 0, including the # column)
// `labelOverrides` — optional map of column index -> display label (falls back to th text)
function applyMobileTableCollapse(table, keepIndices, labelOverrides = {}) {
  if (!table || !isMobile()) return;

  const headRow = table.querySelector("thead tr");
  if (!headRow) return;
  const ths = Array.from(headRow.children);
  if (ths.length === 0) return;

  const keep = new Set(keepIndices);

  // Gather labels for hidden columns from their <th> text
  const hiddenCols = [];
  ths.forEach((th, i) => {
    if (keep.has(i)) return;
    const override = labelOverrides[i];
    const label = override || th.textContent.replace(/[▲▼↕]/g, "").trim();
    hiddenCols.push({ i, label });
    th.classList.add("mob-hide");
  });

  // Add chevron cell to thead (empty — it's the expand indicator column)
  if (!headRow.querySelector(".mob-chev-head")) {
    const chevTh = document.createElement("th");
    chevTh.className = "mob-chev-head mob-only";
    chevTh.textContent = "";
    headRow.appendChild(chevTh);
  }

  // Process each body row
  const tbody = table.querySelector("tbody");
  if (!tbody) return;
  const rows = Array.from(tbody.querySelectorAll("tr")).filter(r => !r.classList.contains("mob-expand-row"));
  rows.forEach(tr => {
    const tds = Array.from(tr.children);
    tds.forEach((td, i) => {
      if (!keep.has(i)) td.classList.add("mob-hide");
    });
    // Append chevron cell if not already there
    if (!tr.querySelector(".mob-chev")) {
      const chevTd = document.createElement("td");
      chevTd.className = "mob-chev mob-only";
      chevTd.innerHTML = "<span class=\"mob-chev-icon\">▸</span>";
      tr.appendChild(chevTd);
    }
    // Make the row tappable
    tr.classList.add("mob-collapsible");
    // Remove any previous handler to keep idempotent
    if (tr._mobToggle) tr.removeEventListener("click", tr._mobToggle);
    tr._mobToggle = (e) => {
      // Don't hijack clicks on actual links (profile links)
      if (e.target.closest("a")) return;
      toggleMobExpand(tbody, tr, hiddenCols);
    };
    tr.addEventListener("click", tr._mobToggle);
  });
}

function toggleMobExpand(tbody, tr, hiddenCols) {
  // If this row is already expanded, collapse it.
  // Multiple rows can be open at once — each one toggles independently.
  const existing = tr.nextElementSibling;
  if (existing && existing.classList.contains("mob-expand-row") && tr.classList.contains("mob-expanded")) {
    existing.remove();
    tr.classList.remove("mob-expanded");
    return;
  }

  // Collect values from the hidden cells
  const tds = Array.from(tr.children);
  const pairs = hiddenCols.map(({ i, label }) => {
    const cell = tds[i];
    const html = cell ? cell.innerHTML : "—";
    return `<div class="mob-kv">
      <span class="mob-kv-lbl">${escapeHTML(label)}</span>
      <span class="mob-kv-val">${html}</span>
    </div>`;
  }).join("");

  const colspan = tds.length + 1;  // +1 for chevron column
  const expandRow = document.createElement("tr");
  expandRow.className = "mob-expand-row";
  expandRow.innerHTML = `<td colspan="${colspan}">
    <div class="mob-expand-body">${pairs}</div>
  </td>`;
  tr.after(expandRow);
  tr.classList.add("mob-expanded");
}

// ============================================================
// MOBILE DROPDOWN MIRRORING
// ============================================================
// On mobile, pill-style toggle groups become <select> dropdowns to save space
// and feel native. Rather than rebuild every toolbar render path, we MIRROR
// the existing pill buttons: for each .toggle-group, inject a matching <select>
// that proxies "change" events to a click on the corresponding button. The
// button remains the source of truth; the pills are still present in the DOM,
// just visually hidden on mobile via CSS.
//
// Called at the end of render() so newly-visible toolbars get the treatment.
// Uses a WeakSet-like marker attribute so we don't re-bind repeatedly.
function syncMobileDropdowns() {
  document.querySelectorAll(".toggle-group").forEach(g => {
    const buttons = Array.from(g.querySelectorAll("button"));
    if (buttons.length === 0) return;

    // Find or create the mirror select
    let sel = g.querySelector(":scope > select.mobile-dd");
    const currentSig = buttons.map(b => `${b.dataset.val || ""}:${b.textContent.trim()}:${b.disabled ? "d" : ""}`).join("|");

    // If the button set has changed (different pills), rebuild the select
    if (sel && sel.dataset.sig !== currentSig) {
      sel.remove();
      sel = null;
    }

    if (!sel) {
      sel = document.createElement("select");
      sel.className = "mobile-dd";
      sel.dataset.sig = currentSig;
      // Option values are the button INDEX, not data-val. Several toggle
      // groups label their buttons with data-srs (series filters) or no
      // data attribute at all (the dynamically-built heatmap Finish/Points
      // toggle). Keying off data-val gave every such option value="", so the
      // change handler always resolved to the first button — the dropdown
      // updated visually but the data never changed (mobile-only). Index is
      // robust to any labeling scheme.
      buttons.forEach((b, idx) => {
        const opt = document.createElement("option");
        opt.value = String(idx);
        opt.textContent = b.textContent.trim();
        if (b.disabled) opt.disabled = true;
        sel.appendChild(opt);
      });
      sel.addEventListener("change", () => {
        const btn = buttons[Number(sel.value)];
        if (btn && !btn.disabled) btn.click();
      });
      g.appendChild(sel);
    }

    // Sync selected state from which button is "on"
    const onIdx = buttons.findIndex(b => b.classList.contains("on"));
    if (onIdx >= 0) sel.value = String(onIdx);
  });

  // Team-filter pill strips: same pattern, but the pills are .tf-pill spans
  // rebuilt on every render of renderTeamFilter. We append a single <select>
  // after the pill row and wire it to call the same handler.
  document.querySelectorAll(".team-filter").forEach(host => {
    const pills = Array.from(host.querySelectorAll(".tf-pill"));
    if (pills.length === 0) {
      // No pills (no data yet) — remove any stale select
      host.querySelector(":scope > select.mobile-dd")?.remove();
      return;
    }
    let sel = host.querySelector(":scope > select.mobile-dd");
    const currentSig = pills.map(p => p.dataset.team || "").join("|");

    if (sel && sel.dataset.sig !== currentSig) {
      sel.remove();
      sel = null;
    }

    if (!sel) {
      sel = document.createElement("select");
      sel.className = "mobile-dd";
      sel.dataset.sig = currentSig;
      pills.forEach(p => {
        const opt = document.createElement("option");
        opt.value = p.dataset.team || "";
        opt.textContent = p.textContent.trim();
        sel.appendChild(opt);
      });
      sel.addEventListener("change", () => {
        const pill = pills.find(p => (p.dataset.team || "") === sel.value);
        if (pill) pill.click();
      });
      host.appendChild(sel);
    }

    // Sync: "All" pill is active when no team filter is set
    const activePill = pills.find(p => p.classList.contains("active"));
    sel.value = activePill ? (activePill.dataset.team || "") : "";
  });
}

// syncMobileDropdowns() only runs when something explicitly calls it — the
// global render() pipeline, plus a few views (compare/heatmap) that re-render
// internally without going through render(). That coverage is fragile: any
// view that rebuilds a .toggle-group on its own (e.g. the standings
// view-switcher) or renders ASYNCHRONOUSLY after data loads (e.g. a profile
// whose bio arrives a beat late) ends up with pill buttons and no mobile
// <select> mirror, so the dropdown is missing/vanishes on mobile.
//
// Rather than hunt down every such path, observe the DOM: whenever a
// .toggle-group or .team-filter is added anywhere, re-mirror. The mirror is
// idempotent (data-sig), and the <select>s we inject are filtered out below
// so we never feed our own mutations back into a loop. rAF-debounced so a
// big render fires the sync at most once per frame.
let _ddSyncScheduled = false;
function scheduleMobileDropdownSync() {
  if (_ddSyncScheduled) return;
  _ddSyncScheduled = true;
  requestAnimationFrame(() => {
    _ddSyncScheduled = false;
    syncMobileDropdowns();
    enhanceCollapsibleTables();
  });
}
function observeMobileDropdowns() {
  if (window._ddObserver) return;            // wire once
  const root = document.body;
  if (!root || typeof MutationObserver === "undefined") return;
  const SEL = ".toggle-group, .team-filter, table.m-collapse";
  const obs = new MutationObserver(mutations => {
    for (const m of mutations) {
      for (const node of m.addedNodes) {
        if (node.nodeType !== 1) continue;   // elements only
        // Ignore the <select> mirrors and detail rows we inject ourselves —
        // avoids feeding our own DOM writes back through the observer.
        if (node.matches && node.matches("select.mobile-dd, tr.mc-detail-row")) continue;
        const isMatch = node.matches && node.matches(SEL);
        const hasMatch = node.querySelector && node.querySelector(SEL);
        if (isMatch || hasMatch) {
          scheduleMobileDropdownSync();
          return;
        }
      }
    }
  });
  obs.observe(root, { childList: true, subtree: true });
  window._ddObserver = obs;
}

// Collapse wide stat tables on mobile. For each table tagged `.m-collapse`,
// keep only the essentials visible — rank/identifier + the projected-points
// column — and tuck every other column into a tap-to-expand detail panel.
// Only opt-in tables whose rows are NOT independently clickable (projection
// tables qualify; race-by-race etc. navigate on row click and need a
// different affordance). Idempotent via data-mc-done; mobile-only.
function enhanceCollapsibleTables() {
  if (typeof isMobile === "function" && !isMobile()) return;
  document.querySelectorAll("table.m-collapse:not([data-mc-done])").forEach(table => {
    const headCells = Array.from(table.querySelectorAll("thead th"));
    if (headCells.length < 3) { table.dataset.mcDone = "1"; return; }
    const labels = headCells.map(th => th.textContent.trim());

    // Which columns stay visible:
    //  - column 0 (rank)
    //  - first non-numeric column (the name/identifier)
    //  - the headline points column: prefer projected/chase points, else
    //    fall back to any pts/points/total column.
    const keep = new Set([0]);
    const nameIdx = headCells.findIndex(th => !th.classList.contains("num"));
    if (nameIdx >= 0) keep.add(nameIdx);
    let metricIdx = labels.findIndex(l => /proj.*pts|chase\s*pts|avg\s*proj\s*pts/i.test(l));
    if (metricIdx < 0) metricIdx = labels.findIndex(l => /\bpts\b|points|total/i.test(l));
    if (metricIdx >= 0) keep.add(metricIdx);

    headCells.forEach((th, i) => { if (!keep.has(i)) th.classList.add("mc-hide"); });

    const bodyRows = Array.from(table.querySelectorAll("tbody > tr"));
    bodyRows.forEach(tr => {
      if (tr.classList.contains("mc-detail-row")) return;
      const cells = Array.from(tr.children);
      if (cells.length !== headCells.length) return;   // skip irregular rows
      const hidden = [];
      cells.forEach((td, i) => {
        if (!keep.has(i)) {
          td.classList.add("mc-hide");
          hidden.push({ k: labels[i] || "", v: td.textContent.trim() });
        }
      });
      if (hidden.length === 0) return;
      tr.classList.add("mc-row");
      const dr = document.createElement("tr");
      dr.className = "mc-detail-row";
      dr.hidden = true;
      const cell = document.createElement("td");
      cell.colSpan = keep.size;
      cell.innerHTML = `<div class="mc-detail">${
        hidden.map(h => `<span class="mc-k">${escapeHTML(h.k)}</span><span class="mc-v">${escapeHTML(h.v)}</span>`).join("")
      }</div>`;
      dr.appendChild(cell);
      tr.after(dr);
    });
    table.dataset.mcDone = "1";
  });
}

// One delegated handler toggles a collapsible row's detail panel. Ignores
// clicks on links/buttons inside the row so interactive cells still work.
function wireCollapsibleRows() {
  if (window._mcClickBound) return;
  document.addEventListener("click", e => {
    const row = e.target.closest("tr.mc-row");
    if (!row) return;
    if (e.target.closest("a, button, select, input")) return;
    const detail = row.nextElementSibling;
    if (detail && detail.classList.contains("mc-detail-row")) {
      const show = detail.hidden;
      detail.hidden = !show;
      row.classList.toggle("mc-open", show);
    }
  });
  window._mcClickBound = true;
}

function parseHash() {
  const h = location.hash.replace("#/", "").split("/");
  // Split a possible "?query" off the leading segment. This is how
  // per-view options like #/standings?view=mfr or #/profile/<slug>?tab=x
  // get passed without colliding with the slash-separated route shape.
  let view = h[0];
  let firstSegmentQuery = "";
  if (typeof view === "string" && view.includes("?")) {
    const i = view.indexOf("?");
    firstSegmentQuery = view.slice(i + 1);
    view = view.slice(0, i);
    h[0] = view;
  }
  // Standings view selector. #/standings?view=driver|owner|manufacturer
  // lets us route directly to a specific standings tab from the nav or
  // from a shared URL. Also accepts ?series=NCS|NOS|NTS so the home-page
  // mini-standings "Full →" link lands on the correct series even if
  // the user is currently viewing a different one. Falls through to the
  // default-view STATE on bare #/standings.
  if (view === "standings" && firstSegmentQuery) {
    const params = new URLSearchParams(firstSegmentQuery);
    const v = params.get("view");
    if (v && ["driver", "owner", "manufacturer"].includes(v)) {
      STATE.standings.view = v;
    }
    const sr = params.get("series");
    if (sr && ["NCS", "NOS", "NTS"].includes(sr) && sr !== STATE.series) {
      // Trigger a full series switch (state reset + data load + render).
      // applySeriesChangeGlobal calls render() on its own when data settles,
      // so we flag the in-flight swap and let the hashchange listener
      // skip its own render to avoid painting stale data mid-swap.
      STATE.view = "standings";
      STATE.pendingSeriesSwap = applySeriesChangeGlobal(sr);
      STATE.lastHash = location.hash;
      return;
    }
  }
  // Compare view: #/compare?with=slug pre-populates the compare slate
  // with one driver (typically from a "Compare" link on a driver profile).
  // The compare page also supports ?with=slug1,slug2 for shared URLs.
  if (view === "compare" && firstSegmentQuery) {
    const params = new URLSearchParams(firstSegmentQuery);
    const withParam = params.get("with");
    if (withParam) {
      // Comma-separated list of slugs. Reset the compare set on each
      // hash navigation so users get a clean state.
      STATE.compare = STATE.compare || { slugs: [] };
      STATE.compare.slugs = withParam.split(",").map(s => s.trim()).filter(Boolean);
    }
  }

  // Present mode invariant — STATE.season must always reflect the latest
  // available year EXCEPT during the brief window where renderProfile
  // needs a historical context (resolveDriverRoute runs AFTER parseHash
  // and flips season as needed for the profile entity to render). Doing
  // the snap-back here at the top means ANY navigation in Present mode —
  // including takeover→takeover transitions like profile→schedule — gets
  // STATE rebased before the route's handler runs.
  if (STATE.mode === "present") {
    const latest = (STATE.seasonsAvailable && STATE.seasonsAvailable[0]);
    if (latest && STATE.season !== latest) {
      STATE.season = latest;
      STATE.throughRound = null;
    }
  }
  // Helper: stash the full PREVIOUS hash before we change view, so back
  // buttons can restore parameterized routes (#/team/HMS, #/track/KAN, etc.)
  // verbatim instead of dropping the parameter.
  const stashPrev = (newView) => {
    if (STATE.view && STATE.view !== newView) {
      STATE.prevView = STATE.view;
      // Take whatever the previous hash was before this navigation. We're
      // mid-parseHash so the URL has already changed; the most reliable
      // source is the prior STATE.lastHash we set at the bottom of this
      // function on each successful resolve.
      STATE.prevHash = STATE.lastHash || `#/${STATE.view}`;
    }
  };

  // Driver-centric route: #/driver/<slug>
  // Resolves driver's home (series, season) automatically and locks the
  // profile to it. The year/series selectors are presented INSIDE the
  // profile body — not via the URL — so a driver has one canonical URL.
  if (view === "driver") {
    if (STATE.view !== "profile") {
      stashPrev("profile");
      STATE.profile.preLockSeries = STATE.series;
      STATE.profile.preLockSeason = STATE.season;
    }
    STATE.view = "profile";
    STATE.profile = {
      kind: "driver",
      slug: h[1] || null,
      preLockSeries: STATE.profile.preLockSeries,
      preLockSeason: STATE.profile.preLockSeason,
      splitsRange: STATE.profile.splitsRange || "season",
      splitsSeries: STATE.profile.splitsSeries || "all",
      heatmapSeries: STATE.profile.heatmapSeries || "all",
      // Reset track picker to defaults on each driver navigation so a
      // selection made on Driver A doesn't bleed into Driver B (where the
      // picked track might not exist in their cache).
      trackPicker: { code: null, series: "all", gens: new Set() },
      locked: true,
    };
    STATE.lastHash = location.hash;
    return;
  }
  // Team route: #/team/<code> — landing page for an organization
  if (view === "team") {
    stashPrev("team");
    STATE.view = "team";
    STATE.team = { code: (h[1] || "").toUpperCase() };
    STATE.lastHash = location.hash;
    return;
  }
  // Crew chief route: #/cc/<slug> — landing page for a crew chief
  if (view === "cc") {
    stashPrev("cc");
    STATE.view = "cc";
    STATE.cc = {
      slug: h[1] || null,
      heatmapSeries: (STATE.cc && STATE.cc.heatmapSeries) || "all",
    };
    STATE.lastHash = location.hash;
    return;
  }
  // Profile routes: #/profile/<slug> or #/car/<number> (legacy)
  // Both legacy routes are TREATED AS LOCKED — the entire app is now driver-
  // centric, and even when entered via car-number, we want the picker to be
  // hidden so the user can't accidentally swap drivers by changing the year.
  if (view === "profile" || view === "car") {
    if (STATE.view !== "profile") {
      stashPrev("profile");
      STATE.profile.preLockSeries = STATE.series;
      STATE.profile.preLockSeason = STATE.season;
    }
    STATE.view = "profile";
    STATE.profile = {
      kind: view,
      slug: h[1] || null,
      preLockSeries: STATE.profile.preLockSeries,
      preLockSeason: STATE.profile.preLockSeason,
      splitsRange: STATE.profile.splitsRange || "season",
      splitsSeries: STATE.profile.splitsSeries || "all",
      heatmapSeries: STATE.profile.heatmapSeries || "all",
      trackPicker: { code: null, series: "all", gens: new Set() },
      locked: true,
    };
    STATE.lastHash = location.hash;
    return;
  }
  // Track route: #/track/KAN — single track landing page
  if (view === "track") {
    stashPrev("track");
    STATE.view = "track";
    // seriesView always resets to STATE.series when entering a new track
    // page. Previously we persisted it across track visits, which led to
    // a track opening in (e.g.) NTS when the user was actually browsing
    // NCS. The per-page toggle (in the track view itself) still lets the
    // user override locally during their visit.
    STATE.track = {
      code: (h[1] || "").toUpperCase(),
      seriesView: STATE.series,
      scopeView: "current",   // "current" = current FT drivers only; "all" = every driver historical
    };
    STATE.lastHash = location.hash;
    return;
  }
  // Race / schedule routes — remember where we came from for back nav.
  // Race route can include a round number: #/race/<round>. It can ALSO
  // include `?_y=YYYY&_s=NCS|NOS|NTS` query params — that format is what
  // heatmap cells / search results emit when linking to a historical race.
  // In Present mode the query params trigger a lightbox via the post-parse
  // handler in the hashchange listener (so STATE doesn't drift). In
  // Historical mode they silently switch STATE.season + STATE.series so
  // the page renders against that year.
  if (view === "race" || view === "schedule") {
    stashPrev(view);
    STATE.view = view;
    if (view === "race") {
      // Pull the round from h[1], stripping any query string suffix.
      const rawSeg = h[1] != null ? String(h[1]) : "";
      const roundPart = rawSeg.split("?")[0];
      const roundN = parseInt(roundPart, 10);
      STATE.race = { round: Number.isFinite(roundN) ? roundN : null };
      // Detect deep-link year/series params (#/race/N?_y=YYYY&_s=NCS).
      // We stash these on STATE.race so the post-parse logic in the
      // hashchange listener can decide whether to open a lightbox or
      // switch context based on STATE.mode.
      const queryStr = rawSeg.includes("?") ? rawSeg.split("?")[1] : "";
      if (queryStr) {
        const params = new URLSearchParams(queryStr);
        const y = parseInt(params.get("_y"), 10);
        const s = params.get("_s");
        if (Number.isFinite(y) && ["NCS", "NOS", "NTS"].includes(s)) {
          STATE.race.deepLinkYear = y;
          STATE.race.deepLinkSeries = s;
        }
      }
    }
    STATE.lastHash = location.hash;
    return;
  }
  // All-time database pages: #/drivers, #/teams, #/crewchiefs.
  // No parameters — these always render against the full SEASON_CACHE.
  if (view === "drivers" || view === "teams" || view === "crewchiefs" || view === "personnel") {
    stashPrev(view);
    STATE.view = view;
    STATE.lastHash = location.hash;
    return;
  }
  // Leaving a takeover (profile/team/cc/track/race) → restore the previous
  // (series, season) we stashed before entering. In Present mode we go a
  // step further: hard-snap to the latest available season regardless of
  // what was stashed, since the user opted into "always live" — even the
  // original entry point may have been historical.
  const wasProfile = STATE.view === "profile" && STATE.profile && STATE.profile.locked;
  const wasOtherTakeover = ["team", "cc", "track", "race", "schedule", "playoffs", "drivers", "teams", "crewchiefs", "personnel", "pointscalc", "projection"].includes(STATE.view);
  const leavingTakeover = wasProfile || wasOtherTakeover;
  const enteringNonTakeover = !["profile", "team", "cc", "track", "race", "schedule", "playoffs", "drivers", "teams", "crewchiefs", "personnel", "pointscalc", "projection"].includes(view);
  if (leavingTakeover && enteringNonTakeover) {
    if (STATE.mode === "present") {
      const latest = (STATE.seasonsAvailable && STATE.seasonsAvailable[0]);
      if (latest) STATE.season = latest;
      // Restore the user's pre-takeover series. Profile pages flip
      // STATE.series to match the driver's home series (a Truck driver
      // pulls us into NTS); when the user clicks a top-level nav item
      // we should return to whatever series they were viewing before
      // diving into the profile. Falls back to STATE.lastPresentSeries
      // (the topbar's canonical Present series) if no profile lock
      // exists, then to NCS as a final default.
      const prevSeries = (wasProfile && STATE.profile && STATE.profile.preLockSeries)
        || STATE.lastPresentSeries
        || "NCS";
      if (prevSeries !== STATE.series) {
        STATE.series = prevSeries;
        // The actual data swap + render cache reset happen downstream
        // when the route's handler runs (parseHash itself doesn't load).
        // Flag the upstream listener so it triggers a reload — same
        // mechanism used by the ?series= URL parameter.
        STATE.pendingSeriesRestore = true;
      }
    } else if (wasProfile) {
      if (STATE.profile.preLockSeries) STATE.series = STATE.profile.preLockSeries;
      if (STATE.profile.preLockSeason) STATE.season = STATE.profile.preLockSeason;
    }
    if (wasProfile) STATE.profile.locked = false;
  }
  STATE.view = VIEWS.includes(view) ? view : "home";
  STATE.lastHash = location.hash;
}

// Slug helper: "A.J. Allmendinger" → "a-j-allmendinger"
function slugify(name) {
  if (!name) return "";
  return String(name)
    .toLowerCase()
    .replace(/[.']/g, "")            // drop periods/apostrophes
    .replace(/[^a-z0-9]+/g, "-")     // non-alphanumeric → dash
    .replace(/^-+|-+$/g, "")         // trim leading/trailing dashes
    || "driver";
}

// Find the (series, season, car_number) where this driver was most recently
// full-time. Used for driver-centric profile routing — when a user clicks a
// driver from any series/year, we land them on that driver's HOME profile
// rather than wherever they currently sit in the cached data.
//
// Resolution order:
//   1. Most recent year (any series) where driver was full-time
//   2. Most recent year (any series) where driver appeared at all
//   3. Fall back to current STATE if nothing found
//
// Returns { series, season, car_number, driver, found: boolean, fallback: boolean }
function findDriverHomeContext(driverSlug, fallbackSeries, fallbackSeason) {
  const fallback = {
    series: fallbackSeries || STATE.series,
    season: fallbackSeason || STATE.season,
    car_number: null,
    driver: null,
    found: false,
    fallback: true,
  };
  if (!driverSlug) return fallback;

  // Scan SEASON_CACHE newest → oldest to find the driver's home season.
  const years = Object.keys(SEASON_CACHE).map(Number)
    .sort((a, b) => b - a);  // newest first
  if (!years.length) {
    // Cache empty — try current data
    if (STATE.data && STATE.data.series) {
      for (const [sCode, block] of Object.entries(STATE.data.series)) {
        const hit = scanSeriesBlockForDriver(block, driverSlug);
        if (hit) {
          return {
            series: sCode,
            season: STATE.data.season,
            car_number: hit.car_number,
            driver: hit.driver,
            found: true,
            fallback: false,
          };
        }
      }
    }
    return fallback;
  }

  // Selection rule: the driver's "home" is the MOST RECENT year they have
  // any starts, and within that year the series they STARTED MOST (ties broken
  // by series prestige NCS > NOS > NTS). Most-started (not highest-prestige)
  // is deliberate: it keeps a full-time Xfinity regular who runs a handful of
  // Cup races framed as an Xfinity driver, and frames a part-time Truck driver
  // (e.g. a former champion running a partial schedule) by their actual Truck
  // program rather than a one-off cameo in a higher series.
  const seriesPriority = ["NCS", "NOS", "NTS"];  // tiebreak only

  for (const year of years) {
    const seriesBlocks = SEASON_CACHE[year];
    if (!seriesBlocks) continue;

    // Collect every series this driver started in, this year.
    let best = null;  // { series, car_number, driver, starts }
    for (const sCode of seriesPriority) {
      const block = seriesBlocks[sCode];
      if (!block) continue;
      const hit = scanSeriesBlockForDriver(block, driverSlug);
      if (!hit || !hit.starts) continue;
      const candidate = {
        series: sCode,
        car_number: hit.car_number,
        driver: hit.driver,
        starts: hit.starts,
      };
      // Most starts wins; on a tie the earlier (higher-prestige) series in
      // seriesPriority is kept because we only replace on strictly-greater.
      if (!best || candidate.starts > best.starts) best = candidate;
    }

    if (best) {
      return { series: best.series, season: year, car_number: best.car_number,
               driver: best.driver, found: true, fallback: false };
    }
  }
  return fallback;
}

// Scan one (year, series) block for a driver matching the given slug.
// Returns the car they drove most often + their starts count, or null.
function scanSeriesBlockForDriver(block, driverSlug) {
  if (!block || !block.races) return null;
  // Match driver rows by slug OR normalized-name fallback. The strict
  // slug check works for ~99% of drivers, but breaks when bio.full_name
  // canonicalizes differently than the race-row driver string ("Brandon
  // Jones" vs "Brandon Jones Jr.", etc). Normalized name is more
  // forgiving — strips suffixes/punctuation/middle initials — and
  // catches the rest.
  const bio = STATE.driverBios && STATE.driverBios[driverSlug];
  const bioName = bio && (bio.full_name || bio.name);
  const targetNorms = [
    bioName ? normalizeDriverName(bioName) : null,
    normalizeDriverName(driverSlug.replace(/-/g, " ")),
  ].filter(Boolean);
  const matchesDriver = (rowDriver) => {
    if (!rowDriver) return false;
    if (slugify(rowDriver) === driverSlug) return true;
    const n = normalizeDriverName(rowDriver);
    return n && targetNorms.includes(n);
  };

  const carStarts = {};   // car_number → { starts, driverName }
  block.races.forEach(race => {
    (race.results || []).forEach(d => {
      // Include ineligible (cross-over) appearances — they're real starts.
      // Without this, a Cup regular's 1-off Xfinity stint never shows in
      // their career history, breaking the chip strip and heatmap.
      if (!d.driver) return;
      if (!matchesDriver(d.driver)) return;
      const car = d.car_number;
      if (!carStarts[car]) carStarts[car] = { starts: 0, driverName: d.driver };
      carStarts[car].starts++;
    });
  });
  // Most-driven car wins
  let best = null;
  for (const [car, info] of Object.entries(carStarts)) {
    if (!best || info.starts > best.starts) {
      best = { car_number: car, starts: info.starts, driver: info.driverName };
    }
  }
  return best;
}

// ============================================================
// DATA LOADING
// ============================================================
async function loadColors() {
  try {
    const r = await fetch("data/colors.json");
    STATE.colors = await r.json();
  } catch (e) {
    console.warn("Colors file unavailable, using fallbacks", e);
    STATE.colors = { W: {}, B: {}, C: {} };
  }
}

// Load optional driver biographies (DOB, hometown, career totals by series).
// Silently no-ops if data/drivers.json doesn't exist — profile view renders
// bio-less in that case.
async function loadDriverBios() {
  try {
    const r = await fetch("data/drivers.json");
    if (!r.ok) { STATE.driverBios = null; return; }
    const payload = await r.json();
    STATE.driverBios = payload.drivers || {};
  } catch (e) {
    // Missing file is the common case early on — not an error
    STATE.driverBios = null;
  }
}

async function discoverSeasons() {
  // Probe for `data/points_YYYY.json` for each plausible year. Lower bound is
  // 1949 (NASCAR's first Strictly Stock / Cup season). Upper bound is derived
  // from the calendar so we don't generate spurious 404s for future years
  // that don't exist yet (the browser logs 404s at the network layer
  // regardless of catch()). +1 gives us a one-year lookahead in case a stub
  // file for next season is published early.
  const currentYear = new Date().getFullYear();
  const upper = currentYear + 1;
  const years = [];
  for (let y = 1949; y <= upper; y++) {
    const r = await fetch(`data/points_${y}.json`, { method: "HEAD" })
      .catch(() => null);
    if (r && r.ok) years.push(y);
  }
  if (years.length === 0) {
    const r = await fetch("data/points.json", { method: "HEAD" }).catch(() => null);
    if (r && r.ok) years.push(currentYear);
  }
  STATE.seasonsAvailable = years.sort((a, b) => b - a);
}

async function loadCurrentData() {
  const year = STATE.season;
  const urls = [
    `data/points_${year}.json`,
    `data/points.json`,
  ];
  let payload = null;
  let lastErr = null;
  for (const u of urls) {
    try {
      const r = await fetch(u);
      if (!r.ok) throw new Error(`${r.status} ${r.statusText}`);
      payload = await r.json();
      break;
    } catch (e) {
      lastErr = e;
    }
  }
  if (!payload) {
    return showError(`Failed to load data: ${lastErr && lastErr.message || "unknown"}`);
  }
  const sCode = STATE.series;
  const seriesBlock = payload.series && payload.series[sCode];
  if (!seriesBlock) {
    return showError(`No data for series ${sCode} in season ${year}`);
  }
  if (payload.series) {
    _normalizeTrackCodes(payload.series, year);
    SEASON_CACHE[year] = payload.series;
  }
  STATE.data = seriesBlock;
  renderSeasonPill();
  document.getElementById("footer-updated").textContent =
    `Updated ${(payload.generated_at || "").slice(0,10)}`;
  hideError();
}

// Topbar season pill — shows year, series, and "R{run} / {total}" progress.
// In Present mode, the pill is locked to display the latest available
// season's progress regardless of where STATE temporarily wandered (e.g.
// while resolving a historical driver's profile, STATE.season might
// briefly be 2020). The user explicitly opted into "always live" so the
// indicator must stay anchored to today's season.
function renderSeasonPill() {
  const el = document.getElementById("season-pill");
  if (!el) return;
  let displayYear, displaySeries, runCount, totalRaces;
  if (STATE.mode === "present") {
    // Anchor to latest available season + whatever series is in topbar
    displayYear = (STATE.seasonsAvailable && STATE.seasonsAvailable[0]) || STATE.season;
    displaySeries = STATE.series;
    // Pull progress from cache if available; fall back to STATE.data
    const block = SEASON_CACHE[displayYear] && SEASON_CACHE[displayYear][displaySeries];
    const races = block ? (block.races || []) : (STATE.data && STATE.data.races || []);
    runCount = races.filter(r => (r.results || []).length > 0).length;
    totalRaces = scheduleLengthForSeries(displaySeries);
  } else {
    // Historical mode — pill reflects whatever STATE actually is
    displayYear = STATE.season;
    displaySeries = STATE.series;
    const races = (STATE.data && STATE.data.races) || [];
    runCount = races.filter(r => (r.results || []).length > 0).length;
    totalRaces = scheduleLengthForSeries(displaySeries);
  }
  el.textContent = `${displayYear} · ${displaySeries} · R${runCount} / ${totalRaces}`;
}

function scheduleLengthForSeries(series) {
  return { NCS: 36, NOS: 33, NTS: 25 }[series] || "—";
}

// ============================================================
// MULTI-SEASON CACHE (used by Stage Analysis for cross-year views)
// Keyed by year → { [seriesCode]: seriesBlock }
// ============================================================
const SEASON_CACHE = {};

// Track code normalization — fixes cases where Racing Reference reuses
// the same track code for physically different tracks across eras.
// Called once at data-load time so all downstream consumers (predictions,
// profiles, analytics, track type lookups) see the corrected codes.
function _normalizeTrackCodes(seriesBlock, year) {
  if (!seriesBlock) return;
  // CHI split: "CHI" = Chicagoland (1.5mi intermediate, ≤2020 and 2026+)
  //            "CHG" = Chicago Street Race (road course, 2023-2025)
  if (year >= 2023 && year <= 2025) {
    Object.values(seriesBlock).forEach(block => {
      if (!block || !block.races) return;
      block.races.forEach(race => {
        if (race.track_code === "CHI") {
          race.track_code = "CHG";
          if (!race.track || race.track === "Chicagoland") {
            race.track = "Chicago Street";
          }
        }
      });
    });
  }

  // Nashville split: "NSH" = Nashville Fairgrounds/Speedway (short track, 0.596mi)
  //                  "NSV" = Nashville Superspeedway (1.33mi intermediate, Lebanon TN)
  // Racing Reference uses distinct names on race pages: "Nashville Speedway"
  // vs "Nashville Superspeedway". Schedule pages may say just "Nashville".
  // Remap NSH → NSV when the name indicates the Superspeedway OR when
  // the name is bare "Nashville" (Fairgrounds would say "Nashville Speedway"
  // or "Nashville Fairgrounds" on its race page).
  Object.values(seriesBlock).forEach(block => {
    if (!block || !block.races) return;
    block.races.forEach(race => {
      if (race.track_code === "NSH") {
        const tname = (race.track || "").toLowerCase().trim();
        const rname = (race.name || "").toLowerCase();
        if (tname.includes("superspeedway") || rname.includes("superspeedway")
            || tname.includes("lebanon")
            || tname === "nashville") {
          // Bare "Nashville" or explicit Superspeedway → NSV
          race.track_code = "NSV";
          race.track = "Nashville Superspeedway";
        }
      }
    });
  });

  // Team code fixes: correct codes that collide across eras/teams.

  // Daytona & Indianapolis road course splits
  Object.values(seriesBlock).forEach(block => {
    if (!block || !block.races) return;
    block.races.forEach(race => {
      const tname = ((race.track || "") + " " + (race.name || "")).toLowerCase();
      if (race.track_code === "DAY" && tname.includes("road course")) {
        race.track_code = "DRC";
        race.track = "Daytona Road Course";
      }
      if (race.track_code === "IND" && tname.includes("road course")) {
        race.track_code = "IRC";
        race.track = "Indianapolis Road Course";
      }
    });
  });

  // ── COMPREHENSIVE TRACK CODE NORMALIZATION ──
  // Phase 1: MERGES — same physical track, different codes across eras.
  const TRACK_MERGES = {
    ALA: "TAL",   // Alabama International Motor Speedway = Talladega
    SEA: "SON",   // Sears Point = Sonoma
    INF: "SON",   // Infineon Raceway = Sonoma
    LOW: "CLT",   // Lowe's Motor Speedway = Charlotte Motor Speedway
    ISM: "PHO",   // ISM Raceway = Phoenix Raceway
  };

  // Phase 2: SPLITS — different physical tracks sharing one code.
  // Each rule: [oldCode, nameSubstring, newCode]
  // More-specific substrings MUST come first (matched top-down, first hit wins).
  const TRACK_SPLITS = [
    // Bristol vs Bridgehampton (2.85mi road course, Long Island)
    ["BRI", "bridgehampton", "BRH"],
    // Atlanta: Rural Fairgrounds (0.5mi) and Road Atlanta (road course)
    ["ATL", "rural fairgrounds", "ARF"],
    ["ATL", "road atlanta", "RAT"],
    // Charlotte Fairgrounds (pre-CMS, 0.5-0.75mi)
    ["CLT", "fairgrounds", "CLF"],
    // Daytona Beach (4.1mi beach/road course, 1949-1958)
    ["DAY", "daytona beach", "DYB"],
    ["DAY", "beach", "DYB"],
    // Michigan State Fairgrounds (1.0mi, Detroit)
    ["MCH", "state fairgrounds", "MSF"],
    ["MCH", "fairgrounds", "MSF"],
    // Fonda Speedway (NY, 0.5mi) vs Fontana/Auto Club
    ["FON", "fonda", "FND"],
    // Texas World Speedway (2.0mi) vs Texas Motor Speedway
    ["TEX", "texas world", "TWS"],
    // Louisville Motor Speedway vs New Hampshire
    ["LOU", "louisville", "LVL"],
    // Roanoke vs Road America
    ["ROA", "roanoke", "RNK"],
    // Middle Georgia Raceway vs Mid-Ohio
    ["MID", "middle georgia", "MGR"],
    // Rochester (NY) vs Rockingham
    ["ROC", "rochester", "RCT"],
    // Memphis-Arkansas Speedway vs Kansas Speedway
    ["KAN", "memphis-arkansas", "MAS"],
    ["KAN", "memphis", "MAS"],
    // Portland Speedway (0.5mi oval) vs Portland International Raceway
    ["POR", "portland speedway", "PRS"],
    // Langhorne, Lancaster, Langley, Lanier — all different tracks
    ["LAN", "langhorne", "LGH"],
    ["LAN", "lancaster", "LCS"],
    ["LAN", "langley", "LGL"],
    ["LAN", "lanier", "LNR"],
    // Norfolk, Norwood, North Platte, NC State Fairgrounds, NC Motor Speedway
    ["NOR", "north carolina motor", "ROC"],  // = Rockingham
    ["NOR", "north carolina state fair", "NCSF"],
    ["NOR", "norfolk", "NFK"],
    ["NOR", "norwood", "NWD"],
    ["NOR", "north platte", "NPL"],
    // Columbia vs Columbus vs Colorado National
    ["COL", "columbus", "CBS"],
    ["COL", "colorado", "CNS"],
    // Monroe vs Montgomery
    ["MON", "monroe", "MNR"],
    // Marchbanks and Maryville are NOT Martinsville
    ["MAR", "marchbanks", "MRB"],
    ["MAR", "maryville", "MRV"],
    // Wall vs Walt Disney World
    ["WAL", "disney", "WDW"],
    // Wilson vs Willow Springs
    ["WIL", "willow", "WLS"],
    // Winchester vs Winston-Salem
    ["WIN", "winchester", "WCH"],
    // Carrell Speedway vs Caraway
    ["CAR", "carrell", "CRL"],
    // Greensboro vs Greenville-Pickens
    ["GRE", "greensboro", "GBO"],
    // South Bend vs South Boston
    ["SOU", "south bend", "SBD"],
    // Pensacola vs Pennsylvania International
    ["PEN", "pensacola", "PNS"],
    // Old Dominion vs Old Bridge
    ["OLD", "old dominion", "ODM"],
    // Hartsville vs Harris
    ["HAR", "hartsville", "HTV"],
    // Asheville-Weaverville vs Asheville Speedway
    ["ASH", "weaverville", "AWV"],
    // Augusta International Raceway (road, 3.0mi) vs Augusta Speedway
    ["AUG", "international", "AGI"],
    // Orange County Speedway vs Orange Speedway
    ["ORA", "orange county", "OCS"],
    // San Jose vs San Mateo
    ["SAN", "san jose", "SJO"],
    // Virginia Beach vs Virginia State Fairgrounds
    ["VIR", "virginia beach", "VBH"],
    ["VIR", "viriginia beach", "VBH"],  // typo in RR data
    // Indianapolis: IRP and Grand Prix Circuit
    ["IND", "raceway park", "IRP"],
    ["IND", "grand prix", "IRC"],
    // Chicago Motor Speedway (2.14mi, 2000-2001) vs Chicagoland
    ["CHI", "chicago motor speedway", "CMS"],
    // Manassas (VA, 1958-1965) vs Mansfield Motorsports (OH, 2004-2008)
    ["MAN", "mansfield", "MNF"],
    // Portland bare (1956-1957, 0.5mi oval) — should be PRS not PTL
    ["PTL", "portland speedway", "PRS"],
    // NEW: 6 different tracks all starting with "New"
    ["NEW", "new asheville", "NAS"],
    ["NEW", "new concord", "NCN"],
    ["NEW", "new river valley", "NRV"],
    ["NEW", "new oxford", "NOX"],
    ["NEW", "newberry", "NBY"],
    ["NEW", "newport", "NPT"],
    // Virginia Beach vs Virginia State Fairgrounds
    ["VIR", "virginia state fair", "VSF"],
    // Linden Airport (1954) is NOT Indianapolis Raceway Park
    ["IRP", "linden", "LND"],
  ];

  Object.values(seriesBlock).forEach(block => {
    if (!block || !block.races) return;
    block.races.forEach(race => {
      const code = race.track_code;
      if (!code) return;

      // Apply merges first
      if (TRACK_MERGES[code]) {
        race.track_code = TRACK_MERGES[code];
        return; // merged, skip splits
      }

      // Apply splits — check track name against rules
      const tname = ((race.track || "") + " " + (race.name || "")).toLowerCase();
      // Special case: "Dayton" (Ohio, 1950-1952) vs "Daytona" — can't use
      // substring matching because "dayton" is inside "daytona".
      if (code === "DAY" && (race.track || "").toLowerCase().trim() === "dayton") {
        race.track_code = "DYT";
        return;
      }
      // Special case: bare "Portland" (1956-57, 0.5mi oval) vs Portland
      // International Raceway (1.97mi road). If no "international" in the
      // name, it's the old oval.
      if (code === "PTL" && !(race.track || "").toLowerCase().includes("international")
          && !(race.track || "").toLowerCase().includes("raceway")) {
        race.track_code = "PRS";
        return;
      }
      for (const [oldCode, substr, newCode] of TRACK_SPLITS) {
        if (code === oldCode && tname.includes(substr)) {
          race.track_code = newCode;
          return; // first match wins
        }
      }
    });
  });

  // Team code fixes: correct codes that collide across eras/teams.
  // Applied at load time so all downstream consumers see the corrected codes.
  const TEAM_CODE_FIXES = {
    // "Sam Hunt" owner → was "SHR" (collision with Stewart-Haas Racing)
    "Sam Hunt": "HUNT",
  };
  Object.values(seriesBlock).forEach(block => {
    if (!block || !block.races) return;
    block.races.forEach(race => {
      (race.results || []).forEach(d => {
        if (!d.team) return;
        for (const [ownerSubstr, newCode] of Object.entries(TEAM_CODE_FIXES)) {
          if (d.team.includes(ownerSubstr) && d.team_code !== newCode) {
            d.team_code = newCode;
          }
        }
      });
    });
  });
}

async function loadSeasonIntoCache(year) {
  // Returns the full payload (all series) for a year. Cached after first hit.
  if (SEASON_CACHE[year]) return SEASON_CACHE[year];
  const urls = [`data/points_${year}.json`, `data/points.json`];
  for (const u of urls) {
    try {
      const r = await fetch(u);
      if (!r.ok) continue;
      const payload = await r.json();
      SEASON_CACHE[year] = payload.series || {};
      // Normalize track codes that map to physically different tracks
      // across eras. Must run BEFORE any analytics or rendering touches
      // this data so every downstream consumer sees the corrected codes.
      _normalizeTrackCodes(SEASON_CACHE[year], year);
      // Invalidate the cross-season driver analytics cache — its
      // per-(driver, series) and per-(driver, series, trackCode)
      // entries were built from a partial SEASON_CACHE and would now
      // be stale (e.g., a `null` "no history" entry would persist
      // even though we just added a year with race history). This
      // was the cause of the intermittent "No active drivers have
      // raced at <track>" empty state on Track / Home pages: a track
      // page rendered during warmup poisoned the cache before the
      // new years arrived.
      if (typeof resetDriverAnalyticsCache === "function") {
        resetDriverAnalyticsCache();
      }
      if (typeof resetProjectionCache === "function") {
        resetProjectionCache();
      }
      return SEASON_CACHE[year];
    } catch (e) { /* try next */ }
  }
  return null;
}

// Fetches every year in STATE.trajectory.seasons that isn't already cached.
// Resolves when all are loaded.
async function ensureTrajectorySeasonsLoaded() {
  const years = [...STATE.trajectory.seasons];
  await Promise.all(years.map(y => loadSeasonIntoCache(y)));
}

function showError(msg) {
  document.querySelectorAll(".view").forEach(v => v.hidden = true);
  const ev = document.getElementById("view-error");
  ev.hidden = false;
  document.getElementById("error-msg").textContent = msg;
}
function hideError() {
  const ev = document.getElementById("view-error");
  if (ev) ev.hidden = true;
}

// ============================================================
// PRESENT / HISTORICAL MODE HELPERS
// ============================================================
// In Present mode we hide the season pickers (desktop + mobile) and
// update the toggle so it's clear what state the site is in. Series
// switcher, R-cursor, and search all stay active in both modes.
function applyModeToDom() {
  const isHistorical = STATE.mode === "historical";
  // Desktop season picker — hide entirely in Present mode (no semi-disabled
  // tease state, just gone, per the design intent of "live at the present").
  const seasonSel = document.getElementById("season-picker");
  if (seasonSel) seasonSel.hidden = !isHistorical;
  // Mobile secondary topbar row — only visible in Historical mode. Hosts
  // both the season picker and the race-cursor picker.
  const historicalRow = document.getElementById("topbar-historical");
  if (historicalRow) {
    historicalRow.hidden = !isHistorical;
    // When the row becomes visible, ensure its selects are populated
    // and synced with the desktop pickers. Safe to call repeatedly.
    if (isHistorical) syncMobileNavSettings();
  }
  // Update the Present/Historical selector button "on" state
  document.querySelectorAll("#topbar-mode-sw button").forEach(b => {
    b.classList.toggle("on", b.dataset.mode === STATE.mode);
  });
  // Sync the mobile mode <select> to match.
  const modeSel = document.getElementById("topbar-mode-sw-select");
  if (modeSel && modeSel.value !== STATE.mode) modeSel.value = STATE.mode;
}

// Pull the persisted mode from localStorage on boot. Default to "present"
// if anything looks off (no localStorage, weird value, etc.).
function restoreModeFromStorage() {
  try {
    const saved = localStorage.getItem("dc_mode");
    if (saved === "historical" || saved === "present") {
      STATE.mode = saved;
    }
  } catch (e) {
    // localStorage blocked / private mode — just stay on default
  }
}

// ============================================================
// UI CONTROLS
// ============================================================
// Sync the series toggle UI (topbar buttons + mobile select) to match
// the active series. Module-scoped so callers outside wireUIControls
// (parseHash, etc.) can use it.
function syncSeriesUIGlobal(target) {
  document.querySelectorAll("#series-sw button").forEach(x =>
    x.classList.toggle("on", x.dataset.series === target));
  const sel = document.getElementById("series-sw-select");
  if (sel) {
    if (sel.value !== target) sel.value = target;
    // data-series drives the colored background (gold/green/red) on
    // mobile — see CSS rules in app.css for .series-sw-select[data-series=].
    sel.setAttribute("data-series", target);
  }
}

// Apply a series change with all the necessary side-effects (state
// reset, data load, UI sync, re-render). Hoisted to module scope so
// the hash router can trigger it for query params like #/standings?series=NOS.
async function applySeriesChangeGlobal(next) {
  if (next === STATE.series) return;
  STATE.series = next;
  syncSeriesUIGlobal(next);
  if (STATE.mode === "present") STATE.lastPresentSeries = next;
  // Clamp current season into the new series's available range.
  // Example: user is on 1955 NCS and switches to NOS (which starts
  // 1982). Without clamping, we'd try to load NOS data for 1955 and
  // either 404 or load an NCS-only block. Pick the most recent
  // available year for the new series instead.
  const seriesYears = seasonsAvailableForSeries(next);
  if (seriesYears.length > 0 && !seriesYears.includes(STATE.season)) {
    STATE.season = seriesYears[0];  // seasonsAvailable is sorted desc, so this is the latest
  }
  STATE.throughRound = null;
  STATE.arc.selected.clear();
  STATE.trajectory.selected.clear();
  STATE.trajectory.seasons.clear();
  await loadCurrentData();
  resetRenderCache();
  populateSeasonPicker();  // dropdown must reflect new series's available years
  populateRacePicker();
  renderTimeCursorBanner();
  render();
}

// ============================================================
// PER-PAGE SERIES TOGGLE
// ============================================================
// The site is no longer in one global series "mode". Each series-scoped
// view owns its NCS/NOS/NTS choice independently (STATE.pageSeries[view]).
// STATE.series remains the single "active render series" that all ~175 read
// sites consume — we just drive it from the current page's memory on every
// navigation/boot (ensurePageSeries) and let the #page-series-bar toggle
// rewrite that memory (applyPageSeries).
//
// Views that get the toggle. Excluded on purpose:
//   home                         → multi-series (the trios), never single-series
//   profile / team / cc          → entity-locked to that entity's home series
//   drivers / teams / crewchiefs → all-time pages with their own series filter
//                                  (incl. an "All" option) — a second toggle
//                                  would fight it
//   pointscalc                   → points-format calculator, series-agnostic
const SERIES_TOGGLE_VIEWS = [
  "schedule", "standings", "playoffs", "projection",
  "race", "track",
  "form", "arc", "breakdown", "trajectory", "teammates", "heatmap",
  "trackstats", "compare",
];

// Restore (or initialize) the active series for the current view from its
// per-page memory. Pure state mutation — callers must run inside an async
// context and reload data afterward (boot's loadCurrentData, or the
// hashchange load guard) since the series may have changed. First visit to a
// page defaults to NCS so the new baseline is predictable everywhere.
function ensurePageSeries() {
  const view = STATE.view;
  if (view === "home") {
    // Home is multi-series (the trios render all three independently), but its
    // surrounding chrome — left standings panel, power rankings, the next-race
    // hero — follows STATE.series. Always anchor Home to Cup so it doesn't
    // inherit NOS/NTS from whatever page you came from.
    if (STATE.series !== "NCS") {
      STATE.series = "NCS";
      if (STATE.mode === "present") STATE.lastPresentSeries = "NCS";
      const yrs = seasonsAvailableForSeries("NCS");
      if (yrs.length > 0 && !yrs.includes(STATE.season)) STATE.season = yrs[0];
    }
    return;
  }
  if (!SERIES_TOGGLE_VIEWS.includes(view)) return;
  STATE.pageSeries = STATE.pageSeries || {};
  if (!STATE.pageSeries[view]) STATE.pageSeries[view] = "NCS";
  const want = STATE.pageSeries[view];
  if (want !== STATE.series) {
    STATE.series = want;
    if (STATE.mode === "present") STATE.lastPresentSeries = want;
    // Clamp the season into the new series's available range (same guard
    // applySeriesChangeGlobal uses) so we never request a year the series
    // didn't run.
    const yrs = seasonsAvailableForSeries(want);
    if (yrs.length > 0 && !yrs.includes(STATE.season)) STATE.season = yrs[0];
  }
}

// Paint the #page-series-bar for the current view. Shown only on
// series-scoped views; highlights whichever series is active. Cheap and
// idempotent — safe to call on every render().
function renderPageSeriesBar() {
  const bar = document.getElementById("page-series-bar");
  if (!bar) return;
  const show = SERIES_TOGGLE_VIEWS.includes(STATE.view);
  bar.hidden = !show;
  if (!show) { bar.innerHTML = ""; return; }
  const cur = STATE.series;
  // Drill-in takeovers (race/track/schedule) carry a Back control. Render it
  // on the LEFT of the series toggle (ordered before the "SERIES" label) so it
  // sits up on this row rather than below it; their own takeover-head Back is
  // hidden via CSS.
  const back = ["race", "track", "schedule"].includes(STATE.view)
    ? `<a href="#" class="takeover-back pgs-back" onclick="takeoverBack(event)">← Back</a>`
    : "";
  bar.innerHTML = back +
    `<div class="pgs-track" role="tablist" aria-label="Series">` +
    ["NCS", "NOS", "NTS"].map(s =>
      `<button type="button" class="pgs-btn${s === cur ? " on" : ""}" ` +
      `data-pgs="${s}" data-series="${s}" role="tab" ` +
      `aria-selected="${s === cur ? "true" : "false"}">${s}</button>`
    ).join("") +
    `</div>`;
}

// Shared Back behavior for drill-in takeovers: return to the previous hash if we
// have one, else the previous view, else a sensible default.
function takeoverBack(e) {
  if (e) e.preventDefault();
  if (STATE.prevHash && STATE.prevHash !== location.hash) {
    location.hash = STATE.prevHash;
    return;
  }
  const skip = ["race", "track", "schedule", "profile", "team", "cc",
                "drivers", "teams", "crewchiefs", "personnel"];
  const prev = (STATE.prevView && !skip.includes(STATE.prevView)) ? STATE.prevView : "arc";
  location.hash = `#/${prev}`;
}

// Toggle handler: record the choice for THIS page, then apply. Reuses
// applySeriesChangeGlobal for the heavy lifting (clamp season, load data,
// reset cache, repopulate pickers, render). If the page is already on that
// series we just repaint the bar.
async function applyPageSeries(series) {
  if (series !== "NCS" && series !== "NOS" && series !== "NTS") return;
  const view = STATE.view;
  STATE.pageSeries = STATE.pageSeries || {};
  STATE.pageSeries[view] = series;
  if (series !== STATE.series) {
    await applySeriesChangeGlobal(series);   // calls render() → renderPageSeriesBar()
  } else {
    renderPageSeriesBar();
  }
}

function wireUIControls() {
  // Race Center session tabs (Race / Practice 1 / Practice 2 / Qualifying).
  // Delegated since the tabs DOM is rebuilt every time the user navigates
  // to a new race. Clicking a tab swaps `.active` on both the tab and its
  // matching pane — no global state, just DOM toggles.
  document.addEventListener("click", (e) => {
    const tab = e.target.closest(".rc-session-tab");
    if (!tab) return;
    const wrap = tab.closest(".rc-sessions-tabbed");
    if (!wrap) return;
    const targetId = tab.dataset.tab;
    wrap.querySelectorAll(".rc-session-tab").forEach(t => t.classList.toggle("active", t === tab));
    wrap.querySelectorAll(".rc-session-pane").forEach(p =>
      p.classList.toggle("active", p.dataset.pane === targetId));
  });

  // Helper: sync the series toggle UI (buttons + mobile select) to match
  // the active series. Used both at boot and after every series change.
  // (Now a thin wrapper around the module-scoped helper. The old global
  // #series-sw element is gone, so this is effectively a no-op for the
  // header but kept so callers don't need null-checks everywhere.)
  const syncSeriesUI = syncSeriesUIGlobal;

  // Per-page series toggle (#page-series-bar). Delegated because the bar's
  // buttons are rebuilt on every render. Clicking one records the choice for
  // the current page and applies it.
  document.addEventListener("click", (e) => {
    const b = e.target.closest(".pgs-btn");
    if (!b) return;
    e.preventDefault();
    applyPageSeries(b.dataset.pgs);
  });

  // Links that carry a series into their destination page (e.g. the home
  // trio's "next race" track links). Set the target page's remembered series
  // BEFORE the anchor navigates (no preventDefault — the href changes the
  // hash and ensurePageSeries picks it up on the way in).
  document.addEventListener("click", (e) => {
    const a = e.target.closest("a[data-series-page][data-series-set]");
    if (!a) return;
    STATE.pageSeries = STATE.pageSeries || {};
    STATE.pageSeries[a.dataset.seriesPage] = a.dataset.seriesSet;
  });

  // Brand link — clicking "datacarracing" is the global escape hatch.
  // Resets to the most recent (season, race), clears any time-cursor
  // scroll-back, snaps to NCS, and routes to the default standings
  // landing. Replaces the old "Now" button (which did the same thing).
  document.getElementById("brand-link")?.addEventListener("click", async (e) => {
    e.preventDefault();
    const targetSeason = (STATE.seasonsAvailable && STATE.seasonsAvailable[0])
      || STATE.season;
    const targetSeries = "NCS";   // Always returns to the top series
    const needsLoad = (targetSeason !== STATE.season) || (targetSeries !== STATE.series);
    STATE.season = targetSeason;
    STATE.series = targetSeries;
    STATE.throughRound = null;          // clear time cursor
    if (needsLoad) {
      await loadCurrentData();
      resetRenderCache();
      populateRacePicker();
    }
    // Sync the series-switcher UI (buttons + mobile select) to match
    syncSeriesUI(targetSeries);
    renderTimeCursorBanner();
    // Sync the season-picker UI to match
    const sel = document.getElementById("season-picker");
    if (sel) sel.value = String(targetSeason);
    const mobileSel = document.getElementById("topbar-historical-season");
    if (mobileSel) mobileSel.value = String(targetSeason);
    // Always brings the user back to the canonical landing — the home page.
    if (location.hash !== "#/home") {
      location.hash = "#/home";
    } else {
      render();
    }
  });

  // Theme toggle (light / dark). Persists user's choice across sessions
  // via localStorage. The actual color values live in CSS — toggling
  // [data-theme] on <html> swaps the variable scope. The toggle icon
  // shows the OPPOSITE of the current theme so it reads as "switch to X".
  const applyTheme = (theme) => {
    document.documentElement.setAttribute("data-theme", theme);
    try { localStorage.setItem("dcr-theme", theme); } catch (e) { /* private mode etc */ }
    const icon = document.querySelector("#theme-toggle .theme-toggle-icon");
    if (icon) icon.textContent = theme === "light" ? "☾" : "☀";
  };
  document.getElementById("theme-toggle")?.addEventListener("click", () => {
    const current = document.documentElement.getAttribute("data-theme") || "light";
    applyTheme(current === "light" ? "dark" : "light");
    // Re-render any views that bake theme-sensitive colors into the DOM
    // via inline style (mostly heatmaps where each cell's text color
    // depends on the active theme). A blanket render() call is the
    // simplest way to refresh everything.
    if (typeof render === "function") render();
  });

  // Historical/Present mode selector. Mobile uses a compact <select>;
  // desktop uses a two-button pill. Both call the same handler and the
  // applyModeToDom() helper keeps each in sync visually.
  const applyModeChange = async (newMode) => {
    if (!newMode || newMode === STATE.mode) return;
    STATE.mode = newMode;
    try { localStorage.setItem("dc_mode", newMode); } catch (e) {}
    if (newMode === "present") {
      const targetSeason = (STATE.seasonsAvailable && STATE.seasonsAvailable[0])
        || STATE.season;
      if (targetSeason !== STATE.season) {
        STATE.season = targetSeason;
        STATE.throughRound = null;
        await loadCurrentData();
        resetRenderCache();
        populateRacePicker();
        renderTimeCursorBanner();
      }
      const sel = document.getElementById("season-picker");
      if (sel) sel.value = String(STATE.season);
      const mobileSel = document.getElementById("topbar-historical-season");
      if (mobileSel) mobileSel.value = String(STATE.season);
    }
    // Sync the mobile <select> to match (when called from the desktop
    // buttons; harmless when called from the select itself since the
    // value already matches).
    const modeSel = document.getElementById("topbar-mode-sw-select");
    if (modeSel && modeSel.value !== newMode) modeSel.value = newMode;
    applyModeToDom();
    render();
  };
  document.querySelectorAll("#topbar-mode-sw button").forEach(b => {
    b.addEventListener("click", () => applyModeChange(b.dataset.mode));
  });
  document.getElementById("topbar-mode-sw-select")?.addEventListener("change", (e) => {
    applyModeChange(e.target.value);
  });

  // Form view toggles
  document.querySelectorAll("#view-form .toggle-group").forEach(g => {
    const group = g.dataset.group;
    g.querySelectorAll("button").forEach(b => {
      b.addEventListener("click", () => {
        g.querySelectorAll("button").forEach(x => x.classList.toggle("on", x === b));
        if (group === "window") STATE.form.window = b.dataset.val;
        if (group === "ftfilter") STATE.form.ftOnly = (b.dataset.val === "ft");
        renderFormTable();
      });
    });
  });
  document.getElementById("form-search")?.addEventListener("input", (e) => {
    STATE.form.search = e.target.value.toLowerCase();
    renderFormTable();
  });

  // Arc toggles (full-time filter)
  document.querySelectorAll("#view-arc .toggle-group").forEach(g => {
    const group = g.dataset.group;
    g.querySelectorAll("button").forEach(b => {
      b.addEventListener("click", () => {
        g.querySelectorAll("button").forEach(x => x.classList.toggle("on", x === b));
        if (group === "arc-ft") STATE.arc.ftOnly = (b.dataset.val === "ft");
        if (group === "arc-metric") STATE.arc.metric = b.dataset.val;
        renderArc();
      });
    });
  });

  // Stage Points view: Drivers / Teams toggle
  document.querySelectorAll("#view-breakdown .toggle-group").forEach(g => {
    const group = g.dataset.group;
    g.querySelectorAll("button").forEach(b => {
      b.addEventListener("click", () => {
        g.querySelectorAll("button").forEach(x => x.classList.toggle("on", x === b));
        if (group === "breakdown-mode") STATE.breakdown.mode = b.dataset.val;
        renderBreakdown();
      });
    });
  });

  // Trajectory toggles — exclude traj-seasons, which is a multi-select group
  // managed by renderTrajectorySeasonChips() (different selection semantics
  // and it needs to re-wire on every render as data loads).
  document.querySelectorAll("#view-trajectory .toggle-group").forEach(g => {
    const group = g.dataset.group;
    if (group === "traj-seasons") return;
    g.querySelectorAll("button").forEach(b => {
      b.addEventListener("click", () => {
        g.querySelectorAll("button").forEach(x => x.classList.toggle("on", x === b));
        if (group === "traj-mode") STATE.trajectory.mode = b.dataset.val;
        if (group === "traj-show") STATE.trajectory.show = b.dataset.val;
        if (group === "traj-labels") STATE.trajectory.labels = b.dataset.val;
        if (group === "traj-tracks") STATE.trajectory.tracks = b.dataset.val;
        if (group === "traj-ft") STATE.trajectory.ftOnly = (b.dataset.val === "ft");
        renderTrajectory();
      });
    });
  });

  // Teammate view toggles
  document.querySelectorAll("#view-teammates .toggle-group").forEach(g => {
    const group = g.dataset.group;
    g.querySelectorAll("button").forEach(b => {
      b.addEventListener("click", () => {
        g.querySelectorAll("button").forEach(x => x.classList.toggle("on", x === b));
        if (group === "teammates-metric") STATE.teammates.metric = b.dataset.val;
        if (group === "teammates-ft")     STATE.teammates.ftOnly = (b.dataset.val === "ft");
        renderTeammates();
      });
    });
  });

  // Takeover back button returns to dashboard home (default = Trending tab)
  // Profile back: return to the previous page IN FULL — including any
  // parameter (so #/team/HMS restores cleanly, not as #/team).
  document.getElementById("takeover-back")?.addEventListener("click", (e) => {
    e.preventDefault();
    if (STATE.prevHash && STATE.prevHash !== location.hash) {
      location.hash = STATE.prevHash;
      return;
    }
    const prev = STATE.prevView && STATE.prevView !== "profile" ? STATE.prevView : "arc";
    location.hash = `#/${prev}`;
  });
  // Race / Track / Schedule / Team back: same logic as profile-back.
  ["race-back", "track-back", "schedule-back", "team-back", "cc-back",
   "drivers-back", "teams-back", "crewchiefs-back", "personnel-back"].forEach(id => {
    document.getElementById(id)?.addEventListener("click", (e) => {
      e.preventDefault();
      if (STATE.prevHash && STATE.prevHash !== location.hash) {
        location.hash = STATE.prevHash;
        return;
      }
      const cur = STATE.view;
      const prev = STATE.prevView && STATE.prevView !== cur ? STATE.prevView : "arc";
      location.hash = `#/${prev}`;
    });
  });
  // Playoffs back: return to the dashboard default
  document.getElementById("playoffs-back")?.addEventListener("click", (e) => {
    e.preventDefault();
    location.hash = "#/";
  });

  document.getElementById("arc-clear")?.addEventListener("click", () => {
    STATE.arc.selected.clear();
    STATE.arc.userCleared = true;
    renderArc();
  });
  document.getElementById("arc-top10")?.addEventListener("click", () => {
    STATE.arc.selected.clear();
    STATE.arc.userCleared = false;
    const totals = computeSeasonTotals();
    totals.slice(0, 10).forEach(t => STATE.arc.selected.add(entityKey(t)));
    renderArc();
  });
  document.getElementById("arc-all")?.addEventListener("click", () => {
    // Select every full-time driver (or every entity, depending on ft toggle).
    // Mirrors the Top 10 button — the FT filter that already governs the
    // chart applies here too via applyTeamFilter / allEntities.
    STATE.arc.selected.clear();
    STATE.arc.userCleared = false;
    const targets = STATE.arc.ftOnly
      ? allEntities().filter(isFullTime)
      : allEntities();
    targets.forEach(e => STATE.arc.selected.add(entityKey(e)));
    renderArc();
  });

  document.getElementById("traj-clear")?.addEventListener("click", () => {
    STATE.trajectory.selected.clear();
    renderTrajectory();
  });

  // Profile/CC takeover click delegation. We bind one listener per
  // takeover root and let event.target.closest() figure out what was
  // clicked. The same handler covers both because they share most of
  // the same interactive controls (heatmap series toggle, etc.).
  // CC-specific controls (`#cc-heatmap-series-toggle`) only ever
  // appear inside `#cc-takeover`; driver-specific ones only inside
  // `#profile-takeover`. Branches that don't match for a given
  // takeover just no-op.
  //
  // Why two listeners instead of one on document.body: keeps event
  // dispatch scoped (no firing for clicks outside takeovers) and
  // sidesteps any other body-level click capture/preventDefault that
  // would interfere.
  const _takeoverClickHandler = (e) => {
    // Both .ctx-chip (year/series chip) and .ctx-today (Today escape hatch)
    // use data-ctx-year/data-ctx-series so we handle them in one branch.
    const ctxBtn = e.target.closest(".ctx-chip, .ctx-today");
    if (ctxBtn) {
      e.preventDefault();
      const year = parseInt(ctxBtn.dataset.ctxYear, 10);
      const series = ctxBtn.dataset.ctxSeries;
      if (year && series) switchProfileContext(year, series);
      return;
    }
    const splitsBtn = e.target.closest("#profile-splits-toggle button");
    if (splitsBtn) {
      e.preventDefault();
      const newMode = splitsBtn.dataset.val;   // "season" or "career"
      if (!newMode || newMode === STATE.profile.splitsRange) return;
      STATE.profile.splitsRange = newMode;
      // Update toggle visual state immediately (no full re-render needed)
      splitsBtn.parentElement.querySelectorAll("button").forEach(b =>
        b.classList.toggle("on", b === splitsBtn)
      );
      // Show/hide the series filter — only relevant in Career mode
      const seriesToggle = document.getElementById("profile-splits-series-toggle");
      if (seriesToggle) {
        seriesToggle.style.display = (newMode === "career") ? "" : "none";
      }
      // Update panel title to match the mode
      const titleEl = document.getElementById("profile-track-splits-title");
      if (titleEl) {
        titleEl.textContent = (newMode === "career" ? "Career" : STATE.season) + " Track Splits";
      }
      // Repaint just the splits grid — no need to rebuild entire profile
      const entity = findEntityFromSlug();
      if (entity) paintProfileTrackSplits(entity);
      // When entering Career mode, eagerly load every season we don't have
      // yet so the strip fills out completely. Default lazy-load only does
      // 8 years per pass; for a 25-year career that's 3-4 re-renders. This
      // pulls them all in parallel and repaints once.
      if (newMode === "career") {
        const allYears = Object.keys(SEASON_CACHE).map(Number);
        const missing = (STATE.seasonsAvailable || []).filter(y => !allYears.includes(y));
        if (missing.length > 0) {
          // Show a loading state in the title so the user knows it's working.
          // Re-grab the element right before each write — re-renders may have
          // replaced it since the click handler fired.
          const t1 = document.getElementById("profile-track-splits-title");
          if (t1) t1.textContent = `Career Track Splits  (loading ${missing.length} season${missing.length === 1 ? "" : "s"}…)`;
          Promise.all(missing.map(y => loadSeasonIntoCache(y)))
            .then(() => {
              // Repaint as long as the user is still on a profile in career
              // mode. We don't gate on STATE.profile.kind === "driver" since
              // paintProfileTrackSplits derives the slug from the entity for
              // car-routed profiles too.
              if (STATE.view !== "profile") return;
              if ((STATE.profile && STATE.profile.splitsRange) !== "career") return;
              const t2 = document.getElementById("profile-track-splits-title");
              if (t2) t2.textContent = "Career Track Splits";
              const e2 = findEntityFromSlug();
              if (e2) paintProfileTrackSplits(e2);
            });
        }
      }
      return;
    }
    // Series-filter toggle (All / NCS / NOS / NTS) — only meaningful in
    // Career mode but the button is hidden in Season mode anyway.
    const seriesBtn = e.target.closest("#profile-splits-series-toggle button");
    if (seriesBtn) {
      e.preventDefault();
      const newSeries = seriesBtn.dataset.srs;
      if (!newSeries || newSeries === STATE.profile.splitsSeries) return;
      STATE.profile.splitsSeries = newSeries;
      seriesBtn.parentElement.querySelectorAll("button").forEach(b =>
        b.classList.toggle("on", b === seriesBtn)
      );
      const entity = findEntityFromSlug();
      if (entity) paintProfileTrackSplits(entity);
      return;
    }
    // Top-5-tracks row expand/collapse (inline detail, not navigation)
    const ttRow = e.target.closest("[data-tt-row]");
    if (ttRow && !e.target.closest(".tt-track-link")) {
      e.preventDefault();
      const detail = ttRow.nextElementSibling;
      if (detail && detail.hasAttribute("data-tt-detail")) {
        const open = !detail.hidden;
        detail.hidden = open;
        ttRow.setAttribute("aria-expanded", String(!open));
        ttRow.classList.toggle("open", !open);
      }
      return;
    }
    // Top-5-tracks series filter (separate toggle, separate state)
    const ttBtn = e.target.closest("#profile-toptracks-series-toggle button");
    if (ttBtn) {
      e.preventDefault();
      const newSeries = ttBtn.dataset.srs;
      if (!newSeries || newSeries === (STATE.profile.topTracksSeries || STATE.series)) return;
      STATE.profile.topTracksSeries = newSeries;
      ttBtn.parentElement.querySelectorAll("button").forEach(b =>
        b.classList.toggle("on", b === ttBtn)
      );
      const ent = findEntityFromSlug();
      const drv = ent ? (ent.primaryDriver || ent.driver) : null;
      if (drv) paintProfileTopTracks(drv);
      return;
    }
    // Career-heatmap series filter (separate toggle, separate state)
    const heatBtn = e.target.closest("#profile-heatmap-series-toggle button");
    if (heatBtn) {
      e.preventDefault();
      const newSeries = heatBtn.dataset.srs;
      // [debug] temporary instrumentation for mobile heatmap-filter bug.
      // Mobile shows the button selection sticking but the heatmap content
      // doesn't change. This log lets us inspect what STATE and DOM look
      // like at click time. Remove once root-caused.
      if (window.dcDebug) {
        console.log("[heat-toggle]", {
          newSeries,
          prevState: STATE.profile && STATE.profile.heatmapSeries,
          hostExists: !!document.getElementById("profile-career-heatmap"),
          hostHTML: (document.getElementById("profile-career-heatmap") || {}).innerHTML?.slice(0, 80),
        });
      }
      if (!newSeries || newSeries === STATE.profile.heatmapSeries) return;
      STATE.profile.heatmapSeries = newSeries;
      heatBtn.parentElement.querySelectorAll("button").forEach(b =>
        b.classList.toggle("on", b === heatBtn)
      );
      paintProfileCareerHeatmap();
      if (window.dcDebug) {
        console.log("[heat-toggle after paint]", {
          stateAfter: STATE.profile.heatmapSeries,
          hostHTMLAfter: (document.getElementById("profile-career-heatmap") || {}).innerHTML?.slice(0, 80),
        });
      }
    }
    // CC career-heatmap series filter — same UX as the driver heatmap but
    // lives on the crew chief profile and updates STATE.cc.heatmapSeries.
    const ccHeatBtn = e.target.closest("#cc-heatmap-series-toggle button");
    if (ccHeatBtn) {
      e.preventDefault();
      const newSeries = ccHeatBtn.dataset.srs;
      if (!newSeries || !STATE.cc || newSeries === STATE.cc.heatmapSeries) return;
      STATE.cc.heatmapSeries = newSeries;
      ccHeatBtn.parentElement.querySelectorAll("button").forEach(b =>
        b.classList.toggle("on", b === ccHeatBtn)
      );
      paintCrewChiefCareerHeatmap();
    }
  };
  document.getElementById("profile-takeover")?.addEventListener("click", _takeoverClickHandler);
  document.getElementById("cc-takeover")?.addEventListener("click", _takeoverClickHandler);
}

// Earliest season per NASCAR national series, used to filter the
// season-picker dropdown when the user switches series. Showing 1949
// in the dropdown while on NOS is misleading — that data file might
// exist but won't have an NOS block. Hardcoded because the inception
// years are fixed historical facts (NASCAR Cup 1949, Busch/Xfinity
// 1982, Craftsman Truck 1995).
const SERIES_MIN_YEAR = { NCS: 1949, NOS: 1982, NTS: 1995 };

function seasonsAvailableForSeries(series) {
  const min = SERIES_MIN_YEAR[series] || 1949;
  return (STATE.seasonsAvailable || []).filter(y => y >= min);
}

function populateSeasonPicker() {
  const sel = document.getElementById("season-picker");
  if (!sel) return;
  const years = seasonsAvailableForSeries(STATE.series);
  sel.innerHTML = years
    .map(y => `<option value="${y}" ${y === STATE.season ? "selected" : ""}>${y}</option>`)
    .join("");
  sel.addEventListener("change", async () => {
    STATE.season = parseInt(sel.value);
    STATE.throughRound = null;  // reset cursor on season change
    STATE.trajectory.selected.clear();
    STATE.trajectory.seasons.clear();
    await loadCurrentData();
    resetRenderCache();   // crucial: STATE.data just changed; cached races/entities are stale
    populateRacePicker();
    renderTimeCursorBanner();
    render();
  });
}

// ============================================================
// TIME CURSOR (race-picker + banner)
// ------------------------------------------------------------
// Populates the race-picker dropdown with every race in the loaded season,
// plus a "Latest" option that unsets the cursor. Also paints the banner
// that appears when a non-latest round is selected.
// ============================================================
function populateRacePicker() {
  const sel = document.getElementById("race-picker");
  if (!sel) return;
  // Only show races that have actually run — the cursor only meaningfully
  // operates on races with results. Upcoming races have no data to view
  // "through" so cluttering the dropdown with them was confusing.
  const races = allRacesSorted().filter(r => (r.results || []).length > 0);
  if (!races.length) { sel.innerHTML = ""; return; }
  const lastRunRound = races[races.length - 1].round;
  const effectiveRound = STATE.throughRound != null ? STATE.throughRound : lastRunRound;
  sel.innerHTML = races.map(r => {
    const trackName = prettyTrack(r.track_code, r.track) || "—";
    const label = `R${r.round} · ${trackName}`;
    const s = (r.round === effectiveRound) ? "selected" : "";
    return `<option value="${r.round}" ${s}>${escapeHTML(label)}</option>`;
  }).join("");
  if (!sel._wired) {
    sel.addEventListener("change", () => {
      const picked = parseInt(sel.value, 10);
      // Picking the last RUN race = "back to latest" = null cursor.
      const runRacesNow = allRacesSorted().filter(r => (r.results || []).length > 0);
      const lastRunNow = runRacesNow.length ? runRacesNow[runRacesNow.length - 1].round : null;
      STATE.throughRound = (picked === lastRunNow) ? null : picked;
      renderTimeCursorBanner();
      render();
    });
    sel._wired = true;
  }
  // Keep the mobile mirror in sync with the freshly-rebuilt options.
  syncMobileNavSettings();
}

function renderTimeCursorBanner() {
  const banner = document.getElementById("time-cursor-banner");
  const text = document.getElementById("time-cursor-banner-text");
  if (!banner || !text) return;
  if (STATE.throughRound == null) {
    banner.hidden = true;
    return;
  }
  const races = allRacesSorted();
  const race = races.find(r => r.round === STATE.throughRound);
  const total = races.length;
  const trackLabel = race ? prettyTrack(race.track_code, race.track) : "";
  text.innerHTML = `Viewing <strong>${STATE.season} ${STATE.series}</strong> through <strong>R${STATE.throughRound}${trackLabel ? " · " + escapeHTML(trackLabel) : ""}</strong> of ${total} — historical snapshot`;
  banner.hidden = false;
}

// ============================================================
// RENDER
// ============================================================
// Views that live as tabs inside the center panel.
const TAB_VIEWS = ["home", "arc", "form", "breakdown", "trajectory", "teammates", "heatmap", "trackstats", "compare", "standings"];
// Full-width takeovers — none currently. Reserved for future use.
const TAKEOVER_VIEWS = [];
// Center-column takeovers — these hide tab-body and live in the center pane,
// alongside left (standings) and right (form) panels.
const CENTER_TAKEOVER_VIEWS = ["profile", "race", "track", "schedule", "team", "cc", "playoffs", "drivers", "teams", "crewchiefs", "personnel", "pointscalc", "projection"];

function render() {
  // Memo cache lives for the duration of one render pass — avoids re-running
  // allEntities() / racesSorted() / computeSeasonTotals() across the dozens
  // of callers each tab triggers.
  resetRenderCache();
  // Refresh the topbar season pill on every render — STATE may have shifted
  // (e.g. when entering a historical driver profile), but in Present mode
  // the pill should still display the live anchor. renderSeasonPill is
  // mode-aware and handles both cases.
  renderSeasonPill();
  const dashboard = document.getElementById("dashboard");
  const takeover = document.getElementById("takeover");
  const inTakeover = TAKEOVER_VIEWS.includes(STATE.view);
  const inCenterTakeover = CENTER_TAKEOVER_VIEWS.includes(STATE.view);

  // Mobile page title — visible only on mobile (CSS-controlled). Reflects the
  // current tab/page so users know which view they're on without a tab strip.
  // Hidden entirely on the Home view since the hero card already establishes
  // context — a "NASCAR Points" header above it is just noise.
  const pageTitleEl = document.getElementById("mobile-page-title-text");
  const pageTitleWrap = document.getElementById("mobile-page-title");
  if (pageTitleEl) {
    const titleMap = {
      race: "Race Center",
      track: "Track",
      schedule: "Schedule",
      form: "Power Rankings",
      arc: "Cumulative Season",
      breakdown: "Stage Points",
      trajectory: "Stage vs Finish",
      teammates: "Teammate Delta",
      heatmap: "Heatmap",
      trackstats: "Tracks",
      compare: "Driver Compare",
      standings: "Standings",
      playoffs: "Playoff Picture",
      profile: "Driver Profile",
      team: "Team",
      cc: "Crew Chief",
      drivers: "Drivers",
      teams: "Teams",
      crewchiefs: "Crew Chiefs",
      pointscalc: "Points Format Calc",
      projection: "Season Projection",
    };
    pageTitleEl.textContent = titleMap[STATE.view] || "";
  }
  if (pageTitleWrap) {
    pageTitleWrap.style.display = (STATE.view === "home") ? "none" : "";
  }

  // Lock the navigation pickers when the view is bound to a specific driver
  // or team. On a locked driver profile we silently switched series/season
  // to the driver's home — letting the user touch the picker would yank the
  // profile to "whoever drives this car number in the new year/series",
  // which is the bug we're trying to prevent. Hide both pickers and the
  // race-cursor picker so the lock is explicit, not silent.
  const seriesSwitcher = document.getElementById("series-sw");
  const seasonPicker = document.getElementById("season-picker");
  const racePicker = document.getElementById("race-picker");
  const lockedProfile = STATE.view === "profile"
    && STATE.profile && STATE.profile.locked;
  const onTeam = STATE.view === "team";
  const onCC = STATE.view === "cc";
  const navLocked = lockedProfile || onTeam || onCC;
  if (seriesSwitcher) seriesSwitcher.classList.toggle("locked", navLocked);
  if (seasonPicker)   seasonPicker.classList.toggle("locked", navLocked);
  if (racePicker)     racePicker.classList.toggle("locked", navLocked);

  // Per-page series toggle — show on series-scoped views, hide elsewhere,
  // highlight the active series. STATE.series was already set to this page's
  // remembered series by ensurePageSeries() before we got here.
  renderPageSeriesBar();

  if (dashboard) dashboard.hidden = inTakeover;
  if (takeover) takeover.hidden = !inTakeover;

  // Center-column takeovers — sit inside col-center, hide tab-body when active
  const profileTakeover = document.getElementById("profile-takeover");
  const raceTakeover    = document.getElementById("race-takeover");
  const trackTakeover   = document.getElementById("track-takeover");
  const schedTakeover   = document.getElementById("schedule-takeover");
  const teamTakeover    = document.getElementById("team-takeover");
  const ccTakeover      = document.getElementById("cc-takeover");
  const playoffsTakeover = document.getElementById("playoffs-takeover");
  const driversTakeover = document.getElementById("drivers-takeover");
  const teamsTakeover   = document.getElementById("teams-takeover");
  const ccsTakeover     = document.getElementById("crewchiefs-takeover");
  const pointscalcTakeover = document.getElementById("pointscalc-takeover");
  const projectionTakeover = document.getElementById("projection-takeover");
  const personnelTakeover = document.getElementById("personnel-takeover");
  const tabBody         = document.getElementById("tab-body");
  if (profileTakeover) profileTakeover.hidden = (STATE.view !== "profile");
  if (raceTakeover)    raceTakeover.hidden    = (STATE.view !== "race");
  if (trackTakeover)   trackTakeover.hidden   = (STATE.view !== "track");
  if (schedTakeover)   schedTakeover.hidden   = (STATE.view !== "schedule");
  if (teamTakeover)    teamTakeover.hidden    = (STATE.view !== "team");
  if (ccTakeover)      ccTakeover.hidden      = (STATE.view !== "cc");
  if (playoffsTakeover) playoffsTakeover.hidden = (STATE.view !== "playoffs");
  if (driversTakeover) driversTakeover.hidden = (STATE.view !== "drivers");
  if (teamsTakeover)   teamsTakeover.hidden   = (STATE.view !== "teams");
  if (ccsTakeover)     ccsTakeover.hidden     = (STATE.view !== "crewchiefs");
  if (pointscalcTakeover) pointscalcTakeover.hidden = (STATE.view !== "pointscalc");
  if (projectionTakeover) projectionTakeover.hidden = (STATE.view !== "projection");
  if (personnelTakeover) personnelTakeover.hidden = (STATE.view !== "personnel");
  // The view-playoffs section inside its takeover wrapper has its own
  // hidden attribute — keep it in sync so renderPlayoffs paints into it.
  const pElem = document.getElementById("view-playoffs");
  if (pElem) pElem.hidden = (STATE.view !== "playoffs");
  if (tabBody)         tabBody.hidden         = inCenterTakeover;

  // Tab-panel visibility. Default to "arc" when the URL doesn't point to a
  // specific tab view (Season Arc is the new landing tab).
  const activeTab = TAB_VIEWS.includes(STATE.view) ? STATE.view : "arc";
  TAB_VIEWS.forEach(v => {
    const el = document.getElementById(`view-${v}`);
    if (el) el.hidden = (v !== activeTab);
  });

  // Tab button active-state — match the current view directly. The "Race"
  // and "Schedule" tabs are special: they're center-pane takeovers, not
  // tab-body panels, but they still highlight when their route is active.
  // Tab + subitem active-state. Center-pane takeovers (race, track,
  // schedule, etc.) ALSO drive their tabs' active state — the tab
  // strip should always reflect "where you are". Subitems mark themselves
  // active when their data-view matches STATE.view; their parent tab
  // group also lights up so the user sees which group is open.
  const v = STATE.view;
  // Top-level dash-tab links (those NOT inside .dash-tab-group)
  document.querySelectorAll(".dash-tabs > .dash-tab").forEach(a => {
    const tv = a.dataset.view;
    let active = false;
    if (tv === "race")          active = (v === "race");
    else if (tv === "schedule") active = (v === "schedule");
    else if (tv === "projection") active = (v === "projection");
    else                        active = (!inCenterTakeover && tv === activeTab);
    a.classList.toggle("active", active);
  });
  // Subitems inside dropdown groups
  document.querySelectorAll(".dash-subitem").forEach(a => {
    const tv = a.dataset.view;
    a.classList.toggle("active", tv === v);
  });
  // Parent tab groups: highlight when any child subitem is active.
  // Exception: "projection" has its own top-level tab, so if the active
  // subitem is projection, don't highlight the parent Standings group.
  document.querySelectorAll(".dash-tab-group").forEach(grp => {
    const anyActive = !!grp.querySelector(".dash-subitem.active:not([data-view='projection'])");
    grp.classList.toggle("has-active-child", anyActive);
  });

  // ---- Always-on dashboard side panels (when not in full-page takeover) ----
  if (!inTakeover) {
    renderMetricBar();
    renderStandingsMini();
    renderFormMini();

    if (STATE.view === "profile") {
      renderProfile();
    } else if (STATE.view === "race") {
      renderRaceCenter();
    } else if (STATE.view === "track") {
      renderTrackPage();
    } else if (STATE.view === "schedule") {
      renderSchedulePage();
    } else if (STATE.view === "team") {
      renderTeamPage();
    } else if (STATE.view === "cc") {
      renderCrewChiefPage();
    } else if (STATE.view === "playoffs") {
      renderPlayoffs();
    } else if (STATE.view === "drivers") {
      renderAllTimeDrivers();
    } else if (STATE.view === "teams") {
      renderAllTimeTeams();
    } else if (STATE.view === "crewchiefs") {
      renderAllTimeCrewChiefs();
    } else if (STATE.view === "personnel") {
      renderPersonnel();
    } else if (STATE.view === "pointscalc") {
      renderPointsCalc();
    } else if (STATE.view === "projection") {
      renderProjection();
    } else {
      // Render the active tab's content
      switch (activeTab) {
        case "arc":        renderArc(); break;
        case "home":       renderHome(); break;
        case "form":       renderFormTable(); break;
        case "breakdown":  renderBreakdown(); break;
        case "trajectory": renderTrajectory(); break;
        case "teammates":  renderTeammates(); break;
        case "heatmap":    renderHeatmap(); break;
        case "trackstats": renderTrackStats(); break;
        case "compare":    renderCompare(); break;
        case "standings":  renderStandings(); break;
      }
    }
  } else {
    renderMetricBar();
  }

  // Mirror toggle-groups + team-filter pills into native <select>s for mobile.
  // Safe to call on every render — idempotent via data-sig deduplication.
  syncMobileDropdowns();
  enhanceCollapsibleTables();   // collapse wide .m-collapse tables on mobile
}

// ============================================================
// DERIVED METRICS
// ============================================================
// Returns races sorted by round, OPTIONALLY filtered by the time cursor.
// When STATE.throughRound is null (default), returns all scraped races.
// When set, clips to races at or before that round — every downstream view
// (standings, arc, breakdown, trajectory, playoffs, heatmap, trending)
// automatically becomes a point-in-time snapshot because they all read from here.
// Per-render-pass memo cache. Reset at the top of render() so each render
// computes the entity list / sorted races at most once, no matter how many
// helpers consume them. Massive savings on tabs that call allEntities() from
// 5+ places (Heatmap, Standings, the team-filter pill bar, etc).
const RENDER_CACHE = { races: null, allRaces: null, entities: null, totals: null };
function resetRenderCache() {
  RENDER_CACHE.races = null;
  RENDER_CACHE.allRaces = null;
  RENDER_CACHE.entities = null;
  RENDER_CACHE.totals = null;
  // Drop the cross-season driver analytics cache too — it's keyed on
  // SEASON_CACHE shape which can change when a year is added/removed.
  if (typeof resetDriverAnalyticsCache === "function") {
    resetDriverAnalyticsCache();
  }
}

function racesSorted() {
  if (RENDER_CACHE.races) return RENDER_CACHE.races;
  // Only races that have actually been run. Upcoming races (empty results)
  // are present in the data for the schedule UI but should NOT drive
  // standings/form/heatmap math, which only operates on completed races.
  const all = (STATE.data?.races || [])
    .filter(r => (r.results || []).length > 0)
    .slice()
    .sort((a, b) => (a.round || 0) - (b.round || 0));
  RENDER_CACHE.races = (STATE.throughRound != null)
    ? all.filter(r => (r.round || 0) <= STATE.throughRound)
    : all;
  return RENDER_CACHE.races;
}

// Unfiltered access — used by the race picker, which needs to show every race
// scheduled (including ones beyond the cursor, so users can navigate forward).
// ALSO includes upcoming (no-results) races so the schedule UI shows them.
function allRacesSorted() {
  if (RENDER_CACHE.allRaces) return RENDER_CACHE.allRaces;
  RENDER_CACHE.allRaces = (STATE.data?.races || [])
    .slice()
    .sort((a, b) => (a.round || 0) - (b.round || 0));
  return RENDER_CACHE.allRaces;
}

function allEntities() {
  if (RENDER_CACHE.entities) return RENDER_CACHE.entities;
  RENDER_CACHE.entities = entitiesFromRaces(racesSorted());
  return RENDER_CACHE.entities;
}

// Pure helper: build the entity map from any races array. Used by allEntities
// (single-season, the default) and by trajectoryEntities() (multi-season).
function entitiesFromRaces(races) {
  const seriesKey = SERIES_TO_KEY[STATE.series];
  const map = new Map();
  races.forEach(r => {
    (r.results || []).forEach(d => {
      // Car-centric: key is always car number. Multiple drivers across a
      // season roll up into the same entity row and get surfaced via the
      // "i" tooltip in each view.
      const key = `#${d.car_number}`;

      // Two-tier team code resolution (palette no longer stores team codes):
      // 1. d.team_code from scraper — authoritative, built from current race data
      // 2. Fallback: owner parse from team string (for pre-upgrade historical data)
      const teamCode = d.team_code
        || teamCodeFromName(d.team, seriesKey, d.car_number)
        || null;

      if (!map.has(key)) {
        map.set(key, {
          key,
          driver: d.driver,
          driversSet: new Set(),
          driverStarts: {},   // driver name → number of starts in this car
          car_number: d.car_number,
          team: d.team,
          team_code: teamCode,
          manufacturer: d.manufacturer,
          races: [],
          totalStarts: 0,     // includes ineligible — used by projection filter
        });
      }
      const e = map.get(key);
      e.totalStarts += 1;    // always count, even if ineligible
      e.driversSet.add(d.driver);
      e.driverStarts[d.driver] = (e.driverStarts[d.driver] || 0) + 1;
      // Track the most-recent round each driver ran this car, so we can resolve
      // the car's CURRENT driver when the predominant one has gone inactive
      // (mid-season driver change, e.g. a replacement taking over a chartered
      // car for the rest of the year).
      e.driverLastRound = e.driverLastRound || {};
      if ((r.round || 0) >= (e.driverLastRound[d.driver] || 0)) {
        e.driverLastRound[d.driver] = r.round || 0;
      }
      e.maxRound = Math.max(e.maxRound || 0, r.round || 0);
      e.driver = d.driver;
      e.team = d.team;
      if (teamCode) e.team_code = teamCode;
      e.manufacturer = d.manufacturer || e.manufacturer;

      // Ineligible results: the driver is not eligible for series championship
      // points, but they DID race. Include in the entity's races array so the
      // heatmap shows their finish positions. Points fields are zeroed so
      // computeSeasonTotals sums correctly.
      if (d.ineligible) {
        e.races.push({
          round: r.round,
          season: r.season,
          finish: d.finish_pos,
          start: d.start_pos,
          s1: 0, s2: 0, fin: 0, fl: 0, total: 0,
          status: d.status,
          driver: d.driver,
          track_code: r.track_code,
          track: r.track,
          ineligible: true,
        });
        return;
      }
      e.races.push({
        round: r.round,
        season: r.season,
        finish: d.finish_pos,
        start: d.start_pos,
        s1: d.stage_1_pts || 0,
        s2: d.stage_2_pts || 0,
        fin: d.finish_pts || 0,
        fl: d.fastest_lap_pt || 0,
        total: d.race_pts || 0,
        lapsLed: d.laps_led || 0,
        pct_top15: d.loop_pct_top15_laps,
        status: d.status,
        driver: d.driver,
        track_code: r.track_code,
        track: r.track,
      });
    });
  });
  // Finalize each entity: sort drivers by starts desc, derive primary + co-drivers.
  return Array.from(map.values()).map(e => {
    const driversByStarts = Object.entries(e.driverStarts)
      .sort((a, b) => b[1] - a[1])
      .map(([name, starts]) => ({ name, starts }));
    const predominant = driversByStarts[0] ? driversByStarts[0].name : e.driver;
    // Representative driver for the car: normally the predominant (most starts),
    // BUT if that driver has gone inactive — hasn't run in the last 3 rounds —
    // use the car's most-recent driver instead. This surfaces the current
    // driver of a chartered car after a mid-season change (e.g. a full-season
    // replacement) without hardcoding names, while leaving every normal car on
    // its regular driver.
    const lastRound = e.driverLastRound || {};
    const maxRound = e.maxRound || 0;
    let primaryDriver = predominant;
    if (maxRound > 0 && (maxRound - (lastRound[predominant] || 0)) >= 3) {
      // predominant is stale — pick the driver with the most-recent start
      let recent = predominant, recentRound = lastRound[predominant] || 0;
      for (const [name, rnd] of Object.entries(lastRound)) {
        if (rnd > recentRound) { recent = name; recentRound = rnd; }
      }
      primaryDriver = recent;
    }
    const coDrivers = driversByStarts.filter(d => d.name !== primaryDriver);
    return {
      ...e,
      drivers: driversByStarts.map(d => d.name),   // legacy field: ordered driver list
      driversByStarts,                              // [{name, starts}] ordered most → least
      predominantDriver: predominant,               // most starts (regardless of activity)
      primaryDriver,                                // current representative (active-aware)
      coDrivers,                                    // non-representative drivers, with start counts
      driver: primaryDriver,                        // the main "driver" label
    };
  });
}

// Builds entities across the seasons selected in the Stage Analysis view.
// When no seasons are selected, falls back to the current single season.
// Returns { entities, totalRaces, seasonsUsed } — totalRaces is the combined
// race count across all selected seasons (used for the 90% full-time threshold).
function trajectoryEntities() {
  const selected = [...STATE.trajectory.seasons].sort();
  const sCode = STATE.series;

  // Fast path: no multi-season selection → reuse current single-season data
  if (selected.length === 0 ||
      (selected.length === 1 && selected[0] === STATE.season)) {
    return {
      entities: allEntities(),
      totalRaces: racesSorted().length,
      seasonsUsed: [STATE.season],
    };
  }

  // Multi-season: concatenate races from the cache
  const combined = [];
  selected.forEach(year => {
    const seriesBlock = SEASON_CACHE[year] && SEASON_CACHE[year][sCode];
    if (!seriesBlock) return;
    (seriesBlock.races || []).forEach(r => {
      // Tag each race with its season so we can dedupe / display per-year later
      combined.push({ ...r, season: year });
    });
  });
  // Sort combined races chronologically: by year, then by round (within year)
  combined.sort((a, b) => (a.season - b.season) || (a.round - b.round));
  return {
    entities: entitiesFromRaces(combined),
    totalRaces: combined.length,
    seasonsUsed: selected,
  };
}

function allDrivers() { return allEntities(); }

function displayName(entity) {
  if (entity.drivers && entity.drivers.length > 1) {
    return `#${entity.car_number} · ${entity.primaryDriver} +${entity.drivers.length - 1}`;
  }
  return `#${entity.car_number} · ${entity.primaryDriver || entity.driver}`;
}

function entityKey(entity) {
  return `#${entity.car_number}`;
}

// Extract the surname from a driver's full name. Handles common suffixes
// (Jr, Sr, II, III, IV) by stepping back to the previous token, so
// "Ricky Stenhouse Jr" → "Stenhouse Jr" instead of "Jr".
const NAME_SUFFIX_RE = /^(jr|sr|ii|iii|iv|v)\.?$/i;
function lastNameOf(name) {
  if (!name) return "";
  const tokens = String(name).trim().split(/\s+/).filter(Boolean);
  if (tokens.length === 0) return "";
  if (tokens.length === 1) return tokens[0];
  const last = tokens[tokens.length - 1];
  if (NAME_SUFFIX_RE.test(last) && tokens.length >= 2) {
    return `${tokens[tokens.length - 2]} ${last}`;
  }
  return last;
}

// Manufacturer code → display name. Codes come from the scraper's MFR_MAP.
// We keep the codes compact in JSON (TYT/CHV/FRD) but render full names in UI.
// CHE/FOR are legacy codes from older snapshots that we still see in cached data.
const MFR_DISPLAY = {
  TYT: "Toyota",
  TOY: "Toyota",
  CHV: "Chevrolet",
  CHE: "Chevrolet",
  CHR: "Chevrolet",
  FRD: "Ford",
  FOR: "Ford",
  RAM: "Ram",       // NTS 2026+
  DOD: "Dodge",     // active in Cup through 2012
  PON: "Pontiac",   // active in Cup through 2003
  PNT: "Pontiac",
  BUI: "Buick",     // older Cup years
  OLD: "Oldsmobile",
  PLY: "Plymouth",
  MER: "Mercury",
  AMC: "AMC",
};
function manufacturerName(code) {
  if (!code) return "";
  return MFR_DISPLAY[code] || code;
}

// Manufacturer swatch colors — single source of truth for the standings
// manufacturer view AND the per-row Mfr column on driver/owner standings.
// Public-association proxies (Chevy gold, Ford blue, Toyota red); RAM is a
// neutral gunmetal so it reads clearly against those three in NTS 2026+.
const MFR_SWATCH = {
  CHV: "#fdbb30", FRD: "#00407a", TYT: "#eb1a23", RAM: "#7d8084",
  DOD: "#a31818", PNT: "#cf9800", BUI: "#700000", OLD: "#5b6770",
  MER: "#8b8589", PLY: "#1f4d8a", CHR: "#7e1e1e",
};
function mfrSwatchColor(code) {
  return MFR_SWATCH[code] || "#777";
}

// Normalize a driver name for cross-year matching. Strips suffixes (Jr/Sr/etc),
// case, accents, internal punctuation. "Dale Earnhardt Jr." → "dale earnhardt"
// — used to dedupe drivers between years where punctuation may differ
// ("D Hamlin" vs "Denny Hamlin" still won't match — name has to be the full
// form in both records, which is true for racing-reference data).
function normalizeDriverName(name) {
  if (!name) return "";
  return String(name)
    .toLowerCase()
    .normalize("NFD").replace(/[\u0300-\u036f]/g, "")  // strip accents
    .replace(/\b(jr|sr|ii|iii|iv|v)\b\.?/gi, "")        // strip suffixes
    .replace(/[^\w\s]/g, "")                             // strip punctuation
    .replace(/\s+/g, " ")
    .trim();
}

// Returns the hash URL for this entity's profile page. Driver-centric app:
// every profile resolves to #/driver/<slug>. We pick the slug from the
// primary driver of the entity. Falls back to the legacy car-number form
// only if there's no usable driver name (rare).
function profileHref(entity) {
  const drv = entity && (entity.primaryDriver || entity.driver);
  if (drv) return `#/driver/${slugify(drv)}`;
  return `#/car/${entity.car_number}`;
}

function computeSeasonTotals() {
  if (RENDER_CACHE.totals) return RENDER_CACHE.totals;
  const entities = allEntities();
  const rows = entities.map(d => {
    const total = d.races.reduce((s, r) => s + r.total, 0);
    const avgFinish = mean(d.races.map(r => r.finish).filter(x => x != null));
    return { ...d, total, avgFinish };
  });

  // Override summed totals with canonical year-end standings when present.
  // This matches what the standings page does — applies to every view that
  // surfaces season totals (Leader tile, Form panel, metric bar, etc.) so
  // the entire UI agrees on who's #1 in champion-determined years.
  // Mode: "owner" — entities are car-keyed here (see allEntities/entitiesFromRaces).
  applyCanonicalStandings(rows, "owner");

  RENDER_CACHE.totals = rows.sort((a, b) => b.total - a.total);
  return RENDER_CACHE.totals;
}

// ============================================================
// CO-DRIVER BADGE — shared across every view
// ------------------------------------------------------------
// A car that had multiple drivers in a season (substitutes, driver changes,
// one-off relief) gets a small "ⁱ" badge next to its primary driver's name.
// Hovering the badge reveals all drivers who drove the car, sorted by starts.
// Data source: entity.driversByStarts, set by entitiesFromRaces().
// ============================================================

// Returns the HTML for the badge, or "" if the car had a single driver.
// Pass-through: entity must have `driversByStarts` (or `coDrivers`) populated.
function renderCoDriverBadge(entity) {
  const list = entity && entity.driversByStarts;
  if (!Array.isArray(list) || list.length < 2) return "";
  const car = entity.car_number || "";
  // The badge uses data-car so one wire-up call can find and attach to every
  // badge on the page at once, regardless of which view rendered it.
  return `<span class="co-badge" data-car="${escapeHTML(String(car))}" title="Shared car — hover for drivers">i</span>`;
}

// Scans a host element for all .co-badge nodes and wires up a hover tooltip
// that lists every driver who drove the car (with start counts, primary
// highlighted). Safe to call multiple times — it re-binds only the nodes
// inside `host`. Data comes from the current allEntities() snapshot, keyed
// by car number.
function wireCoDriverBadges(host, customEntities) {
  if (!host) return;
  const tip = document.getElementById("metric-tooltip");
  if (!tip) return;
  // Build a lookup of car_number → entity. By default we use the
  // current loaded season's entities (allEntities()), which is right
  // for views that always render from STATE.data. The PFC may render
  // from a different season block — it passes its own entity array
  // (rows from playoffStandings) via customEntities so the tooltip
  // shows drivers from THAT season, not whatever STATE.data is.
  const byCar = new Map();
  const sourceEntities = Array.isArray(customEntities) ? customEntities : allEntities();
  sourceEntities.forEach(e => {
    if (e && e.car_number != null) byCar.set(String(e.car_number), e);
  });

  host.querySelectorAll(".co-badge").forEach(el => {
    const car = el.getAttribute("data-car");
    const ent = byCar.get(String(car));
    if (!ent || !Array.isArray(ent.driversByStarts) || ent.driversByStarts.length < 2) return;

    const rowsHTML = ent.driversByStarts.map((dc, i) => {
      const cls = i === 0 ? "primary" : "";
      const s = dc.starts || 0;
      return `<div class="co-tip-row ${cls}"><span>${escapeHTML(dc.name)}</span><span class="n">${s} race${s === 1 ? "" : "s"}</span></div>`;
    }).join("");
    const totalRaces = ent.races
      ? ent.races.length
      : (ent.driversByStarts.reduce((s, dc) => s + (dc.starts || 0), 0));
    const html = `<div class="co-tip-hdr">Shared Car #${escapeHTML(String(car))} · ${totalRaces} races total</div>${rowsHTML}`;

    const show = (evt) => {
      tip.innerHTML = html;
      tip.className = "";
      ["show", "co-tip"].forEach(c => tip.classList.add(c));
      const rect = tip.getBoundingClientRect();
      let left = evt.clientX + 12, top = evt.clientY + 12;
      if (left + rect.width  > window.innerWidth  - 8) left = evt.clientX - rect.width  - 12;
      if (top  + rect.height > window.innerHeight - 8) top  = evt.clientY - rect.height - 12;
      if (left < 8) left = 8;
      if (top  < 8) top  = 8;
      tip.style.left = `${left}px`;
      tip.style.top  = `${top}px`;
    };
    const hide = () => tip.classList.remove("show");

    el.addEventListener("mouseenter", show);
    el.addEventListener("mousemove",  show);
    el.addEventListener("mouseleave", hide);
    // Clicking the badge keeps the tooltip open briefly for mobile / tap users.
    // Simpler than a full popover: on tap, show, then hide after 4s if no move.
    el.addEventListener("click", (e) => {
      e.preventDefault();
      e.stopPropagation();
      show(e);
      clearTimeout(el._coTimer);
      el._coTimer = setTimeout(hide, 4000);
    });
  });
}

function mean(xs) {
  const a = xs.filter(x => Number.isFinite(x));
  if (a.length === 0) return null;
  return a.reduce((s, x) => s + x, 0) / a.length;
}

// Power Rankings metric — raw components over the last N races (default 8),
// EXCLUDING wreck/DNF races so a fast car that got crashed isn't punished.
// Returns higher-is-better raw values per component (or null when no data);
// the field-relative 0-100 blend is assembled in renderFormTable where the
// whole field is available for normalization. Components & weights:
//   finish 35 / pace 30 / qualifying 20 / top-15% 15  (renormalized to 100).
const POWER_WEIGHTS = { pace: 30, finish: 35, top15: 15, qual: 20 };

// Decide if a race is a "clean" race for form purposes — i.e. NOT a wreck/DNF.
// We exclude when the status indicates a DNF (accident/mechanical) OR when the
// finish is far worse than where the car ran (deep finish despite a strong
// top-15% share — the signature of getting collected late while fast).
function _isCleanFormRace(r) {
  const st = (r.status || "").toString().toLowerCase();
  if (st && /(accident|crash|dnf|engine|suspension|brakes|overheating|rear gear|transmission|electrical|fire|did not finish|retired|parked)/.test(st)) {
    return false;
  }
  // Ran up front but finished deep → almost certainly a late incident, not pace.
  if (r.pct_top15 != null && r.pct_top15 >= 40 && r.finish != null && r.finish >= 30) return false;
  return true;
}

function formRatingFor(driverRaces, windowType) {
  // Back-compat shim: some callers still ask for a quick finish-based number
  // (e.g. the season-vs-form delta). Keep a simple clean-finish rating here.
  const n = windowType === "5" ? 5 : windowType === "10" ? 10 : 8;
  const slice = (driverRaces || []).slice(-n);
  const clean = slice.filter(_isCleanFormRace);
  const finishes = (clean.length ? clean : slice).map(r => r.finish).filter(x => x != null);
  if (finishes.length === 0) return null;
  const avg = finishes.reduce((s, x) => s + x, 0) / finishes.length;
  return Math.max(0, Math.min(100, 100 - (avg - 1) * 2));
}

// Raw per-component values for the blend (higher = better), over the last N
// CLEAN races. Pace is pulled from the lap-time records (lower delta = faster,
// so we negate). Returns null components where there's no usable data.
function powerComponentsFor(driverName, series, driverRaces, windowN = 8) {
  const recent = (driverRaces || []).slice(-windowN);
  const clean = recent.filter(_isCleanFormRace);
  const use = clean.length >= 3 ? clean : recent;   // keep ≥3 races of signal
  if (!use.length) return { pace: null, finish: null, top15: null, qual: null, nClean: 0 };

  const roundsInWindow = new Set(use.map(r => r.round));

  // Recency weighting: more recent races count more. Linear step — the newest
  // race weighs 1.0 and each race further back drops by RECENCY_STEP, floored
  // so even the oldest still contributes. At 0.28 the most recent ~3 races
  // carry the weight (older ones sit at the 0.3 floor) — an aggressive, hot-
  // hand-sensitive setting chosen deliberately.
  // `use` is oldest→newest (driverRaces is chronological), so index 0 is oldest.
  const RECENCY_STEP = 0.28;
  const nUse = use.length;
  const wAt = (idx) => Math.max(0.3, 1 - (nUse - 1 - idx) * RECENCY_STEP);
  // Weighted average over a value-extractor, skipping rows where it's null.
  const wAvg = (rows, getter) => {
    let wsum = 0, acc = 0;
    rows.forEach((r, i) => {
      const v = getter(r);
      if (v == null) return;
      const w = wAt(i);
      acc += v * w; wsum += w;
    });
    return wsum > 0 ? acc / wsum : null;
  };

  // Finish (clean): recency-weighted avg finish → negate so higher = better.
  const finAvg = wAvg(use, r => r.finish);
  const finish = finAvg != null ? -finAvg : null;

  // Qualifying: recency-weighted avg start → negate so higher = better.
  const qualAvg = wAvg(use, r => r.start);
  const qual = qualAvg != null ? -qualAvg : null;

  // Top-15%: recency-weighted avg share of green-flag laps in the top 15.
  const top15 = wAvg(use, r => r.pct_top15);

  // Pace: recency-weighted avg lap-time blend over the window's clean rounds
  // (lower delta = faster), negated so higher = better. Pace records are newest
  // -first, so we reverse to oldest→newest to align with the recency weights.
  let pace = null;
  try {
    const recs = _paceRecordsFor(driverName, series);
    const inWin = recs.filter(rec => roundsInWindow.has(rec.round));
    const paceRecs = (inWin.length ? inWin : recs.slice(0, windowN)).slice().reverse();
    const paceAvg = wAvg(paceRecs, rec => rec.blend);
    if (paceAvg != null) pace = -paceAvg;
  } catch (_) { /* pace stays null; weight redistributes */ }

  return { pace, finish, top15, qual, nClean: clean.length };
}

function seasonTotalRating(driverRaces) {
  return formRatingFor(driverRaces, "season");
}

// Build field-relative Power Rankings for a set of entities. Each driver's raw
// components are normalized to 0-100 across the field (min→0, max→100), then
// blended by POWER_WEIGHTS (renormalized over whichever components the driver
// has). Returns a Map entityKey → { rating, rank } plus the sorted order.
// `cutoffRound` (optional) restricts each driver's races to round ≤ cutoff, so
// we can reproduce "last week's" ranking for the up/down arrows.
function buildPowerRankings(entities, series, windowN = 8, cutoffRound = null) {
  // Gather raw components per entity.
  const rows = entities.map(d => {
    let races = d.races || [];
    if (cutoffRound != null) races = races.filter(r => (r.round || 0) <= cutoffRound);
    const comp = powerComponentsFor(d.primary_driver || d.driver, series, races, windowN);
    return { key: entityKey(d), comp, hasAny: comp.pace != null || comp.finish != null || comp.top15 != null || comp.qual != null };
  }).filter(r => r.hasAny);

  // Field min/max per component for normalization.
  const keys = ["pace", "finish", "top15", "qual"];
  const range = {};
  keys.forEach(k => {
    const vals = rows.map(r => r.comp[k]).filter(v => v != null);
    range[k] = vals.length ? { min: Math.min(...vals), max: Math.max(...vals) } : null;
  });

  rows.forEach(r => {
    let wSum = 0, acc = 0;
    keys.forEach(k => {
      const v = r.comp[k];
      const rg = range[k];
      if (v == null || !rg || rg.max === rg.min) return;
      const norm = ((v - rg.min) / (rg.max - rg.min)) * 100;  // 0..100, higher=better
      acc += norm * POWER_WEIGHTS[k];
      wSum += POWER_WEIGHTS[k];
    });
    r.rating = wSum > 0 ? acc / wSum : null;
  });

  const ranked = rows.filter(r => r.rating != null).sort((a, b) => b.rating - a.rating);
  const out = new Map();
  ranked.forEach((r, i) => out.set(r.key, { rating: r.rating, rank: i + 1 }));
  return out;
}

function isFullTime(entity) {
  const totalRaces = racesSorted().length;
  if (totalRaces <= 0) return false;
  // A driver is "full-time" if they've run at least 90% of the season's races.
  // This tolerates missed races due to suspension, injury, or DNS while still
  // excluding part-time entrants, one-race substitutes, and crossover drivers.
  // Early in the season (few races run), we still require all of them — a
  // driver at 4/5 is fine (80% >= 90% is false, so we need the small-n guard
  // below). With fewer than 10 races run, be strict: need to have run them all
  // minus one.
  if (totalRaces < 10) return entity.races.length >= totalRaces - 1;
  return entity.races.length >= Math.ceil(totalRaces * 0.9);
}

// ============================================================
// DRIVER ANALYTICS MODULE
// ============================================================
// Cross-season analytics functions used by:
//   - Top-5 best-active-drivers home card (driverTrackScore)
//   - Driver Compare page (multiple drivers at once)
//   - Race Prediction home card (the full formula)
//
// All functions read SEASON_CACHE directly so they aggregate across
// every season the user has loaded. Memoized by (driverName, series,
// trackCode) tuples since they get called repeatedly in lists.
// ============================================================

// Module-scoped cache. Invalidated by resetRenderCache (which fires
// whenever STATE.data changes — that covers season-switching).
const DRIVER_ANALYTICS_CACHE = {
  // Map<"driverName|series", { allStarts: [...races sorted by date DESC] }>
  driverHistory: new Map(),
  // Map<"driverName|series|trackCode", trackStats>
  trackStats: new Map(),
  // Map<"driverName|series|trackType", typeStats>
  typeStats: new Map(),
};

function resetDriverAnalyticsCache() {
  DRIVER_ANALYTICS_CACHE.driverHistory.clear();
  DRIVER_ANALYTICS_CACHE.trackStats.clear();
  DRIVER_ANALYTICS_CACHE.typeStats.clear();
}

// Walk SEASON_CACHE and collect every race a driver ran in a given
// series, newest first. Returns [{year, round, track_code, finish_pos,
// start_pos, race_pts, stage_pts_won, ...}].
function getDriverRaceHistory(driverName, series) {
  if (!driverName || !series) return [];
  const cacheKey = `${driverName}|${series}`;
  if (DRIVER_ANALYTICS_CACHE.driverHistory.has(cacheKey)) {
    return DRIVER_ANALYTICS_CACHE.driverHistory.get(cacheKey);
  }
  const target = driverName.toLowerCase().trim();
  const out = [];
  // Walk every loaded year. Years iterate naturally; we sort the final
  // array by (year, round) DESC so callers can take .slice(0, N) for
  // "last N races" without further sorting.
  for (const year of Object.keys(SEASON_CACHE)) {
    const block = SEASON_CACHE[year] && SEASON_CACHE[year][series];
    if (!block || !block.races) continue;
    for (const race of block.races) {
      if (!race.results || race.results.length === 0) continue;
      for (const d of race.results) {
        if (d.ineligible) continue;
        const name = (d.driver || "").toLowerCase().trim();
        if (name !== target) continue;
        out.push({
          year: parseInt(year, 10),
          round: race.round,
          track_code: race.track_code,
          track: race.track,
          finish_pos: d.finish_pos,
          start_pos: d.start_pos,
          qual_pos: d.qual_pos != null ? d.qual_pos : null,
          race_pts: d.race_pts,
          stage1_pts: d.stage_1_pts || 0,
          stage2_pts: d.stage_2_pts || 0,
          stage_pts_total: (d.stage_1_pts || 0) + (d.stage_2_pts || 0),
          laps_led: d.laps_led || 0,
          status: d.status || null,
          car_number: d.car_number,
        });
        break; // one row per race per driver
      }
    }
  }
  // Newest first
  out.sort((a, b) => (b.year - a.year) || ((b.round || 0) - (a.round || 0)));
  DRIVER_ANALYTICS_CACHE.driverHistory.set(cacheKey, out);
  return out;
}

// Stats for a driver at a single track. Returns null if no starts.
function getDriverTrackStats(driverName, series, trackCode) {
  if (!driverName || !series || !trackCode) return null;
  const cacheKey = `${driverName}|${series}|${trackCode}`;
  if (DRIVER_ANALYTICS_CACHE.trackStats.has(cacheKey)) {
    return DRIVER_ANALYTICS_CACHE.trackStats.get(cacheKey);
  }
  const history = getDriverRaceHistory(driverName, series);
  const codes = typeof trackCodesForLookup === "function" ? trackCodesForLookup(trackCode) : [trackCode];
  const atTrack = history.filter(r => codes.includes(r.track_code));
  if (atTrack.length === 0) {
    DRIVER_ANALYTICS_CACHE.trackStats.set(cacheKey, null);
    return null;
  }
  const finishes = atTrack.map(r => r.finish_pos).filter(n => n != null);
  const starts = atTrack.map(r => r.start_pos).filter(n => n != null);
  const stagePts = atTrack.map(r => r.stage_pts_total);
  const racePts = atTrack.map(r => r.race_pts).filter(n => n != null);
  const sum = (arr) => arr.reduce((a, b) => a + b, 0);
  const lastNAvg = (n) => {
    const last = atTrack.slice(0, n).map(r => r.finish_pos).filter(v => v != null);
    return last.length ? sum(last) / last.length : null;
  };
  const lastNRacePtsAvg = (n) => {
    const last = atTrack.slice(0, n).map(r => r.race_pts).filter(v => v != null);
    return last.length ? sum(last) / last.length : null;
  };
  const stats = {
    starts: atTrack.length,
    wins: finishes.filter(f => f === 1).length,
    top5: finishes.filter(f => f <= 5).length,
    top10: finishes.filter(f => f <= 10).length,
    avg_finish: finishes.length ? sum(finishes) / finishes.length : null,
    avg_start: starts.length ? sum(starts) / starts.length : null,
    avg_stage_pts: atTrack.length ? sum(stagePts) / atTrack.length : 0,
    avg_race_pts: racePts.length ? sum(racePts) / racePts.length : null,
    last4_race_pts_avg: lastNRacePtsAvg(4),
    best_finish: finishes.length ? Math.min(...finishes) : null,
    last5: atTrack.slice(0, 5),  // newest first
    last5_avg: lastNAvg(5),
    last4_avg: lastNAvg(4),
    last3_avg: lastNAvg(3),
  };
  DRIVER_ANALYTICS_CACHE.trackStats.set(cacheKey, stats);
  return stats;
}

// Aggregate stats across all tracks of a given type (short/inter/super/road).
// Used for "generalize this driver's performance at this kind of track."
function getDriverTrackTypeStats(driverName, series, trackTypeKey) {
  if (!driverName || !series || !trackTypeKey) return null;
  const cacheKey = `${driverName}|${series}|${trackTypeKey}`;
  if (DRIVER_ANALYTICS_CACHE.typeStats.has(cacheKey)) {
    return DRIVER_ANALYTICS_CACHE.typeStats.get(cacheKey);
  }
  const history = getDriverRaceHistory(driverName, series);
  const atType = history.filter(r => trackType(r.track_code) === trackTypeKey);
  if (atType.length === 0) {
    DRIVER_ANALYTICS_CACHE.typeStats.set(cacheKey, null);
    return null;
  }
  const finishes = atType.map(r => r.finish_pos).filter(n => n != null);
  const stagePts = atType.map(r => r.stage_pts_total);
  const sum = (arr) => arr.reduce((a, b) => a + b, 0);
  // Recency-scoped slice — most recent N starts at this track type only.
  // Used by the prediction model as a "current form at this kind of track"
  // signal (cleaner than the career-wide avg, which weights 10-year-old
  // results equally with last month's).
  const lastNStartsAvg = (n) => {
    const last = atType.slice(0, n).map(r => r.finish_pos).filter(v => v != null);
    return last.length ? sum(last) / last.length : null;
  };
  const lastNStartsStageAvg = (n) => {
    const last = atType.slice(0, n).map(r => r.stage_pts_total);
    return last.length ? last.reduce((a, b) => a + b, 0) / last.length : 0;
  };
  const lastNStartsRacePtsAvg = (n) => {
    const last = atType.slice(0, n).map(r => r.race_pts).filter(v => v != null);
    return last.length ? last.reduce((a, b) => a + b, 0) / last.length : null;
  };
  const stats = {
    starts: atType.length,
    wins: finishes.filter(f => f === 1).length,
    top5: finishes.filter(f => f <= 5).length,
    top10: finishes.filter(f => f <= 10).length,
    avg_finish: finishes.length ? sum(finishes) / finishes.length : null,
    avg_stage_pts: atType.length ? sum(stagePts) / atType.length : 0,
    last5_avg: lastNStartsAvg(5),
    last10_avg: lastNStartsAvg(10),
    last5_stage_pts_avg: lastNStartsStageAvg(5),
    last5_race_pts_avg: lastNStartsRacePtsAvg(5),
  };
  DRIVER_ANALYTICS_CACHE.typeStats.set(cacheKey, stats);
  return stats;
}

// Recent form: average finish over the last N races (default 5) in
// the current season+series. This is the "is this driver hot right now"
// signal that's separate from track-history signals.
function getDriverRecentForm(driverName, series, lastN = 5) {
  const history = getDriverRaceHistory(driverName, series);
  // Filter to current STATE.season so "recent" is meaningful — a driver
  // who ran R30 last year shouldn't count their last-year R30 as "recent"
  // when we're at R3 this year.
  const thisYear = history.filter(r => r.year === STATE.season);
  const recent = thisYear.slice(0, lastN);
  if (recent.length === 0) return null;
  const finishes = recent.map(r => r.finish_pos).filter(n => n != null);
  if (finishes.length === 0) return null;
  return {
    starts: recent.length,
    avg_finish: finishes.reduce((a, b) => a + b, 0) / finishes.length,
    last_race_finish: finishes[0],
    avg_stage_pts: recent.reduce((s, r) => s + r.stage_pts_total, 0) / recent.length,
    avg_race_pts: (() => {
      const pts = recent.map(r => r.race_pts).filter(n => n != null);
      return pts.length ? pts.reduce((a, b) => a + b, 0) / pts.length : null;
    })(),
  };
}

// ============================================================
// TOP TRACKS — a driver's best venues by a balanced 6-stat score
// ============================================================
// Ranks every track a driver has run (in `series`, across all loaded years)
// by a blend of six equally-weighted components, each normalized 0..1 across
// THIS driver's own tracks (so the score is "best relative to their tracks"):
//   1. avg finish        (lower better; low-outlier wrecks/DNFs trimmed)
//   2. avg race points   (higher better; low-outlier bad days trimmed)
//   3. laps led / race   (higher better)
//   4. top-15% rate      (finish within top ~15% of field, higher better)
//   5. pace delta        (our lap-time metric; lower better; only races with
//                         pace data — older years without pace skip this and
//                         the other five still score)
//   6. front-running     (win + top-5 rate, higher better)
// Eligibility: a track needs >= minStarts (2 normally; 1 if the driver has
// <2 starts at EVERY track — a newcomer — so they still get a list).
// `series` may be a specific series ("NCS"/"NOS"/"NTS") or "all" to combine
// the driver's record across every series. Only tracks ON THE CURRENT-SEASON
// SCHEDULE are ranked, so the list reflects where the driver is good among
// venues they'll actually race this year.
function getDriverTopTracks(driverName, series, limit = 5) {
  const allSeries = series === "all";
  const seriesList = allSeries ? ["NCS", "NOS", "NTS"] : [series];

  // Track codes on THIS season's schedule (across the relevant series). The
  // season block's races include upcoming/scheduled events, so this is the
  // full year's venue list.
  const scheduledCodes = new Set();
  for (const s of seriesList) {
    const block = SEASON_CACHE[STATE.season] && SEASON_CACHE[STATE.season][s];
    if (block && block.races) {
      for (const race of block.races) {
        if (race.track_code) scheduledCodes.add(race.track_code);
      }
    }
  }

  const history = [];
  for (const s of seriesList) {
    const h = getDriverRaceHistory(driverName, s);
    for (const r of h) history.push({ ...r, _series: s });
  }
  if (!history.length) return [];

  const byTrack = new Map();
  for (const r of history) {
    if (!r.track_code) continue;
    // Only rank tracks on this season's schedule. If we somehow have no
    // schedule data (cache not loaded), fall back to allowing all tracks so
    // the panel isn't empty.
    if (scheduledCodes.size > 0 && !scheduledCodes.has(r.track_code)) continue;
    if (!byTrack.has(r.track_code)) {
      byTrack.set(r.track_code, { code: r.track_code, track: r.track, rows: [] });
    }
    byTrack.get(r.track_code).rows.push(r);
  }

  if (byTrack.size === 0) return [];  // no history at any scheduled track
  const maxStartsAnywhere = Math.max(...[...byTrack.values()].map(t => t.rows.length));
  const minStarts = maxStartsAnywhere >= 2 ? 2 : 1;

  const trimLowFinish = (vals) => {            // finishes: "low" = high number (bad)
    if (vals.length < 4) return vals;
    const s = [...vals].sort((a, b) => a - b);
    const q = (p) => s[Math.min(s.length - 1, Math.floor(p * (s.length - 1)))];
    const fence = q(0.75) + 1.5 * (q(0.75) - q(0.25));
    const t = vals.filter(v => v <= fence);
    return t.length ? t : vals;
  };
  const trimLowPoints = (vals) => {            // points: "low" = small number (bad)
    if (vals.length < 4) return vals;
    const s = [...vals].sort((a, b) => a - b);
    const q = (p) => s[Math.min(s.length - 1, Math.floor(p * (s.length - 1)))];
    const fence = q(0.25) - 1.5 * (q(0.75) - q(0.25));
    const t = vals.filter(v => v >= fence);
    return t.length ? t : vals;
  };
  const mean = (a) => a.length ? a.reduce((x, y) => x + y, 0) / a.length : null;

  const tracks = [];
  for (const t of byTrack.values()) {
    const starts = t.rows.length;
    if (starts < minStarts) continue;
    const finishes = t.rows.map(r => r.finish_pos).filter(n => n != null);
    const pts = t.rows.map(r => r.race_pts).filter(n => n != null);
    if (!finishes.length) continue;

    const avgFinish = mean(trimLowFinish(finishes));
    const avgPts = mean(trimLowPoints(pts));
    const lapsLedPerRace = mean(t.rows.map(r => r.laps_led || 0));
    const top15 = finishes.filter(f => f <= 6).length / finishes.length;  // ~top 15% of 40
    const wins = finishes.filter(f => f === 1).length;
    const top5 = finishes.filter(f => f <= 5).length;
    const frontRate = (wins / starts) * 0.5 + (top5 / starts) * 0.5;

    let paceDelta = null;
    if (typeof _paceRecordsFor === "function") {
      const pr = [];
      for (const s of seriesList) {
        const recs = _paceRecordsFor(driverName, s, { trackName: t.track });
        for (const x of recs) pr.push(x);
      }
      if (pr.length) paceDelta = mean(pr.map(p => p.blend));
    }

    tracks.push({
      code: t.code, track: t.track, starts,
      avgFinish, avgPts, lapsLedPerRace, top15, frontRate, paceDelta, wins, top5,
    });
  }
  if (!tracks.length) return [];

  const norm = (vals, lowerIsBetter) => {
    const present = vals.filter(v => v != null);
    if (!present.length) return vals.map(() => null);
    const lo = Math.min(...present), hi = Math.max(...present);
    const span = hi - lo;
    return vals.map(v => {
      if (v == null) return null;
      if (span === 0) return 0.5;
      const t = (v - lo) / span;
      return lowerIsBetter ? 1 - t : t;
    });
  };
  const nFinish = norm(tracks.map(t => t.avgFinish), true);
  const nLaps   = norm(tracks.map(t => t.lapsLedPerRace), false);
  const nTop15  = norm(tracks.map(t => t.top15), false);
  const nFront  = norm(tracks.map(t => t.frontRate), false);
  const nPace   = norm(tracks.map(t => t.paceDelta), true);

  tracks.forEach((t, i) => {
    // Avg points is intentionally NOT scored: NASCAR's points scale changed
    // across eras (pre-2017 win ≈ 195, modern win = 55), so a multi-year
    // average mixes incomparable scales and skews the ranking. The remaining
    // five metrics capture "good track" cleanly.
    const comps = [nFinish[i], nLaps[i], nTop15[i], nFront[i], nPace[i]]
      .filter(v => v != null);
    t.score = comps.length ? comps.reduce((a, b) => a + b, 0) / comps.length : 0;
    t.hasPace = nPace[i] != null;
  });

  tracks.sort((a, b) => b.score - a.score);
  return tracks.slice(0, limit);
}

// Speed signals — qualifying, stage position, laps led, top-15 rate.
// Used by the prediction model's Tier 2 (speed adjustment) to capture
// raw pace independent of final finish (which can be ruined by wrecks,
// pit strategy, penalties, etc.).

// Average qualifying/start position over the last N races in the
// current season. Lower = faster.
function getDriverRecentQualAvg(driverName, series, lastN = 8) {
  const history = getDriverRaceHistory(driverName, series);
  const thisYear = history.filter(r => r.year === STATE.season);
  const recent = thisYear.slice(0, lastN);
  const starts = recent.map(r => r.start_pos).filter(n => n != null && n > 0);
  if (starts.length === 0) return null;
  return starts.reduce((a, b) => a + b, 0) / starts.length;
}

// Average mid-race position (mean of stage 1 + stage 2 finish positions)
// over the last N races. Captures race pace immune to late-race incidents.
// Returns null if no stage data available (pre-2017 races, or driver has
// no races with stage positions).
function getDriverRecentStageAvg(driverName, series, lastN = 8) {
  const history = getDriverRaceHistory(driverName, series);
  const thisYear = history.filter(r => r.year === STATE.season);
  const recent = thisYear.slice(0, lastN);
  const stageAvgs = recent.map(r => {
    const s1 = r.stage_1_pos, s2 = r.stage_2_pos;
    if (s1 != null && s2 != null) return (s1 + s2) / 2;
    if (s1 != null) return s1;
    if (s2 != null) return s2;
    return null;
  }).filter(n => n != null);
  if (stageAvgs.length === 0) return null;
  return stageAvgs.reduce((a, b) => a + b, 0) / stageAvgs.length;
}

// Speed bonus metrics for Tier 2 adjustment. Returns { lapsLedPerRace,
// top15Rate, avgDriverRating } across the current season.
function getDriverSpeedMetrics(driverName, series) {
  const history = getDriverRaceHistory(driverName, series);
  const thisYear = history.filter(r => r.year === STATE.season);
  if (thisYear.length === 0) return null;
  const totalLapsLed = thisYear.reduce((s, r) => s + (r.laps_led || 0), 0);
  const lapsLedPerRace = totalLapsLed / thisYear.length;
  const top15Count = thisYear.filter(r => r.finish_pos != null && r.finish_pos <= 15).length;
  const top15Rate = top15Count / thisYear.length;
  const ratings = thisYear.map(r => r.loop_driver_rating).filter(n => n != null);
  const avgDriverRating = ratings.length > 0
    ? ratings.reduce((a, b) => a + b, 0) / ratings.length
    : null;
  return { lapsLedPerRace, top15Rate, avgDriverRating, races: thisYear.length };
}

// ============================================================
// LAP-TIME PACE SIGNALS  (lap-time pace pipeline, 2026-05-31)
// ============================================================
// Loads derived pace metrics from data/pace_{year}.json (produced by
// scripts/scrape_lap_pace.py) and exposes windowed pace signals for the
// prediction model. Pace = fastest-20% / green-median blend, stored per
// driver per race as a field-relative delta% (0 = fastest car that race),
// which is track-agnostic and safe to average across tracks.
//
// Lazy: pace files are only fetched on prediction/home views (see
// ensurePaceLoaded). Cached in PACE_CACHE by year.

const PACE_CACHE = {};            // year -> parsed pace_{year}.json
let _paceLoadAttempted = {};      // year -> true once we've tried (avoid refetch storms)

// The pace metric: f20/median 50-50 blend of the field-relative deltas.
// (Consensus formula chosen by calibration against Nashville R18 eyeball.)
function paceBlend(rec) {
  if (!rec) return null;
  const f20 = rec.fast20_avg_delta_pct;
  const med = rec.green_median_delta_pct;
  if (f20 == null && med == null) return null;
  if (f20 == null) return med;
  if (med == null) return f20;
  return 0.5 * f20 + 0.5 * med;
}

async function ensurePaceLoaded(years) {
  // years: array of calendar years to make sure are loaded. Safe to call
  // repeatedly; only fetches once per year.
  const todo = years.filter(y => !PACE_CACHE[y] && !_paceLoadAttempted[y]);
  await Promise.all(todo.map(async (y) => {
    _paceLoadAttempted[y] = true;
    try {
      const r = await fetch(`data/pace_${y}.json`);
      if (r.ok) PACE_CACHE[y] = await r.json();
    } catch (e) { /* no pace for this year — fine, signals fall back */ }
  }));
}

// Normalize a track name to a comparison token set. The NASCAR feed uses
// full names ("Nashville Superspeedway", "Daytona International Speedway")
// while the app's TRACK_NAMES uses short names ("Nashville Superspeedway",
// "Daytona"). We match on lowercased significant words, dropping generic
// suffixes, so "Daytona" matches "Daytona International Speedway".
const _PACE_TRACK_STOPWORDS = new Set([
  "international", "speedway", "motor", "raceway", "superspeedway",
  "the", "of", "at", "park", "circuit",
]);
function _trackTokens(name) {
  return new Set(
    String(name || "")
      .toLowerCase()
      .replace(/[^a-z0-9 ]/g, " ")
      .split(/\s+/)
      .filter(w => w && !_PACE_TRACK_STOPWORDS.has(w))
  );
}
function _tracksMatch(nameA, nameB) {
  const a = _trackTokens(nameA), b = _trackTokens(nameB);
  if (!a.size || !b.size) return false;
  for (const w of a) if (b.has(w)) return true;   // any significant word in common
  return false;
}

// Gather a driver's pace records (newest first) across all loaded pace years,
// optionally filtered to a track (by name match) or a track type.
// Strip status annotations some feeds bake into pace-data driver keys
// ("* Corey Heim(i)", "Connor Zilisch #", "Shane Van Gisbergen (P)") so a
// driver's history isn't fragmented across variants. Then normalize for match.
function _cleanPaceName(raw) {
  let s = String(raw || "").trim();
  s = s.replace(/^\*\s*/, "");          // leading "* "
  s = s.replace(/\s*\([^)]*\)/g, "");    // "(i)", "(P)", etc.
  s = s.replace(/\s*#\s*$/, "");         // trailing rookie "#"
  return s.replace(/\s+/g, " ").trim();
}

function _paceRecordsFor(driverName, series, { trackName = null, trackType = null } = {}) {
  const out = [];
  const want = (typeof normalizeDriverName === "function")
    ? normalizeDriverName(_cleanPaceName(driverName))
    : _cleanPaceName(driverName).toLowerCase();
  const years = Object.keys(PACE_CACHE).map(Number).sort((a, b) => b - a);
  for (const y of years) {
    const sBlock = PACE_CACHE[y] && PACE_CACHE[y].series && PACE_CACHE[y].series[series];
    if (!sBlock || !sBlock.races) continue;
    for (const race of sBlock.races) {
      if (trackName && !_tracksMatch(race.track, trackName)) continue;
      if (trackType && (typeof trackTypeFromName !== "function" ||
                        trackTypeFromName(race.track) !== trackType)) continue;
      if (!race.drivers) continue;
      // Build (once per race) a normalized-name → record map, merging any
      // annotated variants of the same driver (keep the one with more laps).
      if (!race._paceByNorm) {
        const m = {};
        for (const [k, rec] of Object.entries(race.drivers)) {
          const nk = (typeof normalizeDriverName === "function")
            ? normalizeDriverName(_cleanPaceName(k))
            : _cleanPaceName(k).toLowerCase();
          if (!m[nk] || (rec.green_laps || 0) > (m[nk].green_laps || 0)) m[nk] = rec;
        }
        Object.defineProperty(race, "_paceByNorm", { value: m, enumerable: false });
      }
      const rec = race._paceByNorm[want];
      if (!rec) continue;
      // Skip low-confidence records: a pace built on too few green laps (e.g.
      // 1 lap → an absurd 80%+ delta from a slow out-lap/pit cycle) is not a
      // usable measurement of how fast the car was, and would otherwise poison
      // the driver's OWN pace average (it's already excluded from the field
      // benchmark in the scraper). Treat it as missing.
      if (rec.low_confidence) continue;
      const blend = paceBlend(rec);
      if (blend == null) continue;
      out.push({ year: y, round: race.round || 0, track: race.track, blend,
                 green_laps: rec.green_laps || 0,
                 ref_green: rec.race_ref_green || 0 });
    }
  }
  out.sort((a, b) => (b.year - a.year) || (b.round - a.round));
  return out;
}

// Average the pace blend over the last N records (newest first).
function _avgPace(records, n) {
  const slice = records.slice(0, n);
  if (!slice.length) return null;
  return slice.reduce((s, r) => s + r.blend, 0) / slice.length;
}

// Map a feed track NAME to a track type, reusing the app's TRACK_TYPES via
// the app's track codes. We resolve name->code by matching TRACK_NAMES.
function trackTypeFromName(trackName) {
  if (typeof TRACK_NAMES === "undefined" || typeof TRACK_TYPES === "undefined") return null;
  for (const [code, nm] of Object.entries(TRACK_NAMES)) {
    if (_tracksMatch(nm, trackName)) {
      const t = TRACK_TYPES[code];
      if (t) return t;
    }
  }
  return null;
}

// PRIMARY PACE SIGNAL: last 3 races at THIS track, with fallback chain:
//   1. last 3 at this track
//   2. else recent pace at this track TYPE (last 5)
//   3. else recent overall pace (last 5)
//   4. else null (weight redistributes in the model)
// Returns { value, source } where value is the avg blend delta% (lower=faster)
// and source tags which tier produced it (for debugging/breakdown).
function getDriverTrackPace(driverName, series, trackCode) {
  const trackName = (typeof TRACK_NAMES !== "undefined" && TRACK_NAMES[trackCode]) || null;
  const ttype = (typeof trackType === "function") ? trackType(trackCode) : null;

  if (trackName) {
    const here = _paceRecordsFor(driverName, series, { trackName });
    if (here.length) {
      // Use the record with the most green laps in the window and compare it
      // to that race's field-max (ref_green) → a race-length-agnostic measure
      // of "ran most of the race". Window is the last 5 races at the track
      // (was 3): with only a few seasons of pace data, a 3-race window let a
      // single strong run at a track dominate the prediction (e.g. one good
      // Bristol pace day making a driver the predicted Bristol winner). Five
      // races dilutes any one race's influence. Low-confidence pace records are
      // already excluded upstream in _paceRecordsFor.
      const top = here.slice(0, 5).reduce((a, b) =>
        (b.green_laps || 0) > (a.green_laps || 0) ? b : a, here[0]);
      const ratio = (top.ref_green > 0) ? (top.green_laps || 0) / top.ref_green : null;
      return { value: _avgPace(here, 5), source: "track", n: Math.min(here.length, 5),
               greenLaps: top.green_laps || 0, greenRatio: ratio };
    }
  }
  if (ttype) {
    const atType = _paceRecordsFor(driverName, series, { trackType: ttype });
    if (atType.length) {
      const maxGreen = Math.max(...atType.slice(0, 5).map(r => r.green_laps || 0));
      return { value: _avgPace(atType, 5), source: "type", n: Math.min(atType.length, 5),
               greenLaps: maxGreen, greenRatio: null };
    }
  }
  const recent = _paceRecordsFor(driverName, series, {});
  if (recent.length) {
    const maxGreen = Math.max(...recent.slice(0, 5).map(r => r.green_laps || 0));
    return { value: _avgPace(recent, 5), source: "recent", n: Math.min(recent.length, 5),
             greenLaps: maxGreen, greenRatio: null };
  }
  return { value: null, source: "none", n: 0, greenLaps: 0, greenRatio: null };
}

// SECONDARY PACE SIGNAL: recent pace at this track TYPE (last 5).
function getDriverTypePace(driverName, series, trackCode) {
  const ttype = (typeof trackType === "function") ? trackType(trackCode) : null;
  if (!ttype) return null;
  const atType = _paceRecordsFor(driverName, series, { trackType: ttype });
  return _avgPace(atType, 5);
}

// ============================================================
// ENTRY LIST  (definitive field for an upcoming race)
// ============================================================
// When NASCAR publishes an entry list for the upcoming race, it's the
// authoritative answer to "who is in which car this weekend" — including
// mid-season driver swaps and one-off part-timers. The prediction board
// prefers it over the car-based full-time roster when available.
//
// Cache shape: ENTRY_LIST_CACHE[series][trackCode] = [
//   { car_number, driver, team, ineligible }   // ineligible = not a points car
// ]
// Populated by loadEntryList() once the feed endpoint is wired (see below).
const ENTRY_LIST_CACHE = {};

// Mid-season charter continuations: when a car number is retired and its
// charter continues under a NEW number (e.g. a driver leaves/retires mid-year
// and the team fields a different number for the rest of the season). Keyed
// series -> { oldCarNumber: newCarNumber }. In prediction fallback rosters the
// old car is dropped and the new car is surfaced even if its own start count
// is still below the full-time threshold. 2026: the #8 (Kyle Busch) charter
// continued as the #33 after Charlotte.
const CHARTER_CONTINUATIONS = {
  NCS: { "8": "33" },
};

// Known cross-source name aliases: cases where the odds feed and the points
// data disagree in ways normalization can't safely bridge (abbreviated vs full
// middle names, nicknames). Maps a NORMALIZED odds-feed name → the normalized
// name as it appears in our data, so the entry-list→car join resolves. Add
// entries here when a full-time driver shows up flagged PT with a "—" car.
const DRIVER_NAME_ALIASES = {
  "john hunter nemechek": "john h nemechek",
};

// Normalize a driver name for matching across data sources. The odds feed and
// the points data disagree on punctuation/suffixes ("AJ Allmendinger" vs
// "A.J. Allmendinger", "Ricky Stenhouse Jr." vs "Ricky Stenhouse Jr"), which
// otherwise breaks the entry-list→car join and mislabels full-timers as PT.
// Strips periods, commas, accents, common suffixes, and collapses whitespace,
// then applies any explicit alias.
function normalizeDriverName(name) {
  const base = String(name || "")
    .toLowerCase()
    .normalize("NFD").replace(/[\u0300-\u036f]/g, "")   // strip accents
    .replace(/[.,'']/g, "")                              // drop periods/commas/apostrophes
    .replace(/\b(jr|sr|ii|iii|iv)\b/g, "")               // drop generational suffixes
    .replace(/\s+/g, " ")
    .trim();
  return DRIVER_NAME_ALIASES[base] || base;
}

function getEntryList(series, trackCode) {
  const s = ENTRY_LIST_CACHE[series];
  if (!s) return null;
  // Prefer an exact track-code match; fall back to the "_next" slot only if it
  // matches the requested track (guards against a stale file for another race).
  const hit = s[trackCode] || (s._next && s._next) || null;
  if (!hit) return null;
  if (trackCode && hit.track && _entryTrackToCode(hit.track) &&
      _entryTrackToCode(hit.track) !== trackCode) {
    return null;  // file is for a different race than the one being predicted
  }
  return hit.list || null;
}

// Lazily load the entry list for the upcoming race from the committed data
// file (data/entry_list.json), produced weekly by scripts/scrape_entry_list.py
// from NASCAR's odds feed. The file holds the next race per series, each with
// the full field (driver, driver_id, win_prob). We match the requested
// trackCode to the file's track to be sure it's the right race; if it doesn't
// match (file is stale / different race), we return nothing and the board
// falls back to the full-time car roster.
let _entryListAttempted = false;
async function loadEntryList() {
  if (_entryListAttempted) return;
  _entryListAttempted = true;
  try {
    // Cache-bust: this file is rewritten several times a day by the scheduled
    // scrape, and GitHub Pages serves it with a cache header. Without a unique
    // query the browser can serve a stale copy (e.g. last race's field), so we
    // append a timestamp to force a fresh pull every load.
    const r = await fetch("data/entry_list.json?v=" + Date.now(), { cache: "no-store" });
    if (!r.ok) return;
    const data = await r.json();
    const bySeries = (data && data.series) || {};
    for (const [series, block] of Object.entries(bySeries)) {
      if (!block || !Array.isArray(block.entries)) continue;
      const list = block.entries
        .map(e => ({
          driver: (e.driver || "").trim(),
          driver_id: e.driver_id != null ? e.driver_id : null,
          win_prob: typeof e.win_prob === "number" ? e.win_prob : null,
          // Top-5 finish probability, if the odds feed provides it. Optional —
          // the odds column prefers this over win_prob when present, so adding
          // a `top5_prob` field per entry to the scrape switches the column to
          // top-5 odds with no further code change.
          top5_prob: typeof e.top5_prob === "number" ? e.top5_prob : null,
          // Raw American top-5 odds (e.g. +450, -160), shown exactly as posted
          // when present (preferred over the implied-prob round-trip).
          top5_odds: typeof e.top5_odds === "number" ? e.top5_odds : null,
          // Car number from the entry source (the Jayski fallback supplies this;
          // the odds feed does not). When present, used for display so a one-off
          // sub shows in the car they're actually entered in.
          car: e.car != null ? String(e.car) : null,
        }))
        .filter(e => e.driver);
      if (!list.length) continue;
      // Key by the file's track for this race so getEntryList can confirm the
      // match. We resolve the feed track name to the app's track code.
      const code = _entryTrackToCode(block.track);
      ENTRY_LIST_CACHE[series] = ENTRY_LIST_CACHE[series] || {};
      ENTRY_LIST_CACHE[series][code || "_next"] = { list, track: block.track, race_id: block.race_id };
    }
  } catch (e) { /* no entry list — fall back to full-time roster */ }
}

// ============================================================
// RACE DOCUMENTS — per-race Jayski sheets (entry list, pit stalls,
// crew rosters, infraction report) parsed into tables by
// scripts/scrape_race_docs.py into data/race_docs.json:
//   { "<year>": { "<series>": { "<race_id>": {
//       track, race_date, round, race_page,
//       docs: { entry|pitstall|roster|infraction: { url, rows:[...] } } } } } }
// The race page matches a record by date (unique within a series-year),
// with track name as a fallback, since the app keys races by round (no
// NASCAR race_id of its own).
// ============================================================
const RACE_DOCS_CACHE = {};
let _raceDocsAttempted = false;
let PERSONNEL_INDEX = null;   // built lazily by renderPersonnel from roster docs

async function loadRaceDocs() {
  if (_raceDocsAttempted) return;
  _raceDocsAttempted = true;
  try {
    // Cache-bust: rewritten by the scheduled scrape; force a fresh pull.
    const r = await fetch("data/race_docs.json?v=" + Date.now(), { cache: "no-store" });
    if (!r.ok) return;
    const data = await r.json();
    for (const [yr, bySeries] of Object.entries(data || {})) {
      RACE_DOCS_CACHE[yr] = bySeries;
    }
  } catch (e) { /* no race-docs file yet — the section just won't render */ }
}

// Find the document record for a race. Date (YYYY-MM-DD) is unique within a
// series-year, so match on it first; fall back to track name.
function getRaceDocs(year, series, race) {
  const blk = RACE_DOCS_CACHE[String(year)] && RACE_DOCS_CACHE[String(year)][series];
  if (!blk || !race) return null;
  const wantDate = String(race.date || "").slice(0, 10);
  const wantTrack = String(race.track || "").toLowerCase().trim();
  let byTrack = null;
  for (const rec of Object.values(blk)) {
    const recDate = String(rec.race_date || "").slice(0, 10);
    if (wantDate && recDate && recDate === wantDate) return rec;
    if (wantTrack && String(rec.track || "").toLowerCase().trim() === wantTrack) byTrack = rec;
  }
  return byTrack;
}

// Active top-level tab on the race page; reset when the round changes so a
// fresh race always lands on Overview.
let _raceTab = null;
let _raceTabRound = null;
function selectRaceTab(k) {
  _raceTab = k;
  if (STATE.view === "race") renderRaceCenter();
}

const _DOC_LABELS = { entry: "Entry List", pitstall: "Pit Stalls",
                      roster: "Crew Rosters", infraction: "Infractions" };
const _DOC_ORDER = ["entry", "pitstall", "roster", "infraction"];

// All crew member names whose position contains a keyword (case-insensitive).
function _crewBy(crew, kw) {
  return (crew || [])
    .filter(c => (c.position || "").toLowerCase().includes(kw))
    .map(c => c.name).filter(Boolean);
}
function _pitAbbr(p) {
  return { "front changer": "FC", "rear changer": "RC", "jack": "Jack",
           "fueler": "Fuel", "tire carrier": "TC" }[p] || p;
}
function _td(v) { return escapeHTML(v == null || v === "" ? "—" : String(v)); }

// Build the per-document race-page tabs (entry / pit stalls / rosters /
// infractions) as [{ key, label, count, html }]. The entry list's team and
// crew-chief columns are enriched from the roster doc when the entry sheet
// itself omits them. Returns [] when no docs exist for the race.
function raceDocTabs(race) {
  const rec = getRaceDocs(STATE.season, STATE.series, race);
  if (!rec || !rec.docs) return [];
  const docs = rec.docs;

  // car -> driver, and car -> {team, crew_chief}, sourced from the roster
  // (richest) and then the entry list.
  const carDriver = {}, carMeta = {};
  for (const src of ["roster", "entry"]) {
    if (!docs[src]) continue;
    for (const row of docs[src].rows) {
      const c = row.car != null ? String(row.car) : "";
      if (!c) continue;
      if (row.driver && !carDriver[c]) carDriver[c] = row.driver;
      if (!carMeta[c]) carMeta[c] = {};
      if (row.team && !carMeta[c].team) carMeta[c].team = row.team;
      if (row.crew_chief && !carMeta[c].crew_chief) carMeta[c].crew_chief = row.crew_chief;
    }
  }
  const drv = c => carDriver[String(c)] || "";
  const srcFoot = k => docs[k] && docs[k].url
    ? `<div class="rdoc-foot"><a class="rdoc-src" href="${escapeHTML(docs[k].url)}" ` +
      `target="_blank" rel="noopener">source PDF&nbsp;↗</a></div>` : "";

  const tabs = [];
  for (const k of _DOC_ORDER) {
    const d = docs[k];
    if (!d || !Array.isArray(d.rows) || !d.rows.length) continue;
    let html = "";
    if (k === "entry") html = _rdocEntryTable(d.rows, carMeta);
    else if (k === "pitstall") html = _rdocPitVisual(d.rows, drv);
    else if (k === "roster") html = _rdocRosters(d.rows);
    else if (k === "infraction") html = _rdocInfractionTable(d.rows, drv);
    tabs.push({ key: k, label: _DOC_LABELS[k], count: d.rows.length,
                html: `<div class="rdoc-body">${html}${srcFoot(k)}</div>` });
  }
  return tabs;
}

function _rdocEntryTable(rows, carMeta) {
  carMeta = carMeta || {};
  const body = rows.map(r => {
    const m = carMeta[String(r.car)] || {};
    const team = r.team || m.team;
    const cc = r.crew_chief || m.crew_chief;
    return `<tr><td class="rdoc-car">#${_td(r.car)}</td><td>${_td(r.driver)}</td>
      <td>${_td(team)}</td><td>${_td(cc)}</td></tr>`;
  }).join("");
  return `<div class="table-scroll"><table class="data-table rdoc-table">
      <thead><tr><th>Car</th><th>Driver</th><th>Team</th><th>Crew Chief</th></tr></thead>
      <tbody>${body}</tbody></table></div>`;
}

// A car-number pill + driver name as a single consolidated cell, matching the
// standings-rail look so the colored swatch always carries its number.
function _carDriverCell(car, driver) {
  const hex = (typeof colorFor === "function") ? colorFor(STATE.series, car) : "#888";
  const txt = (typeof contrastTextFor === "function") ? contrastTextFor(hex) : "#000";
  return `<span class="car-tag" style="background:${hex};color:${txt}">${escapeHTML(String(car ?? ""))}</span>` +
    `<span class="rdoc-cd-name">${escapeHTML(driver || "")}</span>`;
}

// Map a parsed stall "type" to its legend class. Occupied boxes are colored by
// the car; unused boxes get the sheet's category colors.
const _STALL_TYPES = [
  { type: "eliminated", label: "Eliminated / Mobility", cls: "st-elim" },
  { type: "vacant",     label: "Vacant",                cls: "st-vac" },
  { type: "monster",    label: "Monster",               cls: "st-mon" },
  { type: "smi",        label: "SMI C10",               cls: "st-smi" },
];
function _stallCls(type) {
  const m = _STALL_TYPES.find(s => s.type === type);
  return m ? m.cls : "st-vac";
}

// Pit stalls as the NASCAR stall sheet: boxes numbered high→low (Turn 4 → Turn
// 1), split at start/finish, each occupied box showing its car number in the
// car's color over the box number; unused boxes colored by category with a
// legend. Wraps to fit the column (no horizontal scroll).
function _rdocPitVisual(rows, drv) {
  const byBox = {}; let maxBox = 0;
  const specialsL = [], specialsR = [];
  rows.forEach(r => {
    if (r.box == null) {
      (r.side === "left" ? specialsL : specialsR).push(r);
      return;
    }
    byBox[r.box] = r;
    maxBox = Math.max(maxBox, r.box);
  });
  if (!maxBox) return `<div class="rc-empty">No pit-stall data.</div>`;
  const sfBox = Math.ceil(maxBox / 2);

  const boxHTML = b => {
    const r = byBox[b];
    if (r && r.car != null && r.car !== "") {
      const hex = (typeof colorFor === "function") ? colorFor(STATE.series, r.car) : "#888";
      const txt = (typeof contrastTextFor === "function") ? contrastTextFor(hex) : "#000";
      return `<div class="rdoc-box" title="#${_td(r.car)} ${escapeHTML(drv(r.car) || "")}">
          <div class="rdoc-box-car" style="background:${hex};color:${txt}">${_td(r.car)}</div>
          <div class="rdoc-box-n">${b}</div></div>`;
    }
    const cls = _stallCls(r && r.type);
    return `<div class="rdoc-box rdoc-box-${cls}" title="${escapeHTML((r && r.type) || "vacant")}"><div class="rdoc-box-car"></div><div class="rdoc-box-n">${b}</div></div>`;
  };
  const specialHTML = r => {
    const lbl = { smi: "SMI", monster: "MON", eliminated: "ELIM", vacant: "" }[r.type] || "";
    return `<div class="rdoc-box rdoc-box-${_stallCls(r.type)}" title="${escapeHTML(r.type)}">
        <div class="rdoc-box-car rdoc-box-special">${lbl}</div><div class="rdoc-box-n">·</div></div>`;
  };

  const group = (hi, lo) => {
    let s = "";
    for (let b = hi; b >= lo; b--) s += boxHTML(b);
    return `<div class="rdoc-pit-group">${s}</div>`;
  };

  const legend = _STALL_TYPES.map(s =>
    `<span class="rdoc-leg"><span class="rdoc-leg-sw rdoc-box-${s.cls}"></span>${s.label}</span>`).join("");

  return `<div class="rdoc-pit">
      <div class="rdoc-pit-legend">${legend}</div>
      <div class="rdoc-pit-lane">
        <span class="rdoc-pit-turn">◄ Turn&nbsp;4</span>
        ${specialsL.map(specialHTML).join("")}
        ${group(maxBox, sfBox + 1)}
        <span class="rdoc-pit-sf">START<br>FINISH</span>
        ${group(sfBox, 1)}
        ${specialsR.map(specialHTML).join("")}
        <span class="rdoc-pit-turn">Turn&nbsp;1 ►</span>
      </div>
    </div>`;
}

// Starting lineup from a completed race's results — grid by start position,
// with qualifying position alongside (they differ after penalties).
function raceLineupTab(race) {
  const grid = ((race && race.results) || [])
    .filter(d => d.start_pos != null && d.start_pos > 0)
    .slice().sort((a, b) => a.start_pos - b.start_pos);
  if (!grid.length) return null;
  const body = grid.map(d => `<tr>
      <td class="rdoc-pos">${d.start_pos}</td>
      <td class="rdoc-cd">${_carDriverCell(d.car_number, d.driver)}</td>
      <td class="rdoc-pos">${d.qual_pos != null && d.qual_pos > 0 ? "P" + d.qual_pos : "—"}</td></tr>`).join("");
  const html = `<div class="rdoc-body"><div class="table-scroll"><table class="data-table rdoc-table rdoc-narrow">
      <thead><tr><th>Start</th><th>Car / Driver</th><th>Qual</th></tr></thead>
      <tbody>${body}</tbody></table></div></div>`;
  return { key: "lineup", label: "Starting Lineup", html };
}

// Driver + owner championship points AS OF this race's round: rank, car/driver,
// starts, wins, points, and points behind the leader.
function racePointsTab(race) {
  if (!race || !((race.results || []).length)) return null;
  if (typeof driverPointsMapThroughRound !== "function" ||
      typeof pointsMapThroughRound !== "function") return null;
  const round = race.round;
  const dRows = driverRankingRowsFrom(driverPointsMapThroughRound(round));
  const oRows = rankingRowsFrom(pointsMapThroughRound(round));
  const tbl = (rows, who) => {
    const leader = rows.length ? Math.round(rows[0].total) : 0;
    const b = rows.map((r, i) => {
      const pts = Math.round(r.total);
      const behind = i === 0 ? "—" : "-" + (leader - pts);
      const name = who === "owner" ? (r.primaryDriver || r.driver) : r.driver;
      return `<tr><td class="rdoc-pos">${i + 1}</td>
          <td class="rdoc-cd">${_carDriverCell(r.car_number, name)}</td>
          <td class="rdoc-pos">${r.starts ?? "—"}</td>
          <td class="rdoc-pos">${r.wins ?? 0}</td>
          <td class="rdoc-pos"><b>${pts}</b></td>
          <td class="rdoc-pos rdoc-behind">${behind}</td></tr>`;
    }).join("");
    return `<table class="data-table rdoc-table"><thead><tr><th>#</th>` +
      `<th>${who === "owner" ? "Car / Owner" : "Car / Driver"}</th>` +
      `<th>St</th><th>W</th><th>Pts</th><th>Back</th></tr></thead><tbody>${b}</tbody></table>`;
  };
  const html = `<div class="rdoc-body"><div class="rc-pts-grid">
      <div class="rc-pts-col"><div class="rc-pts-h">Driver Points</div>
        <div class="table-scroll">${tbl(dRows, "driver")}</div></div>
      <div class="rc-pts-col"><div class="rc-pts-h">Owner Points</div>
        <div class="table-scroll">${tbl(oRows, "owner")}</div></div>
    </div></div>`;
  return { key: "points", label: "Points", html };
}

function _rdocInfractionTable(rows, drv) {
  const body = rows.map(r => `<tr>
      <td class="rdoc-car">#${_td(r.car)}</td><td>${_td(drv(r.car))}</td>
      <td class="rdoc-lap">${_td(r.lap)}</td><td class="rdoc-inf">${_td(r.infraction)}</td>
      <td>${_td(r.penalty)}</td><td class="rdoc-lap">${_td(r.assessed)}</td></tr>`).join("");
  return `<div class="table-scroll"><table class="data-table rdoc-table">
      <thead><tr><th>Car</th><th>Driver</th><th>Lap</th><th>Infraction</th>
      <th>Penalty</th><th>Assessed</th></tr></thead>
      <tbody>${body}</tbody></table></div>`;
}

function _rdocRosters(rows) {
  const sorted = rows.slice().sort(
    (a, b) => (parseInt(a.car, 10) || 999) - (parseInt(b.car, 10) || 999));
  const cards = sorted.map(r => {
    const carChief = _crewBy(r.crew, "car chief").join(", ");
    const eng = _crewBy(r.crew, "engineer").join(", ");
    const spotter = _crewBy(r.crew, "spotter").join(", ");
    const pit = ["front changer", "rear changer", "jack", "fueler", "tire carrier"]
      .map(p => { const n = _crewBy(r.crew, p)[0];
        return n ? `<span class="rdoc-pit"><b>${_pitAbbr(p)}</b>&nbsp;${escapeHTML(n)}</span>` : ""; })
      .filter(Boolean).join("");
    const role = (lbl, v) => v ? `<span><label>${lbl}</label> ${escapeHTML(v)}</span>` : "";
    const full = (r.crew || []).map(c =>
      `<tr><td>${_td(c.type)}</td><td>${_td(c.position)}</td><td>${_td(c.name)}</td></tr>`).join("");
    return `<div class="rdoc-roster">
        <div class="rdoc-roster-head">
          <span class="rdoc-car">#${_td(r.car)}</span>
          <span class="rdoc-roster-drv">${_td(r.driver)}</span>
          <span class="rdoc-roster-cc">CC&nbsp;·&nbsp;${_td(r.crew_chief)}</span>
        </div>
        <div class="rdoc-roster-roles">${role("Car Chief", carChief)}${role("Engineer", eng)}${role("Spotter", spotter)}</div>
        ${pit ? `<div class="rdoc-roster-pit">${pit}</div>` : ""}
        <details class="rdoc-roster-full"><summary>Full crew (${(r.crew || []).length})</summary>
          <div class="table-scroll"><table class="data-table rdoc-table">
            <thead><tr><th>Type</th><th>Position</th><th>Name</th></tr></thead>
            <tbody>${full}</tbody></table></div>
        </details>
      </div>`;
  }).join("");
  return `<div class="rdoc-rosters">${cards}</div>`;
}

// Resolve a feed track name to the app's track code via TRACK_NAMES token match.
function _entryTrackToCode(trackName) {
  if (typeof TRACK_NAMES === "undefined" || !trackName) return null;
  for (const [code, nm] of Object.entries(TRACK_NAMES)) {
    if (_tracksMatch(nm, trackName)) return code;
  }
  return null;
}

// QUAL-PACE SIGNALS. Use TRUE qualifying position (qual_pos), not start_pos —
// start_pos is contaminated by post-qual penalties and backup-car drops, so a
// fast qualifier sent to the rear would look slow. Fall back to start_pos only
// when there was no time-trial qualifying (qual_pos null = random draw etc.).
function _qualValue(row) {
  if (row.qual_pos != null && row.qual_pos > 0) return row.qual_pos;
  return null;  // no real qualifying — don't pollute the signal with start_pos drops
}

// Qual pace at THIS track — average true qual position over last 3 starts here.
function getDriverTrackQual(driverName, series, trackCode) {
  const history = getDriverRaceHistory(driverName, series);
  const codes = (typeof trackCodesForLookup === "function")
    ? trackCodesForLookup(trackCode) : [trackCode];
  const here = history.filter(r => codes.includes(r.track_code));
  const quals = here.map(_qualValue).filter(v => v != null).slice(0, 3);
  if (!quals.length) return null;
  return quals.reduce((a, b) => a + b, 0) / quals.length;
}

// Qual pace at this track TYPE — average true qual position over last 5 at type.
function getDriverTypeQual(driverName, series, trackCode) {
  const ttype = (typeof trackType === "function") ? trackType(trackCode) : null;
  if (!ttype) return null;
  const history = getDriverRaceHistory(driverName, series);
  const atType = history.filter(r => trackType(r.track_code) === ttype);
  const quals = atType.map(_qualValue).filter(v => v != null).slice(0, 5);
  if (!quals.length) return null;
  return quals.reduce((a, b) => a + b, 0) / quals.length;
}


// "Best active drivers at THIS track" composite score. Higher = better.
// Weighted by recency: a 2026 result counts more than a 2020 result.
//
// Score formula (recency-weighted):
//   for each start at this track:
//     w = 0.5 ** (years_ago)   // 1.0 this year, 0.5 last year, 0.25 two years ago...
//     contribution = w * (
//       3.0  if win (P1)
//       + 1.5  if T5
//       + 1.0  if T10
//       - 0.05 * (finish_pos - 1)   // penalty grows with finish position
//     )
//   final_score = sum(contributions)
//
// Drivers with 0 starts at the track get a score of -Infinity so they
// fall off the leaderboard naturally (no need for separate filtering).
function driverTrackScore(driverName, series, trackCode) {
  if (!driverName || !trackCode) return -Infinity;
  const history = getDriverRaceHistory(driverName, series);
  const codes = typeof trackCodesForLookup === "function" ? trackCodesForLookup(trackCode) : [trackCode];
  const atTrack = history.filter(r => codes.includes(r.track_code));
  if (atTrack.length === 0) return -Infinity;
  const currentYear = STATE.season || new Date().getFullYear();
  let score = 0;
  for (const r of atTrack) {
    if (r.finish_pos == null) continue;
    const yearsAgo = Math.max(0, currentYear - r.year);
    const w = Math.pow(0.5, yearsAgo);   // 1.0, 0.5, 0.25, 0.125 ...
    let pts = 0;
    if (r.finish_pos === 1) pts += 3.0;
    if (r.finish_pos <= 5) pts += 1.5;
    if (r.finish_pos <= 10) pts += 1.0;
    pts -= 0.05 * (r.finish_pos - 1);    // a P20 contributes -0.95 before bonuses
    score += w * pts;
  }
  return score;
}

// ============================================================
// COLORS
// ============================================================
function colorFor(series, carNumber) {
  const k = SERIES_TO_KEY[series];
  const pal = STATE.colors && STATE.colors[k];
  if (pal && pal[carNumber] && pal[carNumber].car) return pal[carNumber].car;
  return hashColor(`${series}:${carNumber}`);
}
// Team org color — looked up by team code, not car number. This is the
// single source of truth: one team == one color, any series, any season.
// Fall back to the JS-side constants (TEAM_FULL_NAMES / TEAM_ALLIANCE) for
// metadata if colors.json doesn't have the team entry yet.
function orgColorForTeam(teamCode) {
  if (!teamCode) return null;
  const teams = STATE.colors && STATE.colors.teams;
  if (teams && teams[teamCode] && teams[teamCode].org) return teams[teamCode].org;
  return null;
}
// Back-compat shim: some call sites still pass (series, carNumber). They all
// ultimately want the team color, so resolve car -> team_code -> org via the
// entity map if possible. Prefer callers pass team_code directly.
function orgColorFor(series, carNumber) {
  // Find the entity for this car in the current series and use its team_code.
  if (!STATE.data) return null;
  for (const race of (STATE.data.races || [])) {
    for (const d of (race.results || [])) {
      if (d.car_number === carNumber && d.team_code) {
        return orgColorForTeam(d.team_code);
      }
    }
  }
  return null;
}
function hashColor(str) {
  let h = 2166136261;
  for (let i = 0; i < str.length; i++) {
    h ^= str.charCodeAt(i); h = Math.imul(h, 16777619);
  }
  const hue = Math.abs(h) % 360;
  return `hsl(${hue}, 62%, 60%)`;
}
function contrastTextFor(hex) {
  if (!hex || !hex.startsWith("#") || hex.length < 7) return "#000";
  const r = parseInt(hex.substr(1,2), 16);
  const g = parseInt(hex.substr(3,2), 16);
  const b = parseInt(hex.substr(5,2), 16);
  const lum = (0.299*r + 0.587*g + 0.114*b) / 255;
  return lum > 0.6 ? "#000" : "#fff";
}

// Pick a stroke/dot color that won't disappear into the page background
// for the current theme. Light cars (#fff, #eaeaea) vanish on cream; dark
// cars vanish on charcoal. If a color is "too close" to the page bg we
// scale it toward black (in light mode) or white (in dark mode). Used for
// chart lines, sparklines, and other on-canvas elements that would
// otherwise blend in. Solid pill backgrounds DON'T need this — they
// supply their own contrast against the page through the fill itself.
function safeContrastColor(hex) {
  if (!hex || !hex.startsWith("#") || hex.length < 7) return hex;
  const isLight = document.documentElement.getAttribute("data-theme") === "light";
  const r = parseInt(hex.substr(1,2), 16);
  const g = parseInt(hex.substr(3,2), 16);
  const b = parseInt(hex.substr(5,2), 16);
  const lum = (0.299*r + 0.587*g + 0.114*b) / 255;
  // Threshold: in light mode anything brighter than ~0.78 luminance is
  // washing into the cream. In dark mode anything darker than ~0.18 is
  // disappearing into the charcoal.
  if (isLight && lum > 0.78) {
    // Darken to roughly 50% luminance while preserving hue.
    const factor = 0.55 / lum;
    const nr = Math.round(r * factor);
    const ng = Math.round(g * factor);
    const nb = Math.round(b * factor);
    return `#${nr.toString(16).padStart(2,"0")}${ng.toString(16).padStart(2,"0")}${nb.toString(16).padStart(2,"0")}`;
  }
  if (!isLight && lum < 0.18) {
    // Brighten dark cars toward mid-tone in dark mode.
    const factor = 0.45 / Math.max(lum, 0.05);
    const nr = Math.min(255, Math.round(r * factor));
    const ng = Math.min(255, Math.round(g * factor));
    const nb = Math.min(255, Math.round(b * factor));
    return `#${nr.toString(16).padStart(2,"0")}${ng.toString(16).padStart(2,"0")}${nb.toString(16).padStart(2,"0")}`;
  }
  return hex;
}

// ============================================================
// METRIC BAR
// ============================================================
function renderMetricBar() {
  const bar = document.getElementById("metricbar");
  if (!bar) return;
  // Same context swap as the standings/form mini panels — in Present
  // mode, this bar always shows the latest year's data even when the
  // user has wandered into a historical driver profile.
  const restoreCtx = sidePanelPresentContext();
  if (!STATE.data) { bar.innerHTML = ""; restoreCtx(); return; }
  const races = racesSorted();
  const totals = computeSeasonTotals();
  const lastRace = races[races.length - 1];
  const leader = totals[0];

  // Hottest/Coldest: total points scored in the last 5 completed races
  // (current series). Limited to full-time drivers so a one-off ringer
  // who scored 47 in a single race doesn't dominate. Each entity's
  // races[] is keyed by round; we sum `total` across the 5 most-recent
  // run rounds. Ties are rare with 5-race sums; sort puts highest first.
  const lastRunRounds = races
    .map(r => r.round)
    .filter(rd => rd != null)
    .sort((a, b) => b - a)
    .slice(0, 5);
  const last5 = allEntities().filter(isFullTime).map(d => {
    const sum = (d.races || [])
      .filter(r => lastRunRounds.includes(r.round))
      .reduce((acc, r) => acc + (r.total || 0), 0);
    return { entity: d, points: sum };
  }).filter(d => d.points > 0 || lastRunRounds.length === 0);
  const hottest = last5.slice().sort((a, b) => b.points - a.points)[0];
  const coldest = last5.slice().sort((a, b) => a.points - b.points)[0];

  const winLen = lastRunRounds.length;
  const hotColdTip = `Total points scored in the last ${winLen} race${winLen === 1 ? "" : "s"} (full-time drivers only). Resets each week as new races run.`;
  const leaderTip = "Points leader through the last completed race.";
  const raceTip = "Most recent race in the dataset, with the top 3 finishers.";
  const upcomingTip = "Next scheduled race.";

  // Build top-3 finisher pills for the last race
  let top3HTML = "";
  if (lastRace && (lastRace.results || []).length) {
    const top3 = (lastRace.results || [])
      .filter(d => d.finish_pos != null && d.finish_pos >= 1 && d.finish_pos <= 3)
      .sort((a, b) => a.finish_pos - b.finish_pos);
    top3HTML = top3.map(d => {
      const carHex = colorFor(STATE.series, d.car_number);
      const txtCol = contrastTextFor(carHex);
      return `<a class="metric-finisher profile-link" href="#/driver/${slugify(d.driver)}" title="P${d.finish_pos} \u00b7 ${escapeHTML(d.driver)}">
        <span class="metric-pos">${d.finish_pos}</span>
        <span class="car-tag" style="background:${carHex};color:${txtCol}">${d.car_number}</span>
        <span class="metric-finisher-name">${escapeHTML(lastNameOf(d.driver))}</span>
      </a>`;
    }).join("");
  }

  // Find the next upcoming race (results.length === 0)
  const allRaces = allRacesSorted();
  const upcoming = allRaces.find(r => (r.results || []).length === 0);
  let upcomingHTML = "";
  if (upcoming) {
    const trackName = prettyTrack(upcoming.track_code, upcoming.track) || upcoming.track || "TBD";
    const dateStr = upcoming.date ? formatRaceDate(upcoming.date) : "TBD";
    const timeStr = upcoming.time ? ` \u00b7 ${escapeHTML(upcoming.time)}` : "";
    upcomingHTML = `R${upcoming.round} \u00b7 ${escapeHTML(trackName)}<span class="metric-sub"> \u00b7 ${escapeHTML(dateStr)}${timeStr}</span>`;
  } else {
    upcomingHTML = "Season complete";
  }

  // Build clickable name spans for the leader/hot/cold rows so the user
  // can jump straight into a driver profile from the metric bar. Plain
  // text fallback if we can't resolve a primary driver (rare).
  const driverLink = (entity, suffix = "") => {
    if (!entity) return "—";
    const drv = entity.primaryDriver || entity.driver;
    if (!drv) return escapeHTML(displayName(entity)) + suffix;
    return `<a href="#/driver/${slugify(drv)}" class="metric-name-link">${escapeHTML(displayName(entity))}</a>${suffix}`;
  };

  const metricsHTML = `
    <div class="metric" data-tip="${escapeHTML(leaderTip)}"><span class="k">Leader</span>
      <span class="v">${leader ? `${driverLink(leader)} \u00b7 ${leader.total}` : "\u2014"}</span></div>
    <div class="metric" data-tip="${escapeHTML(hotColdTip)}"><span class="k">Hottest</span>
      <span class="v hot">${hottest ? `${driverLink(hottest.entity)} <span class="metric-pts">${hottest.points}pts</span>` : "\u2014"}</span></div>
    <div class="metric" data-tip="${escapeHTML(hotColdTip)}"><span class="k">Coldest</span>
      <span class="v cold">${coldest ? `${driverLink(coldest.entity)} <span class="metric-pts">${coldest.points}pts</span>` : "\u2014"}</span></div>
    <div class="metric metric-lastrace" data-tip="${escapeHTML(raceTip)}"><span class="k">${STATE.throughRound != null ? "As Of" : "Last Race"}</span>
      <div class="metric-lastrace-row">
        <span class="v">${lastRace ? `<a class="metric-name-link" href="#/race/${lastRace.round}">R${lastRace.round} \u00b7 ${escapeHTML(prettyTrack(lastRace.track_code, lastRace.track))}</a>` : "\u2014"}</span>
        ${top3HTML ? `<div class="metric-finishers">${top3HTML}</div>` : ""}
      </div>
    </div>
    <div class="metric" data-tip="${escapeHTML(upcomingTip)}"><span class="k">Upcoming</span>
      <span class="v">${upcoming ? `<a class="metric-name-link" href="#/race/${upcoming.round}">${upcomingHTML}</a>` : upcomingHTML}</span></div>
  `;

  if (isMobile()) {
    // Two identical copies side-by-side; the CSS animates the track by -50%
    // so the second copy lands exactly where the first began — seamless loop.
    bar.innerHTML = `<div class="metricbar-track">
      <div class="metricbar-copy">${metricsHTML}</div>
      <div class="metricbar-copy">${metricsHTML}</div>
    </div>`;
  } else {
    bar.innerHTML = metricsHTML;
  }

  // Wire hover handlers for the floating metric tooltip
  const tip = document.getElementById("metric-tooltip");
  if (tip) {
    bar.querySelectorAll(".metric[data-tip]").forEach(el => {
      el.addEventListener("mouseenter", () => {
        tip.textContent = el.getAttribute("data-tip") || "";
        tip.classList.add("show");
        // position below the metric element using viewport coords (fixed positioning)
        const rect = el.getBoundingClientRect();
        // measure tooltip after content is set
        const tipW = tip.offsetWidth || 280;
        const tipH = tip.offsetHeight || 60;
        let left = rect.left;
        // don't let it run off the right edge
        const vw = window.innerWidth;
        if (left + tipW > vw - 8) left = vw - tipW - 8;
        if (left < 8) left = 8;
        let top = rect.bottom + 8;
        // if no room below, flip above
        if (top + tipH > window.innerHeight - 8) top = rect.top - tipH - 8;
        tip.style.left = `${left}px`;
        tip.style.top  = `${top}px`;
      });
      el.addEventListener("mouseleave", () => {
        tip.classList.remove("show");
      });
    });
  }
  restoreCtx();
}

function signed(n) {
  const v = parseFloat(n);
  return v > 0 ? `+${n}` : `${n}`;
}

// ============================================================
// SORT HELPER
// ============================================================
function sortRows(rows, key, dir) {
  const mul = dir === "asc" ? 1 : -1;
  return rows.slice().sort((a, b) => {
    const va = a[key], vb = b[key];
    if (va == null && vb == null) return 0;
    if (va == null) return 1;
    if (vb == null) return -1;
    if (typeof va === "number" && typeof vb === "number") return (va - vb) * mul;
    return String(va).localeCompare(String(vb)) * mul;
  });
}

// ============================================================
// FORM TABLE
// ============================================================
function renderFormTable() {
  const card = document.getElementById("form-card");
  if (!STATE.data) return;

  const entities = allEntities();
  const races = racesSorted();
  const POWER_N = 8;                 // fixed last-8-races window (no toggle)
  const windowSize = POWER_N;
  const shownRaces = races.slice(-Math.min(windowSize, races.length));

  // Field-relative Power Rankings now, and "last week" (through the previous
  // completed round) so we can show up/down arrows like the standings page.
  const completedRounds = races.map(r => r.round).filter(n => n != null).sort((a, b) => a - b);
  const latestRound = completedRounds.length ? completedRounds[completedRounds.length - 1] : null;
  const prevRound = completedRounds.length > 1 ? completedRounds[completedRounds.length - 2] : null;
  // Rank over the field that's actually shown. When the Full-time toggle is on,
  // exclude part-timers from the RANKING itself (not just the display) so the
  // rank numbers stay consecutive. Previously the full field was ranked and the
  // part-timers were merely filtered out of the table, leaving gaps (e.g. 35 →
  // 38, where #8/#67 held 26/27 and #33/#84 held 36/37). This mirrors the rail
  // (renderFormMini), which already ranks allEntities().filter(isFullTime).
  const fieldEntities = STATE.form.ftOnly ? entities.filter(isFullTime) : entities;
  const powerNow = buildPowerRankings(fieldEntities, STATE.series, POWER_N);
  const powerPrev = prevRound != null ? buildPowerRankings(fieldEntities, STATE.series, POWER_N, prevRound) : new Map();

  // Power-RATING trend over the last 8 race-states — same as the right rail, so
  // the "last 8" plot on this table matches the rail's line exactly. Compute
  // the field rankings at each of the last 8 round cutoffs once, then read each
  // driver's rating at each step.
  const trendRounds = completedRounds.slice(-POWER_N);
  const ratingByRound = trendRounds.map(rnd => ({
    round: rnd,
    map: buildPowerRankings(fieldEntities, STATE.series, POWER_N, rnd),
  }));
  const ratingHistoryFor = (key) =>
    ratingByRound.map(rr => { const pr = rr.map.get(key); return pr ? pr.rating : null; });

  let decorated = entities.map(d => {
    const key = entityKey(d);
    const pr = powerNow.get(key);
    const prPrev = powerPrev.get(key);
    const formRating = pr ? pr.rating : null;     // field-relative 0-100 blend
    const powerRank = pr ? pr.rank : null;        // headline rank (1-N)
    // Ranking change vs last week (positive = moved UP, i.e. lower rank number).
    const rankDelta = (pr && prPrev) ? (prPrev.rank - pr.rank) : null;
    const seasonRating = seasonTotalRating(d.races);
    const deltaR = (formRating != null && seasonRating != null) ? formRating - seasonRating : null;
    const ratingHistory = ratingHistoryFor(key);
    const totalPts = d.races.reduce((s, r) => s + r.total, 0);
    const windowPts = d.races
      .filter(r => shownRaces.some(sr => sr.round === r.round))
      .reduce((s, r) => s + (r.total || 0), 0);
    let windowPtsDelta = null;
    if (d.races.length > 0 && shownRaces.length > 0) {
      const seasonAvgPerRace = totalPts / d.races.length;
      const racesInWindow = d.races.filter(r => shownRaces.some(sr => sr.round === r.round)).length;
      if (racesInWindow > 0) {
        const expectedPts = seasonAvgPerRace * racesInWindow;
        windowPtsDelta = windowPts - expectedPts;
      }
    }
    return { ...d, formRating, powerRank, rankDelta, seasonRating, deltaR, ratingHistory, totalPts, windowPts, windowPtsDelta, fullTime: isFullTime(d) };
  });

  // Compute avg NASCAR Driver Rating across the form window for each
  // entity. Loop data lives on the per-race result row (loop_driver_rating)
  // so we just walk shown-window races and average. Drivers/cars with
  // no loop data in the window get null. Pre-2005 era races also have
  // null. We compute this AFTER the spread above so it integrates cleanly
  // with the sortable column logic that follows.
  decorated.forEach(d => {
    const ratings = (d.races || [])
      .filter(r => shownRaces.some(sr => sr.round === r.round))
      .map(r => r.loop_driver_rating)
      .filter(v => v != null);
    d.windowRating = ratings.length
      ? ratings.reduce((s, x) => s + x, 0) / ratings.length
      : null;
    d.windowRatingRaces = ratings.length;
  });

  if (STATE.form.ftOnly) decorated = decorated.filter(d => d.fullTime);

  // Assign rank by season totalPts (descending) — used by the Pos column.
  // Done before user filters so the rank reflects the actual standings, not
  // the filtered position. Tap "Pos" header to sort by it.
  const ranked = decorated.slice().sort((a, b) => b.totalPts - a.totalPts);
  const rankByKey = new Map();
  ranked.forEach((d, i) => rankByKey.set(entityKey(d), i + 1));
  decorated.forEach(d => { d.rank = rankByKey.get(entityKey(d)) || 999; });

  const q = STATE.form.search.trim().toLowerCase();
  if (q) {
    decorated = decorated.filter(d =>
      d.driver.toLowerCase().includes(q) ||
      (d.car_number || "").toLowerCase().includes(q) ||
      (d.drivers || []).some(n => n.toLowerCase().includes(q))
    );
  }

  const sortKey = STATE.form.sortKey || "powerRank";
  const sortDir = STATE.form.sortKey ? STATE.form.sortDir : "asc";
  decorated = sortRows(decorated, sortKey, sortDir);

  const headerCols = shownRaces.map(r =>
    `<th class="num" title="${escapeHTML(r.name || '')}">R${r.round}</th>`
  ).join("");

  const rows = decorated.map((d, i) => {
    const carHex = colorFor(STATE.series, d.car_number);
    const txtCol = contrastTextFor(carHex);
    const spark = ratingSparkSVG(d.ratingHistory || [], carHex, 58, 18);
    const ratingCls = d.deltaR == null ? "" : d.deltaR > 6 ? "hot" : d.deltaR < -6 ? "cold" : "";
    const teamPill = renderTeamPill(d.team_code);
    // Power-rank movement pill vs last week — same style as the standings page.
    let rankArrow;
    if (d.rankDelta == null) {
      rankArrow = `<span class="pos-change new" title="New to rankings">NEW</span>`;
    } else if (d.rankDelta === 0) {
      rankArrow = `<span class="pos-change flat" title="No change">—</span>`;
    } else if (d.rankDelta > 0) {
      rankArrow = `<span class="pos-change up" title="Up ${d.rankDelta} since last race">▲${d.rankDelta}</span>`;
    } else {
      rankArrow = `<span class="pos-change down" title="Down ${Math.abs(d.rankDelta)} since last race">▼${Math.abs(d.rankDelta)}</span>`;
    }
    return `<tr data-car-key="${escapeHTML(entityKey(d))}">
      <td class="rank-cell num">${d.powerRank != null ? d.powerRank : "—"}${rankArrow}</td>
      <td><a class="driver-cell profile-link" href="${profileHref(d)}">
        <span class="car-tag" style="background:${carHex};color:${txtCol}">${d.car_number}</span>
        <span>${escapeHTML(displayName(d))}</span>
        ${renderCoDriverBadge(d)}
      </a></td>
      <td>${teamPill}</td>
      <td><span class="form-wrap">${spark}</span></td>
      <td class="num">
        <span class="rating-stack">
          <span class="rating-big ${ratingCls}">${d.formRating != null ? d.formRating.toFixed(1) : "—"}</span>
          <span class="rating-small">rating</span>
        </span>
      </td>
      <td class="num">${deltaPill(d.deltaR)}</td>
      <td class="num">${
        d.windowRating == null
          ? `<span class="muted">—</span>`
          : `<span class="${d.windowRating >= 100 ? "hot" : d.windowRating < 70 ? "cold" : ""}" title="Avg NASCAR Driver Rating across ${d.windowRatingRaces} races in this window. 100+ = championship-caliber, ~70 = average.">${d.windowRating.toFixed(1)}</span>`
      }</td>
      <td class="num">${
        (d.windowPts == null)
          ? `<span class="muted">—</span>`
          : `<span class="pts-delta-only ${d.windowPtsDelta != null && d.windowPtsDelta > 1.5 ? "hot" : d.windowPtsDelta != null && d.windowPtsDelta < -1.5 ? "cold" : ""}">+${d.windowPts}</span>`
      }</td>
      <td class="num" style="color: var(--muted)">${d.totalPts}</td>
    </tr>`;
  }).join("");

  const th = (key, label, numeric) => {
    const active = STATE.form.sortKey === key;
    const cls = `sortable ${numeric ? "num" : ""} ${active ? "sort-" + STATE.form.sortDir : ""}`.trim();
    const arrow = active ? (STATE.form.sortDir === "asc" ? "▲" : "▼") : "↕";
    return `<th class="${cls}" data-sort="${key}">${label}<span class="sort-arrow">${arrow}</span></th>`;
  };

  const formColLabel = `Last 8`;

  const windowPtsLabel = `L8 Pts`;
  card.innerHTML = `
    <div class="table-scroll">
    <table class="data-table">
      <thead>
        <tr>
          ${th("powerRank", "Rank", true)}
          ${th("driver", "Driver", false)}
          ${th("team", "Team", false)}
          <th>${formColLabel}</th>
          ${th("formRating", "Rating", true)}
          ${th("deltaR", "vs Season", true)}
          ${th("windowRating", "Drv Rating", true)}
          ${th("windowPts", windowPtsLabel, true)}
          ${th("totalPts", "Total Pts", true)}
        </tr>
      </thead>
      <tbody>${rows || `<tr><td colspan="99" class="muted" style="padding:40px;text-align:center">No drivers match.</td></tr>`}</tbody>
    </table>
    </div>
  `;

  card.querySelectorAll("th.sortable").forEach(th => {
    th.addEventListener("click", () => {
      const key = th.dataset.sort;
      if (STATE.form.sortKey === key) {
        STATE.form.sortDir = STATE.form.sortDir === "asc" ? "desc" : "asc";
      } else {
        STATE.form.sortKey = key;
        STATE.form.sortDir = (key === "driver" || key === "team" || key === "powerRank") ? "asc" : "desc";
      }
      renderFormTable();
    });
  });

  wireCoDriverBadges(card);

  // Mobile collapse: keep Rank (0), Driver (1), Rating (4).
  const mobTable = card.querySelector("table.data-table");
  if (mobTable) {
    applyMobileTableCollapse(mobTable, [0, 1, 4]);
  }

  const sub = document.getElementById("form-sub");
  if (sub) {
    const ftNote = STATE.form.ftOnly ? "full-time only" : "all entrants";
    sub.textContent = `${decorated.length} cars · ${ftNote} · finish 35 / pace 30 / qual 20 / top-15% 15 · last 8 races, wrecks excluded`;
  }
}

function heatCell(finish) {
  // Same 6-tier scheme as the Career Heatmap and Finish Per Race:
  // win = gold, T5 bright green, T10 muted green, 11-20 neutral,
  // 21-30 warm, 31+ red.
  let cls = "heat-mid";
  if (finish === 1) cls = "heat-win";
  else if (finish <= 5) cls = "heat-t5";
  else if (finish <= 10) cls = "heat-t10";
  else if (finish > 30)  cls = "heat-bot";
  else if (finish > 20)  cls = "heat-down";
  return `<span class="heat ${cls}">${finish}</span>`;
}

function trendArrow(delta) {
  if (delta == null || isNaN(delta)) return { a: "·", cls: "" };
  if (delta >= 6)  return { a: "↑↑", cls: "up" };
  if (delta >= 2)  return { a: "↑",  cls: "up" };
  if (delta <= -6) return { a: "↓↓", cls: "down" };
  if (delta <= -2) return { a: "↓",  cls: "down" };
  return { a: "·", cls: "" };
}

function deltaPill(d) {
  if (d == null) return `<span class="delta-pill zero">—</span>`;
  const cls = d > 0.5 ? "up" : d < -0.5 ? "down" : "zero";
  const s = d > 0 ? "+" : "";
  return `<span class="delta-pill ${cls}">${s}${d.toFixed(1)}</span>`;
}

// Sparkline for a 0-100 power RATING series (higher = up, unlike sparkSVG which
// is for finishes). Auto-scales to the series' own range so small week-to-week
// moves are visible, with a little padding so a flat line sits mid-height.
function ratingSparkSVG(ratings, color, w, h) {
  const valid = ratings.filter(v => v != null);
  if (valid.length < 2) {
    return `<svg class="spark" width="${w}" height="${h}" viewBox="0 0 ${w} ${h}"></svg>`;
  }
  let lo = Math.min(...valid), hi = Math.max(...valid);
  if (hi - lo < 4) { const mid = (hi + lo) / 2; lo = mid - 2; hi = mid + 2; }  // avoid flat-line zero range
  const span = hi - lo;
  const yFor = (v) => (1 - (v - lo) / span) * (h - 4) + 2;   // higher rating = higher on chart
  const pts = ratings.map((v, i) => {
    if (v == null) return null;
    const x = (i / (ratings.length - 1 || 1)) * (w - 2) + 1;
    return `${x.toFixed(1)},${yFor(v).toFixed(1)}`;
  }).filter(Boolean).join(" ");
  const dots = ratings.map((v, i) => {
    if (v == null) return "";
    const x = (i / (ratings.length - 1 || 1)) * (w - 2) + 1;
    return `<circle cx="${x.toFixed(1)}" cy="${yFor(v).toFixed(1)}" r="1.6" fill="${color}"/>`;
  }).join("");
  return `<svg class="spark" width="${w}" height="${h}" viewBox="0 0 ${w} ${h}">
    <polyline points="${pts}" fill="none" stroke="${color}" stroke-width="1.4" stroke-linejoin="round"/>
    ${dots}
  </svg>`;
}

function sparkSVG(finishes, color, w, h) {
  const valid = finishes.filter(f => f != null);
  if (valid.length < 2) {
    return `<svg class="spark" width="${w}" height="${h}" viewBox="0 0 ${w} ${h}"></svg>`;
  }
  const max = 40, min = 1;
  const pts = finishes.map((f, i) => {
    if (f == null) return null;
    const x = (i / (finishes.length - 1 || 1)) * (w - 2) + 1;
    const y = ((Math.min(f, max) - min) / (max - min)) * (h - 2) + 1;
    return `${x.toFixed(1)},${y.toFixed(1)}`;
  }).filter(Boolean).join(" ");
  const dots = finishes.map((f, i) => {
    if (f == null) return "";
    const x = (i / (finishes.length - 1 || 1)) * (w - 2) + 1;
    const y = ((Math.min(f, max) - min) / (max - min)) * (h - 2) + 1;
    return `<circle cx="${x}" cy="${y}" r="1.6" fill="${color}"/>`;
  }).join("");
  return `<svg class="spark" width="${w}" height="${h}" viewBox="0 0 ${w} ${h}">
    <polyline points="${pts}" fill="none" stroke="${color}" stroke-width="1.4" stroke-linejoin="round"/>
    ${dots}
  </svg>`;
}

