  "Ed Sutton":                "SUT",
  "Joe Dennette":             "DNT",
  "Ted Marsh":                "MSH",
  "Don Arnold":               "ARN",
  "Dwayne Gaulding":          "GLD",
  "Ray Montgomery":           "MGY",
  "Gaunt Brothers":           "GBR",
  "Gaunt Brothers Racing":    "GBR",
  "Gary Baker":               "BAK",
  "Joe Scott":                "JSC",
  "Chris Fontaine":           "FON",
  "Brandon Davis":            "BDV",
  "Max Siegel":               "REV",
  "Rev Racing":                "REV",
  "Jim Rosenblum":            "RZB",
  "Steve Urvan":              "URV",
  "Ray Ciccarelli":           "CCM",
  "JP Motorsports":           "JPM",
  "Tom Mazzuchi":             "MZZ",
